/**
 * اختبارات وحدة — AppState Controller [UTP-008]
 *
 * يتحقق من:
 * - getState: استرجاع حالة تطبيق صالح
 * - getState: رفض معرّف غير صالح بـ 400
 * - getState: إرجاع null عند عدم وجود حالة
 * - setState: حفظ حالة بنجاح
 * - setState: رفض بدون data بـ 400
 * - clearState: مسح حالة بنجاح
 * - clearState: رفض معرّف غير صالح
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { Request, Response } from 'express';

// ─── Mock لخدمة App State ───
const mockReadAppState = vi.fn();
const mockSaveAppState = vi.fn();
const mockClearAppState = vi.fn();

vi.mock('@/services/app-state.service', () => ({
  readAppState: (...args: unknown[]) => mockReadAppState(...args),
  saveAppState: (...args: unknown[]) => mockSaveAppState(...args),
  clearAppState: (...args: unknown[]) => mockClearAppState(...args),
}));

import { AppStateController } from '@/controllers/appState.controller';

// ─── مساعدات ───

function createReq(overrides: Record<string, unknown> = {}): Request {
  return {
    params: {},
    body: {},
    query: {},
    ...overrides,
  } as unknown as Request;
}

function createRes(): Response & { _status: number; _json: unknown } {
  const res = {
    _status: 200,
    _json: null,
    status: vi.fn(function (this: any, code: number) {
      this._status = code;
      return this;
    }),
    json: vi.fn(function (this: any, data: unknown) {
      this._json = data;
      return this;
    }),
  } as unknown as Response & { _status: number; _json: unknown };
  return res;
}

// ═══ اختبارات ═══

describe('AppStateController', () => {
  let controller: AppStateController;

  beforeEach(() => {
    vi.clearAllMocks();
    controller = new AppStateController();
  });

  // ─── getState ───

  describe('getState', () => {
    it('يجب أن يسترجع حالة تطبيق صالح', async () => {
      mockReadAppState.mockResolvedValue({
        data: { step: 3, analysis: 'complete' },
        updatedAt: '2025-01-01T00:00:00Z',
      });

      const req = createReq({ params: { appId: 'analysis' } });
      const res = createRes();

      await controller.getState(req, res);

      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          data: expect.objectContaining({ step: 3 }),
        })
      );
    });

    it('يجب أن يرفض معرّف تطبيق غير صالح بـ 400', async () => {
      const req = createReq({ params: { appId: 'invalid-app-xyz' } });
      const res = createRes();

      await controller.getState(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          code: 'INVALID_APP_ID',
        })
      );
    });

    it('يجب أن يُرجع null عند عدم وجود حالة محفوظة', async () => {
      mockReadAppState.mockResolvedValue({ data: {}, updatedAt: null });

      const req = createReq({ params: { appId: 'breakdown' } });
      const res = createRes();

      await controller.getState(req, res);

      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          data: null,
        })
      );
    });

    it('يجب أن يتعامل مع خطأ القراءة بـ 500', async () => {
      mockReadAppState.mockRejectedValue(new Error('IO error'));

      const req = createReq({ params: { appId: 'analysis' } });
      const res = createRes();

      await controller.getState(req, res);

      expect(res.status).toHaveBeenCalledWith(500);
    });
  });

  // ─── setState ───

  describe('setState', () => {
    it('يجب أن يحفظ حالة بنجاح', async () => {
      mockSaveAppState.mockResolvedValue({
        data: { step: 5 },
        updatedAt: '2025-06-01T00:00:00Z',
      });

      const req = createReq({
        params: { appId: 'analysis' },
        body: { data: { step: 5 } },
      });
      const res = createRes();

      await controller.setState(req, res);

      expect(mockSaveAppState).toHaveBeenCalledWith('analysis', { step: 5 });
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({ success: true })
      );
    });

    it('يجب أن يرفض بدون data بـ 400', async () => {
      const req = createReq({
        params: { appId: 'analysis' },
        body: {},
      });
      const res = createRes();

      await controller.setState(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({ code: 'INVALID_DATA' })
      );
    });

    it('يجب أن يرفض data من نوع غير object بـ 400', async () => {
      const req = createReq({
        params: { appId: 'analysis' },
        body: { data: 'not an object' },
      });
      const res = createRes();

      await controller.setState(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
    });
  });

  // ─── clearState ───

  describe('clearState', () => {
    it('يجب أن يمسح حالة تطبيق صالح', async () => {
      mockClearAppState.mockResolvedValue(undefined);

      const req = createReq({ params: { appId: 'breakdown' } });
      const res = createRes();

      await controller.clearState(req, res);

      expect(mockClearAppState).toHaveBeenCalledWith('breakdown');
    });

    it('يجب أن يرفض معرّف غير صالح', async () => {
      const req = createReq({ params: { appId: 'INVALID' } });
      const res = createRes();

      await controller.clearState(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
    });
  });
});

/**
 * اختبارات وحدة — Queue Controller [UTP-008]
 *
 * يتحقق من:
 * - getJobStatus: رفض بدون jobId بـ 400
 * - getJobStatus: رفض اسم قائمة غير صالح بـ 400
 * - getJobStatus: إرجاع 404 عند عدم وجود المهمة
 * - getJobStatus: إرجاع بيانات المهمة عند النجاح
 * - getQueueStats: إرجاع إحصائيات جميع القوائم
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { Request, Response } from 'express';

// ─── Mock لنظام القوائم ───
const mockGetQueue = vi.fn();
vi.mock('@/queues/queue.config', () => ({
  queueManager: {
    getQueue: (...args: unknown[]) => mockGetQueue(...args),
  },
  QueueName: {
    AI_ANALYSIS: 'ai-analysis',
    DOCUMENT_PROCESSING: 'document-processing',
    NOTIFICATIONS: 'notifications',
    EXPORT: 'export',
    CACHE_WARMING: 'cache-warming',
  },
}));

import { QueueController } from '@/controllers/queue.controller';

// ─── مساعدات ───

function createReq(overrides: Record<string, unknown> = {}): Request {
  return {
    params: {},
    query: {},
    body: {},
    ...overrides,
  } as unknown as Request;
}

function createRes(): Response {
  return {
    status: vi.fn().mockReturnThis(),
    json: vi.fn().mockReturnThis(),
  } as unknown as Response;
}

// ═══ اختبارات ═══

describe('QueueController', () => {
  let controller: QueueController;

  beforeEach(() => {
    vi.clearAllMocks();
    controller = new QueueController();
  });

  // ─── getJobStatus ───

  describe('getJobStatus', () => {
    it('يجب أن يرفض بدون jobId بـ 400', async () => {
      const req = createReq({ params: {} });
      const res = createRes();

      await controller.getJobStatus(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({ success: false })
      );
    });

    it('يجب أن يرفض اسم قائمة غير صالح بـ 400', async () => {
      const req = createReq({
        params: { jobId: 'job-123' },
        query: { queue: 'invalid-queue-name' },
      });
      const res = createRes();

      await controller.getJobStatus(req, res);

      expect(res.status).toHaveBeenCalledWith(400);
    });

    it('يجب أن يُرجع 404 عند عدم وجود المهمة', async () => {
      const mockQueue = {
        getJob: vi.fn().mockResolvedValue(null),
      };
      mockGetQueue.mockReturnValue(mockQueue);

      const req = createReq({
        params: { jobId: 'nonexistent-job' },
        query: { queue: 'ai-analysis' },
      });
      const res = createRes();

      await controller.getJobStatus(req, res);

      expect(res.status).toHaveBeenCalledWith(404);
    });

    it('يجب أن يُرجع بيانات المهمة عند النجاح', async () => {
      const mockJob = {
        id: 'job-123',
        name: 'analyze',
        progress: 50,
        returnvalue: null,
        failedReason: null,
        data: { type: 'scene' },
        timestamp: Date.now(),
        processedOn: null,
        finishedOn: null,
        attemptsMade: 0,
        getState: vi.fn().mockResolvedValue('active'),
      };
      const mockQueue = {
        getJob: vi.fn().mockResolvedValue(mockJob),
      };
      mockGetQueue.mockReturnValue(mockQueue);

      const req = createReq({
        params: { jobId: 'job-123' },
        query: { queue: 'ai-analysis' },
      });
      const res = createRes();

      await controller.getJobStatus(req, res);

      const call = (res.json as ReturnType<typeof vi.fn>).mock.calls[0][0];
      expect(call.success).toBe(true);
      expect(call.job).toMatchObject({
        id: 'job-123',
        state: 'active',
      });
    });
  });
});

/**
 * اختبارات وحدة — Redis Reconnection Strategy [UTP-007]
 *
 * يتحقق من:
 * - استراتيجية إعادة الاتصال (exponential backoff)
 * - التوقف عن المحاولة بعد 10 مرات في Sentinel mode
 * - بوابة Redis: isRedisEnabled
 * - getRedisConfig: تكوين URL مباشر
 * - getRedisConfig: تكوين Sentinel
 * - checkRedisVersion: التحقق من توافق الإصدار
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// ─── Mock للوحدات الخارجية ───
vi.mock('redis', () => ({
  createClient: vi.fn(() => ({
    connect: vi.fn().mockResolvedValue(undefined),
    ping: vi.fn().mockResolvedValue('PONG'),
    info: vi.fn().mockResolvedValue('redis_version:7.2.0'),
    quit: vi.fn().mockResolvedValue(undefined),
    on: vi.fn(),
  })),
}));

// ═══ اختبارات getRedisConfig ═══

describe('getRedisConfig', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    vi.resetModules();
    process.env = { ...originalEnv };
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  it('يجب أن يُرجع config مع URL عند وجود REDIS_URL', async () => {
    process.env['REDIS_URL'] = 'redis://localhost:6379';
    process.env['REDIS_SENTINEL_ENABLED'] = 'false';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    expect(config).toHaveProperty('url', 'redis://localhost:6379');
  });

  it('يجب أن يضيف كلمة المرور عند وجود REDIS_PASSWORD مع URL', async () => {
    process.env['REDIS_URL'] = 'redis://localhost:6379';
    process.env['REDIS_PASSWORD'] = 'secret123';
    process.env['REDIS_SENTINEL_ENABLED'] = 'false';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    expect(config.password).toBe('secret123');
  });

  it('يجب أن يفعّل وضع Sentinel عند REDIS_SENTINEL_ENABLED=true', async () => {
    process.env['REDIS_SENTINEL_ENABLED'] = 'true';
    process.env['REDIS_SENTINELS'] = '10.0.0.1:26379,10.0.0.2:26380';
    process.env['REDIS_MASTER_NAME'] = 'mymaster';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    expect(config).toHaveProperty('sentinels');
    expect(config.sentinels).toHaveLength(2);
    expect(config.name).toBe('mymaster');
  });

  it('يجب أن تتضمن استراتيجية إعادة الاتصال في وضع Sentinel', async () => {
    process.env['REDIS_SENTINEL_ENABLED'] = 'true';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    expect(config.socket).toHaveProperty('reconnectStrategy');
    expect(typeof config.socket.reconnectStrategy).toBe('function');
  });

  it('يجب أن تُرجع reconnectStrategy تأخيراً متزايداً', async () => {
    process.env['REDIS_SENTINEL_ENABLED'] = 'true';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    const strategy = config.socket.reconnectStrategy;

    // المحاولة الأولى: 100ms
    expect(strategy(1)).toBe(100);
    // المحاولة الخامسة: 500ms
    expect(strategy(5)).toBe(500);
    // بعد الحد الأقصى: false (استنفاد المحاولات)
    // الكود يتوقف عند retries > 10
    const result = strategy(10);
    expect(typeof result === 'number' || result === false).toBe(true);
  });

  it('يجب أن تتوقف reconnectStrategy بعد 10 محاولات', async () => {
    process.env['REDIS_SENTINEL_ENABLED'] = 'true';

    const { getRedisConfig } = await import('@/config/redis.config');
    const config = getRedisConfig();

    const strategy = config.socket.reconnectStrategy;

    // بعد 10 محاولات: يجب أن ترجع false
    expect(strategy(11)).toBe(false);
  });
});

// ═══ اختبارات isRedisEnabled ═══

describe('isRedisEnabled', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    vi.resetModules();
    process.env = { ...originalEnv };
  });

  afterEach(() => {
    process.env = originalEnv;
  });

  it('يجب أن تُرجع false عند عدم وجود REDIS_URL أو REDIS_HOST', async () => {
    delete process.env['REDIS_ENABLED'];
    delete process.env['REDIS_URL'];
    delete process.env['REDIS_HOST'];

    const { isRedisEnabled } = await import('@/config/redis-gate');
    expect(isRedisEnabled()).toBe(false);
  });

  it('يجب أن تُرجع true عند وجود REDIS_URL مع عدم تعطيل Redis', async () => {
    process.env['REDIS_ENABLED'] = 'true';
    process.env['REDIS_URL'] = 'redis://localhost:6379';

    const { isRedisEnabled } = await import('@/config/redis-gate');
    expect(isRedisEnabled()).toBe(true);
  });

  it('يجب أن تُرجع false عند REDIS_ENABLED=false حتى مع وجود URL', async () => {
    process.env['REDIS_ENABLED'] = 'false';
    process.env['REDIS_URL'] = 'redis://localhost:6379';

    const { isRedisEnabled } = await import('@/config/redis-gate');
    expect(isRedisEnabled()).toBe(false);
  });
});

import { beforeAll, describe, expect, it, vi } from "vitest";
import supertest from "supertest";

const { state, collectClauses, toRowKey } = vi.hoisted(() => {
  const state = {
    users: [] as Array<{
      id: string;
      email: string;
      password: string;
      firstName?: string;
      lastName?: string;
    }>,
    tokens: new Map<string, string>(),
    projects: [] as Array<{
      id: string;
      title: string;
      scriptContent?: string | null;
      userId: string;
      createdAt: Date;
      updatedAt: Date;
    }>,
    userSeq: 1,
    projectSeq: 1,
  };

  const toRowKey = (columnName: string): string =>
    columnName.replace(/_([a-z])/g, (_match, char: string) => char.toUpperCase());

  const collectClauses = (
    node: unknown,
    acc: Array<{ column: string; value: unknown }> = []
  ) => {
    if (!node || typeof node !== "object") {
      return acc;
    }

    const queryNode = node as { queryChunks?: unknown[] };
    const chunks = Array.isArray(queryNode.queryChunks) ? queryNode.queryChunks : [];

    for (let index = 0; index < chunks.length; index += 1) {
      const current = chunks[index] as
        | { name?: string; queryChunks?: unknown[] }
        | undefined;
      const maybeSeparator = chunks[index + 1] as { value?: string[] } | undefined;
      const maybeParam = chunks[index + 2] as { value?: unknown } | undefined;

      if (
        current &&
        typeof current.name === "string" &&
        maybeSeparator &&
        Array.isArray(maybeSeparator.value) &&
        maybeSeparator.value.includes(" = ") &&
        maybeParam &&
        "value" in maybeParam
      ) {
        acc.push({ column: current.name, value: maybeParam.value });
      }

      collectClauses(current, acc);
    }

    return acc;
  };

  return { state, collectClauses, toRowKey };
});

vi.mock("@/utils/logger", () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
    warn: vi.fn(),
    debug: vi.fn(),
  },
}));

vi.mock("@/editor/runtime", () => ({
  registerEditorRuntimeRoutes: vi.fn().mockResolvedValue(undefined),
}));

vi.mock("@/memory", async () => {
  const express = await import("express");

  return {
    memoryHealthHandler: (_req: unknown, res: { json: (body: unknown) => void }) =>
      res.json({ success: true, status: "disabled" }),
    memoryRoutes: express.Router(),
    weaviateStore: {
      bootstrap: vi.fn().mockResolvedValue(undefined),
      disconnect: vi.fn().mockResolvedValue(undefined),
      getStatus: vi.fn(() => ({
        enabled: false,
        required: false,
        state: "disabled",
      })),
    },
  };
});

vi.mock("@/services/auth.service", () => ({
  authService: {
    signup: vi.fn(async (email: string, password: string, firstName?: string, lastName?: string) => {
      const existingUser = state.users.find((user) => user.email === email);
      if (existingUser) {
        throw new Error("المستخدم موجود بالفعل");
      }

      const user = {
        id: `user-${state.userSeq++}`,
        email,
        password,
        firstName,
        lastName,
      };

      state.users.push(user);

      const accessToken = `token-${user.id}`;
      const refreshToken = `refresh-${user.id}`;
      state.tokens.set(accessToken, user.id);

      return {
        accessToken,
        refreshToken,
        user: {
          id: user.id,
          email: user.email,
          firstName: user.firstName,
          lastName: user.lastName,
        },
      };
    }),

    login: vi.fn(async (email: string, password: string) => {
      const user = state.users.find(
        (candidate) => candidate.email === email && candidate.password === password
      );

      if (!user) {
        throw new Error("البريد الإلكتروني أو كلمة المرور غير صحيحة");
      }

      const accessToken = `token-${user.id}-${state.tokens.size + 1}`;
      const refreshToken = `refresh-${user.id}-${state.tokens.size + 1}`;
      state.tokens.set(accessToken, user.id);

      return {
        accessToken,
        refreshToken,
        user: {
          id: user.id,
          email: user.email,
          firstName: user.firstName,
          lastName: user.lastName,
        },
      };
    }),

    getUserById: vi.fn(async (userId: string) => {
      const user = state.users.find((candidate) => candidate.id === userId);

      return user
        ? {
            id: user.id,
            email: user.email,
            firstName: user.firstName,
            lastName: user.lastName,
          }
        : null;
    }),

    verifyToken: vi.fn((token: string) => {
      if (!token) {
        throw new Error("jwt must be provided");
      }

      const userId = state.tokens.get(token);
      if (!userId) {
        throw new Error("رمز التحقق غير صالح");
      }

      return { userId, sub: userId };
    }),

    revokeRefreshToken: vi.fn(async () => undefined),
    refreshAccessToken: vi.fn(async () => ({
      accessToken: "token-refreshed",
      refreshToken: "refresh-refreshed",
    })),
  },
}));

vi.mock("@/db", async () => {
  const schema = await import("@/db/schema");

  const filterProjects = (condition: unknown) => {
    const clauses = collectClauses(condition);
    if (clauses.length === 0) {
      return [...state.projects];
    }

    return state.projects.filter((project) =>
      clauses.every(({ column, value }) => {
        const rowKey = toRowKey(column);
        return project[rowKey as keyof typeof project] === value;
      })
    );
  };

  return {
    databaseAvailable: true,
    initializeDatabase: vi.fn().mockResolvedValue(undefined),
    closeDatabase: vi.fn().mockResolvedValue(undefined),
    pool: null,
    db: {
      select: vi.fn(() => ({
        from: (table: unknown) => {
          if (table !== schema.projects) {
            return {
              where: () => [],
              orderBy: async () => [],
              then: (resolve: (value: unknown[]) => unknown) => resolve([]),
            };
          }

          const asQuery = (rows: typeof state.projects) => ({
            where: (condition: unknown) => asQuery(filterProjects(condition)),
            orderBy: async () =>
              [...rows].sort(
                (left, right) =>
                  right.updatedAt.getTime() - left.updatedAt.getTime()
              ),
            limit: async (limit: number) => rows.slice(0, limit),
            then: (
              resolve: (value: typeof rows) => unknown,
              reject?: (reason: unknown) => unknown
            ) => Promise.resolve([...rows]).then(resolve, reject),
          });

          return asQuery([...state.projects]);
        },
      })),

      insert: vi.fn((table: unknown) => ({
        values: (values: Record<string, unknown>) => {
          if (table !== schema.projects) {
            return {
              returning: async () => [],
            };
          }

          const now = new Date();
          const project = {
            id: `project-${state.projectSeq++}`,
            title: String(values.title),
            scriptContent:
              typeof values.scriptContent === "string"
                ? values.scriptContent
                : null,
            userId: String(values.userId),
            createdAt: now,
            updatedAt: now,
          };

          state.projects.push(project);

          return {
            returning: async () => [project],
          };
        },
      })),

      update: vi.fn(() => ({
        set: () => ({
          where: () => ({
            returning: async () => [],
          }),
        }),
      })),

      delete: vi.fn(() => ({
        where: async () => ({ rowCount: 0 }),
      })),
    },
  };
});

import { app } from "@/server";

const request = supertest(app);

function extractCookieValue(
  cookies: string[] | undefined,
  cookieName: string
): string | undefined {
  return cookies
    ?.find((cookie) => cookie.startsWith(`${cookieName}=`))
    ?.split(";")[0]
    ?.split("=")[1];
}

describe("Controllers Integration Tests", () => {
  let token: string;
  let csrfToken: string;
  let authCookies: string[] = [];

  const testUser = {
    email: `test-${Date.now()}@example.com`,
    password: "TestPass123!",
  };

  beforeAll(async () => {
    state.users.length = 0;
    state.tokens.clear();
    state.projects.length = 0;
    state.userSeq = 1;
    state.projectSeq = 1;

    const signupResponse = await request
      .post("/api/auth/signup")
      .send(testUser)
      .expect(201);

    token = signupResponse.body.data.token;
