import { describe, it, expect, beforeEach, afterAll, vi } from 'vitest';
import crypto from 'crypto';

describe('Environment Configuration', () => {
  const originalEnv = process.env;
  const createBaseEnv = () => ({
    NODE_ENV: 'test',
    DATABASE_URL: 'postgresql://test:test@localhost:5432/test_db',
  });
  const createProductionEnv = (overrides: Record<string, string> = {}) => ({
    NODE_ENV: 'production',
    PORT: '3001',
    DATABASE_URL: 'postgresql://prod:prod@localhost:5432/prod_db',
    JWT_SECRET: crypto.randomBytes(32).toString('hex'),
    CORS_ORIGIN: 'http://localhost:5000',
    RATE_LIMIT_WINDOW_MS: '900000',
    RATE_LIMIT_MAX_REQUESTS: '100',
    ...overrides,
  });

  beforeEach(() => {
    vi.resetModules();
    const parse = vi.fn(() => ({}));
    vi.doMock('dotenv', () => ({
      default: {
        config: vi.fn(),
        parse,
      },
      parse,
    }));
    process.env = createBaseEnv();
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  describe('env validation', () => {
    it('should parse valid environment variables', async () => {
      process.env['NODE_ENV'] = 'development';
      process.env['PORT'] = '3001';
      process.env['DATABASE_URL'] = `postgresql://${process.env['TEST_DB_USER'] || 'user'}:${process.env['TEST_DB_PASS'] || 'pass'}@localhost:5432/test_db`;
      process.env['JWT_SECRET'] = 'a-very-long-secret-key-for-testing-purposes-32-chars';
      process.env['CORS_ORIGIN'] = 'http://localhost:5000';
      process.env['RATE_LIMIT_WINDOW_MS'] = '900000';
      process.env['RATE_LIMIT_MAX_REQUESTS'] = '100';

      const { env } = await import('./env');

      expect(env.NODE_ENV).toBe('development');
      expect(env.PORT).toBe(3001);
      expect(env.DATABASE_URL).toContain('postgresql://');
      expect(env.DATABASE_URL).toContain('@localhost:5432/test_db');
      expect(env.JWT_SECRET).toBe(process.env['JWT_SECRET']);
      expect(env.CORS_ORIGIN).toBe('http://localhost:5000');
      expect(env.RATE_LIMIT_WINDOW_MS).toBe(900000);
      expect(env.RATE_LIMIT_MAX_REQUESTS).toBe(100);
    });

    it('should use default values when not provided', async () => {
      process.env = createBaseEnv();

      const { env } = await import('./env');

      expect(env.NODE_ENV).toBe('test');
      expect(env.PORT).toBe(3001);
      expect(env.DATABASE_URL).toBe('postgresql://test:test@localhost:5432/test_db');
      expect(env.WEAVIATE_REQUIRED).toBe(true);
    });

    it('should validate NODE_ENV enum', async () => {
      process.env = createProductionEnv();

      const { env } = await import('./env');

      expect(env.NODE_ENV).toBe('production');
    });

    it('should reject weak JWT secrets in production', async () => {
      process.env = createProductionEnv({ JWT_SECRET: 'weak-secret' });

      await expect(import('./env')).rejects.toThrow(
        'JWT_SECRET must be at least 32 characters in production'
      );
    });

    it('should handle test environment', async () => {
      process.env['NODE_ENV'] = 'test';
      delete process.env['JWT_SECRET'];

      const { env } = await import('./env');

      expect(env.NODE_ENV).toBe('test');
    });

    it('should transform string PORT to number', async () => {
      process.env['PORT'] = '8080';
      delete process.env['JWT_SECRET'];

      const { env } = await import('./env');

      expect(typeof env.PORT).toBe('number');
      expect(env.PORT).toBe(8080);
    });

    it('should transform rate limit values to numbers', async () => {
      process.env['RATE_LIMIT_WINDOW_MS'] = '600000';
      process.env['RATE_LIMIT_MAX_REQUESTS'] = '50';
      delete process.env['JWT_SECRET'];

      const { env } = await import('./env');

      expect(typeof env.RATE_LIMIT_WINDOW_MS).toBe('number');
      expect(typeof env.RATE_LIMIT_MAX_REQUESTS).toBe('number');
      expect(env.RATE_LIMIT_WINDOW_MS).toBe(600000);
      expect(env.RATE_LIMIT_MAX_REQUESTS).toBe(50);
    });
  });

  describe('isDevelopment helper', () => {
    it('should return true for development environment', async () => {
      process.env['NODE_ENV'] = 'development';
      delete process.env['JWT_SECRET'];

      const { isDevelopment } = await import('./env');

      expect(isDevelopment).toBe(true);
    });

    it('should return false for production environment', async () => {
      process.env = createProductionEnv();

      const { isDevelopment } = await import('./env');

      expect(isDevelopment).toBe(false);
    });

    it('should return false for test environment', async () => {
      process.env['NODE_ENV'] = 'test';
      delete process.env['JWT_SECRET'];

      const { isDevelopment } = await import('./env');

      expect(isDevelopment).toBe(false);
    });
  });

  describe('optional environment variables', () => {
    it('should handle optional GOOGLE_GENAI_API_KEY', async () => {
      process.env = createBaseEnv();

      const { env } = await import('./env');

      // Optional fields can be undefined
      expect(env.GOOGLE_GENAI_API_KEY === undefined || typeof env.GOOGLE_GENAI_API_KEY === 'string').toBe(true);
    });

    it('should handle optional GEMINI_API_KEY', async () => {
      process.env = createBaseEnv();

      const { env } = await import('./env');

      // Optional fields can be undefined
      expect(env.GEMINI_API_KEY === undefined || typeof env.GEMINI_API_KEY === 'string').toBe(true);
    });

    it('should accept GOOGLE_GENAI_API_KEY when provided', async () => {
      process.env = {
        ...createBaseEnv(),
        GOOGLE_GENAI_API_KEY: 'test-key',
      };

      const { env } = await import('./env');

      expect(env.GOOGLE_GENAI_API_KEY).toBe('test-key');
    });

    it('should accept documented operational environment variables', async () => {
      process.env = {
        ...createBaseEnv(),
        FRONTEND_URL: 'http://localhost:5000',
        REDIS_ENABLED: 'true',
        REDIS_SENTINEL_ENABLED: 'false',
        REDIS_SENTINELS: '127.0.0.1:26379,127.0.0.1:26380',
        REDIS_MASTER_NAME: 'mymaster',
        SERVICE_NAME: 'thecopy-backend',
        TRACING_ENABLED: 'true',
        FILE_IMPORT_HOST: '127.0.0.1',
        FILE_IMPORT_PORT: '3001',
        LOG_LEVEL: 'info',
        SENTRY_RELEASE: 'the-copy@1.0.0',
        SENTRY_SERVER_NAME: 'backend-prod-01',
      };

      const { env } = await import('./env');

      expect(env.FRONTEND_URL).toBe('http://localhost:5000');
      expect(env.REDIS_ENABLED).toBe('true');
      expect(env.REDIS_SENTINELS).toBe('127.0.0.1:26379,127.0.0.1:26380');
      expect(env.SERVICE_NAME).toBe('thecopy-backend');
      expect(env.FILE_IMPORT_PORT).toBe('3001');
      expect(env.SENTRY_RELEASE).toBe('the-copy@1.0.0');
    });

    it('should parse Weaviate operational flags and timeout values', async () => {
      process.env = {
        ...createBaseEnv(),
        MEMORY_SYSTEM_ENABLED: 'true',
        WEAVIATE_REQUIRED: 'false',
        WEAVIATE_URL: 'http://localhost:8080',
        WEAVIATE_API_KEY: 'memory-key',
        WEAVIATE_STARTUP_TIMEOUT_MS: '4500',
      };

      const { env } = await import('./env');

      expect(env.MEMORY_SYSTEM_ENABLED).toBe(true);
      expect(env.WEAVIATE_REQUIRED).toBe(false);
      expect(env.WEAVIATE_URL).toBe('http://localhost:8080');
      expect(env.WEAVIATE_API_KEY).toBe('memory-key');
      expect(env.WEAVIATE_STARTUP_TIMEOUT_MS).toBe(4500);
    });

    it('should reject requiring Weaviate when memory system is disabled', async () => {
      process.env = {
        ...createBaseEnv(),
        MEMORY_SYSTEM_ENABLED: 'false',
        WEAVIATE_REQUIRED: 'true',
      };

      await expect(import('./env')).rejects.toThrow(
        'WEAVIATE_REQUIRED=true requires MEMORY_SYSTEM_ENABLED=true'
      );
    });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { Request, Response } from 'express';

const { mockRunFullPipeline, mockQueueAIAnalysis } = vi.hoisted(() => ({
  mockRunFullPipeline: vi.fn(),
  mockQueueAIAnalysis: vi.fn(),
}));

vi.mock('@/services/analysis.service', () => ({
  AnalysisService: class MockAnalysisService {
    runFullPipeline = mockRunFullPipeline;
  },
}));

vi.mock('@/queues/jobs/ai-analysis.job', () => ({
  queueAIAnalysis: mockQueueAIAnalysis,
}));

vi.mock('@/utils/logger', () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

import { AnalysisController } from './analysis.controller';

describe('AnalysisController', () => {
  let analysisController: AnalysisController;
  let mockRequest: Partial<Request> & { user?: { id: string } };
  let mockResponse: Partial<Response>;

  beforeEach(() => {
    vi.clearAllMocks();

    analysisController = new AnalysisController();
    mockRequest = {
      body: {},
      user: { id: 'user-123' },
    };
    mockResponse = {
      status: vi.fn().mockReturnThis(),
      json: vi.fn().mockReturnThis(),
    };
  });

  describe('runSevenStationsPipeline', () => {
    it('يعالج النص عبر خدمة التحليل المباشرة', async () => {
      mockRunFullPipeline.mockResolvedValue({
        pipelineMetadata: { averageConfidence: 0.91 },
        stationOutputs: {
          station7: {
            details: {
              finalReport: 'تقرير التحليل الكامل',
            },
          },
        },
      });

      mockRequest.body = { text: 'نص درامي للتحليل' };

      await analysisController.runSevenStationsPipeline(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockRunFullPipeline).toHaveBeenCalledWith(
        expect.objectContaining({
          fullText: 'نص درامي للتحليل',
          projectName: 'تحليل سيناريو',
          language: 'ar',
        })
      );
      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          report: 'تقرير التحليل الكامل',
          confidence: 0.91,
          executionTime: expect.any(Number),
          timestamp: expect.any(String),
          stationsCount: 7,
        })
      );
    });

    it('يعيد 400 عندما يغيب النص', async () => {
      mockRequest.body = {};

      await analysisController.runSevenStationsPipeline(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockResponse.status).toHaveBeenCalledWith(400);
      expect(mockResponse.json).toHaveBeenCalledWith({
        error: 'النص مطلوب ولا يمكن أن يكون فارغاً',
        code: 'INVALID_TEXT',
      });
    });

    it('يعيد 400 عندما يكون النص فارغاً', async () => {
      mockRequest.body = { text: '   ' };

      await analysisController.runSevenStationsPipeline(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockResponse.status).toHaveBeenCalledWith(400);
    });

    it('يحوّل الطلب إلى قائمة الانتظار في النمط غير المتزامن', async () => {
      mockQueueAIAnalysis.mockResolvedValue('job-123');
      mockRequest.body = { text: 'نص طويل', async: true };

      await analysisController.runSevenStationsPipeline(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockQueueAIAnalysis).toHaveBeenCalledWith(
        expect.objectContaining({
          userId: 'user-123',
          analysisType: 'full',
          options: { text: 'نص طويل' },
        })
      );
      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: true,
          jobId: 'job-123',
          message: 'تم إضافة التحليل إلى قائمة الانتظار',
        })
      );
    });

    it('يعيد 500 عندما تفشل خدمة التحليل', async () => {
      mockRunFullPipeline.mockRejectedValue(new Error('Pipeline failed'));
      mockRequest.body = { text: 'نص الاختبار' };

      await analysisController.runSevenStationsPipeline(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockResponse.status).toHaveBeenCalledWith(500);
      expect(mockResponse.json).toHaveBeenCalledWith({
        error: 'حدث خطأ أثناء تحليل النص',
        message: 'Pipeline failed',
        code: 'ANALYSIS_FAILED',
      });
    });
  });

  describe('getStationDetails', () => {
    it('يعيد معلومات المحطات السبع', async () => {
      await analysisController.getStationDetails(
        mockRequest as Request,
        mockResponse as Response
      );

      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          stations: expect.any(Array),
          totalStations: 7,
          executionOrder: expect.any(String),
          outputFormat: expect.any(String),
        })
      );

      const stations = (mockResponse.json as ReturnType<typeof vi.fn>).mock.calls[0][0].stations;
      expect(stations).toHaveLength(7);
      expect(new Set(stations.map((station: { id: string }) => station.id)).size).toBe(7);
    });
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { AuthController } from './auth.controller';
import { Request, Response } from 'express';
import { z } from 'zod';

// تعريف نوع المستخدم للاختبار - User type definition for testing
interface UserPayload {
  id: string;
  email: string;
  firstName?: string;
  lastName?: string;
}

// Test Constants
const TEST_PASSWORD = 'StrongPass123!';
const INVALID_PASSWORD_TOO_SHORT = 'abc';
const INVALID_PASSWORD_EMPTY = '';

// Mock dependencies
vi.mock('../services/auth.service', () => ({
  authService: {
    signup: vi.fn(),
    login: vi.fn(),
    getUserById: vi.fn(),
    revokeRefreshToken: vi.fn(),
  },
}));

vi.mock('../utils/logger', () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

describe('AuthController', () => {
  let authController: AuthController;
  // تعريف mockRequest مع دعم خاصية user
  // Define mockRequest with support for user property
  let mockRequest: Partial<Request> & { user?: UserPayload };
  let mockResponse: Partial<Response>;
  let authService: any;

  beforeEach(async () => {
    authController = new AuthController();

    mockRequest = {
      body: {},
      cookies: {},
    };

    mockResponse = {
      status: vi.fn().mockReturnThis(),
      json: vi.fn().mockReturnThis(),
      cookie: vi.fn().mockReturnThis(),
      clearCookie: vi.fn().mockReturnThis(),
    };

    const authServiceModule = await import('../services/auth.service');
    authService = authServiceModule.authService;

    vi.clearAllMocks();
  });

  describe('signup', () => {
    it('should successfully create a new user', async () => {
      const signupData = {
        email: 'test@example.com',
        password: TEST_PASSWORD,
        firstName: 'Test',
        lastName: 'User',
      };

      const mockUser = {
        id: 'user-123',
        email: signupData.email,
        firstName: signupData.firstName,
        lastName: signupData.lastName,
      };

      const mockToken = 'jwt-token';
      const mockRefreshToken = 'refresh-token';

      mockRequest.body = signupData;

      vi.mocked(authService.signup).mockResolvedValue({
        accessToken: mockToken,
        refreshToken: mockRefreshToken,
        user: mockUser,
      });

      await authController.signup(mockRequest as Request, mockResponse as Response);

      expect(authService.signup).toHaveBeenCalledWith(
        signupData.email,
        signupData.password,
        signupData.firstName,
        signupData.lastName
      );

      expect(mockResponse.cookie).toHaveBeenCalledWith('refreshToken', expect.any(String), expect.any(Object));
      expect(mockResponse.cookie).toHaveBeenCalledWith('accessToken', mockToken, {
        httpOnly: true,
        secure: false, // In test environment
        maxAge: 15 * 60 * 1000,
        sameSite: 'strict',
      });

      expect(mockResponse["status"]).toHaveBeenCalledWith(201);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        message: 'تم إنشاء الحساب بنجاح',
        data: {
          user: mockUser,
          token: mockToken,
        },
      });
    });

    it('should handle validation errors', async () => {
      mockRequest.body = {
        email: 'invalid-email',
        password: INVALID_PASSWORD_TOO_SHORT,
      };

      await authController.signup(mockRequest as Request, mockResponse as Response);

      expect(mockResponse["status"]).toHaveBeenCalledWith(400);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'بيانات غير صالحة',
        details: expect.any(Array),
      });
    });

    it('should handle duplicate email error', async () => {
      mockRequest.body = {
        email: 'existing@example.com',
        password: TEST_PASSWORD,
      };

      vi.mocked(authService.signup).mockRejectedValue(
        new Error('المستخدم موجود بالفعل')
      );

      await authController.signup(mockRequest as Request, mockResponse as Response);

      expect(mockResponse["status"]).toHaveBeenCalledWith(400);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'المستخدم موجود بالفعل',
      });
    });

    it('should work with optional firstName and lastName', async () => {
      const signupData = {
        email: 'test@example.com',
        password: TEST_PASSWORD,
      };

      const mockUser = {
        id: 'user-123',
        email: signupData.email,
      };

      const mockToken = 'jwt-token';
      const mockRefreshToken = 'refresh-token';

      mockRequest.body = signupData;

      vi.mocked(authService.signup).mockResolvedValue({
        accessToken: mockToken,
        refreshToken: mockRefreshToken,
        user: mockUser,
      });

      await authController.signup(mockRequest as Request, mockResponse as Response);

      expect(authService.signup).toHaveBeenCalledWith(
        signupData.email,
        signupData.password,
        undefined,
        undefined
      );
    });
  });

  describe('login', () => {
    it('should successfully login user', async () => {
      const loginData = {
        email: 'test@example.com',
        password: TEST_PASSWORD,
      };

      const mockUser = {
        id: 'user-123',
        email: loginData.email,
      };

      const mockToken = 'jwt-token';
      const mockRefreshToken = 'refresh-token';

      mockRequest.body = loginData;

      vi.mocked(authService.login).mockResolvedValue({
        accessToken: mockToken,
        refreshToken: mockRefreshToken,
        user: mockUser,
      });

      await authController.login(mockRequest as Request, mockResponse as Response);

      expect(authService.login).toHaveBeenCalledWith(
        loginData.email,
        loginData.password
      );

      expect(mockResponse.cookie).toHaveBeenCalledWith('refreshToken', expect.any(String), expect.any(Object));
      expect(mockResponse.cookie).toHaveBeenCalledWith('accessToken', mockToken, {
        httpOnly: true,
        secure: false,
        maxAge: 15 * 60 * 1000,
        sameSite: 'strict',
      });

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        message: 'تم تسجيل الدخول بنجاح',
        data: {
          user: mockUser,
          token: mockToken,
        },
      });
    });

    it('should handle validation errors', async () => {
      mockRequest.body = {
        email: 'invalid-email',
        password: INVALID_PASSWORD_EMPTY,
      };

      await authController.login(mockRequest as Request, mockResponse as Response);

      expect(mockResponse["status"]).toHaveBeenCalledWith(400);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'بيانات غير صالحة',
        details: expect.any(Array),
      });
    });

    it('should handle invalid credentials', async () => {
      mockRequest.body = {
        email: 'test@example.com',
        password: 'wrong_' + TEST_PASSWORD,
      };

      vi.mocked(authService.login).mockRejectedValue(
        new Error('البريد الإلكتروني أو كلمة المرور غير صحيحة')
      );

      await authController.login(mockRequest as Request, mockResponse as Response);

      // Login errors return 401 instead of 400
      expect(mockResponse["status"]).toHaveBeenCalledWith(401);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'البريد الإلكتروني أو كلمة المرور غير صحيحة',
      });
    });
  });

  describe('logout', () => {
    it('should successfully logout user', async () => {
      mockRequest.cookies = { refreshToken: 'refresh-token' };

      await authController.logout(mockRequest as Request, mockResponse as Response);

      expect(authService.revokeRefreshToken).toHaveBeenCalledWith('refresh-token');
      expect(mockResponse.clearCookie).toHaveBeenCalledWith('refreshToken');
      expect(mockResponse.clearCookie).toHaveBeenCalledWith('accessToken');
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        message: 'تم تسجيل الخروج بنجاح',
      });
    });
  });

  describe('getCurrentUser', () => {
    it('should return current user', async () => {
      const mockUser = {
        id: 'user-123',
        email: 'test@example.com',
        firstName: 'Test',
        lastName: 'User',
      };

      mockRequest.user = mockUser;

      await authController.getCurrentUser(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: { user: mockUser },
      });
    });

    it('should return 401 if user not authenticated', async () => {
      mockRequest.user = undefined;

      await authController.getCurrentUser(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(401);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'غير مصرح',
      });
    });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { Request, Response } from 'express';

const { mockBreakdownService } = vi.hoisted(() => ({
  mockBreakdownService: {
    createProjectAndParse: vi.fn(),
    parseProject: vi.fn(),
    analyzeProject: vi.fn(),
    getProjectReport: vi.fn(),
    getProjectSchedule: vi.fn(),
    getSceneBreakdown: vi.fn(),
    reanalyzeScene: vi.fn(),
    exportReport: vi.fn(),
    chat: vi.fn(),
  },
}));

vi.mock('@/services/breakdown/service', () => ({
  breakdownService: mockBreakdownService,
}));

import { breakdownController } from './breakdown.controller';

function createMockResponse(): Response & {
  json: ReturnType<typeof vi.fn>;
  status: ReturnType<typeof vi.fn>;
} {
  const json = vi.fn();
  const response = {
    json,
    status: vi.fn(),
  } as unknown as Response & {
    json: ReturnType<typeof vi.fn>;
    status: ReturnType<typeof vi.fn>;
  };

  response["status"].mockImplementation(() => response);
  return response;
}

describe('BreakdownController', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('يعيد الحالة الصحية للخدمة', async () => {
    const res = createMockResponse();

    await breakdownController.health({} as Request, res);

    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({
        success: true,
        data: expect.objectContaining({
          service: 'breakdown',
          status: 'ok',
        }),
      })
    );
  });

  it('يرفض طلب التهيئة إذا غاب نص السيناريو', async () => {
    const req = {
      body: {},
      user: { id: 'user-1', email: 'test@example.com' },
    } as unknown as Request;
    const res = createMockResponse();

    await breakdownController.bootstrapProject(req, res);

    expect(res["status"]).toHaveBeenCalledWith(400);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({
        success: false,
        error: 'بيانات الطلب غير صالحة',
      })
    );
  });

  it('يعيد 404 إذا لم يجد تقرير المشروع', async () => {
    mockBreakdownService.getProjectReport.mockResolvedValueOnce(null);
    const req = {
      params: { projectId: 'project-1' },
      user: { id: 'user-1', email: 'test@example.com' },
    } as unknown as Request;
    const res = createMockResponse();

    await breakdownController.getProjectReport(req, res);

    expect(res["status"]).toHaveBeenCalledWith(404);
    expect(res.json).toHaveBeenCalledWith({
      success: false,
      error: 'لم يتم العثور على تقرير بريك دون للمشروع',
    });
  });

  it('يحوّل أخطاء الكيان غير الموجود إلى 404', async () => {
    mockBreakdownService.analyzeProject.mockRejectedValueOnce(
      new Error('المشروع غير موجود')
    );
    const req = {
      params: { projectId: 'missing-project' },
      user: { id: 'user-1', email: 'test@example.com' },
    } as unknown as Request;
    const res = createMockResponse();

    await breakdownController.analyzeProject(req, res);

    expect(res["status"]).toHaveBeenCalledWith(404);
    expect(res.json).toHaveBeenCalledWith({
      success: false,
      error: 'المشروع غير موجود',
    });
  });

  it('يرفض أي طلب محمي إذا غاب المستخدم المصادق', async () => {
    const req = {
      params: { projectId: 'project-1' },
    } as unknown as Request;
    const res = createMockResponse();

    await breakdownController.analyzeProject(req, res);

    expect(res["status"]).toHaveBeenCalledWith(401);
    expect(res.json).toHaveBeenCalledWith({
      success: false,
      error: 'غير مصرح',
    });
    expect(mockBreakdownService.analyzeProject).not.toHaveBeenCalled();
  });

  it('يمرر معرف المستخدم إلى خدمة التهيئة', async () => {
    mockBreakdownService.createProjectAndParse.mockResolvedValueOnce({
      projectId: 'project-1',
      title: 'مشروع',
      parsed: { scenes: [] },
    });
    const req = {
      body: { scriptContent: 'مشهد داخلي' },
      user: { id: 'user-42', email: 'owner@example.com' },
    } as unknown as Request;
    const res = createMockResponse();

    await breakdownController.bootstrapProject(req, res);

    expect(mockBreakdownService.createProjectAndParse).toHaveBeenCalledWith(
      'مشهد داخلي',
      undefined,
      'user-42'
    );
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { charactersController } from './characters.controller';
import { Request, Response } from 'express';
import { z } from 'zod';

// Mock dependencies
vi.mock('@/db', () => ({
  db: {
    select: vi.fn().mockReturnThis(),
    from: vi.fn().mockReturnThis(),
    where: vi.fn().mockReturnThis(),
    insert: vi.fn().mockReturnThis(),
    update: vi.fn().mockReturnThis(),
    delete: vi.fn().mockReturnThis(),
    values: vi.fn().mockReturnThis(),
    returning: vi.fn().mockReturnThis(),
    innerJoin: vi.fn().mockReturnThis(),
    limit: vi.fn().mockReturnThis(),
    orderBy: vi.fn().mockReturnThis(),
    set: vi.fn().mockReturnThis(),
  },
}));

vi.mock('@/db/schema', () => ({
  characters: { id: 'characters.id' },
  projects: { id: 'projects.id', userId: 'projects.userId' },
}));

vi.mock('@/utils/logger', () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

vi.mock('drizzle-orm', () => ({
  eq: vi.fn((col, val) => ({ col, val })),
  and: vi.fn((...conds) => ({ conditions: conds })),
}));

describe('CharactersController', () => {
  let mockRequest: Partial<Request>;
  let mockResponse: Partial<Response>;
  let mockDb: any;

  beforeEach(async () => {
    mockRequest = {
      params: {},
      body: {},
      user: { id: 'user-123' },
    };

    mockResponse = {
      status: vi.fn().mockReturnThis(),
      json: vi.fn().mockReturnThis(),
    };

    const dbModule = await import('@/db');
    mockDb = dbModule.db;

    vi.clearAllMocks();

    [
      'select',
      'from',
      'where',
      'insert',
      'update',
      'delete',
      'values',
      'returning',
      'innerJoin',
      'limit',
      'orderBy',
      'set',
    ].forEach((method) => {
      mockDb[method].mockReset().mockReturnThis();
    });
  });

  describe('getCharacters', () => {
    it('should return characters for authorized user', async () => {
      const mockProject = [{ id: 'project-1', userId: 'user-123' }];
      const mockCharacters = [
        { id: 'char-1', name: 'Test Character', projectId: 'project-1' },
      ];

      mockDb.select.mockReturnValueOnce({
        from: vi.fn().mockReturnValueOnce({
          where: vi.fn().mockReturnValueOnce(mockProject),
        }),
      });

      mockDb.select.mockReturnValueOnce(mockCharacters);

      mockRequest.params = { projectId: 'project-1' };

      await charactersController.getCharacters(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockCharacters,
      });
    });

    it('should return 401 for unauthorized user', async () => {
      mockRequest.user = undefined;

      await charactersController.getCharacters(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(401);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'غير مصرح',
      });
    });

    it('should return 400 when projectId is missing', async () => {
      mockRequest.params = {};

      await charactersController.getCharacters(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(400);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'معرف المشروع مطلوب',
      });
    });

    it('should return 404 when project not found', async () => {
      mockDb.select.mockReturnValueOnce({
        from: vi.fn().mockReturnValueOnce({
          where: vi.fn().mockReturnValueOnce([]),
        }),
      });

      mockRequest.params = { projectId: 'nonexistent-project' };

      await charactersController.getCharacters(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(404);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'المشروع غير موجود',
      });
    });

    it('should handle database errors gracefully', async () => {
      mockDb.select.mockRejectedValueOnce(new Error('Database error'));

      mockRequest.params = { projectId: 'project-1' };

      await charactersController.getCharacters(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(500);
      expect(mockResponse.json).toHaveBeenCalledWith({
        success: false,
        error: 'حدث خطأ أثناء جلب الشخصيات',
      });
    });
  });

  describe('getCharacter', () => {
    it('should return character for authorized user', async () => {
      const mockCharacter = { id: 'char-1', name: 'Test Character', projectId: 'project-1' };
      const mockProject = [{ id: 'project-1', userId: 'user-123' }];

      mockDb.select.mockReturnValueOnce({
        from: vi.fn().mockReturnValueOnce({
          where: vi.fn().mockReturnValueOnce([mockCharacter]),
        }),
      });

      mockDb.select.mockReturnValueOnce(mockProject);

      mockRequest.params = { id: 'char-1' };

      await charactersController.getCharacter(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse.json).toHaveBeenCalledWith({
        success: true,
        data: mockCharacter,
      });
    });

    it('should return 404 when character not found', async () => {
      mockDb.select.mockReturnValueOnce({
        from: vi.fn().mockReturnValueOnce({
          where: vi.fn().mockReturnValueOnce([]),
        }),
      });

      mockRequest.params = { id: 'nonexistent-character' };

      await charactersController.getCharacter(
        mockRequest as any,
        mockResponse as Response
      );

      expect(mockResponse["status"]).toHaveBeenCalledWith(404);
