    if (!req.user) {
      return res["status"](401).json({
        success: false,
        error: 'غير مصرح',
      });
    }

    const { id } = req.params;

    if (!id) {
      return res["status"](400).json({
        success: false,
        error: 'معرف المشروع مطلوب',
