import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { Request, Response, NextFunction } from "express";
import {
  wafMiddleware,
  updateWAFConfig,
  getWAFConfig,
  blockIP,
  unblockIP,
  getBlockedIPs,
  addCustomRule,
  removeCustomRule,
  getWAFEvents,
  getWAFStats,
  clearRateLimit,
  clearAllRateLimits,
  resetWAFConfig,
  WAF_PATTERNS,
  WAFRule,
} from "./waf.middleware";

// Mock logger
vi.mock("@/utils/logger", () => ({
  logger: {
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
    debug: vi.fn(),
  },
}));

// Mock env
