#!/usr/bin/env npx tsx
/**
 * agent.ts — وكيل OCR العربي الرئيسي
 *
 * مبني على Vercel AI SDK v6 مع دعم MCP.
 * يُنسّق عملية تحويل ملفات PDF العربية الممسوحة ضوئياً إلى نص.
 *
 * البنية المعمارية:
 *   ┌─────────────┐     ┌──────────────┐     ┌─────────────────┐
 *   │  المستخدم   │────▶│  ToolLoop    │────▶│  MCP Server     │
 *   │  (CLI)      │◀────│  Agent       │◀────│  (Mistral OCR)  │
 *   └─────────────┘     └──────┬───────┘     └─────────────────┘
 *                              │
 *                    ┌─────────┴─────────┐
 *                    │  أدوات محلية:     │
 *                    │  - تصنيف PDF     │
 *                    │  - قراءة ملفات   │
 *                    │  - كتابة ملفات   │
 *                    │  - سرد ملفات     │
 *                    └─────────┬─────────┘
 *                              │
 *                    ┌─────────┴─────────┐
 *                    │  أدوات المهارة:   │
 *                    │  (skill scripts)  │
 *                    │  - OCR Mistral   │
 *                    │  - كتابة مخرجات  │
 *                    │  - تحسين صور     │
 *                    │  - تصنيف PDF     │
 *                    └───────────────────┘
 */

import { ToolLoopAgent, stepCountIs } from "ai";
import { createMCPClient } from "@ai-sdk/mcp";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { openai } from "@ai-sdk/openai";
import { resolve } from "node:path";

import { buildAgentConfig, validateEnvironment } from "./config";
import {
  readFileTool,
  writeFileTool,
  listFilesTool,
  classifyPdfTool,
} from "./tools";
import {
  skillClassifyPdf,
  skillOcrMistral,
  skillWriteOutput,
  skillEnhanceImages,
} from "./skill-tools";

// ─── ألوان الطرفية ──────────────────────────────────────────

const C = {
  reset: "\x1b[0m",
  bold: "\x1b[1m",
  dim: "\x1b[2m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  blue: "\x1b[34m",
  red: "\x1b[31m",
  cyan: "\x1b[36m",
} as const;

function log(prefix: string, color: string, msg: string): void {
  console.error(`${color}${C.bold}[${prefix}]${C.reset} ${msg}`);
}

// ─── إنشاء عميل MCP ────────────────────────────────────────

async function createOcrMcpClient(serverPath: string) {
  log("MCP", C.blue, `الاتصال بخادم OCR: ${serverPath}`);

  const transport = new StdioClientTransport({
    command: "npx",
    args: ["tsx", serverPath],
    env: {
      ...process.env,
      // تمرير مفاتيح API للخادم
      MISTRAL_API_KEY: process.env["MISTRAL_API_KEY"] ?? "",
      OPENAI_API_KEY: process.env["OPENAI_API_KEY"] ?? "",
    },
  });

  const client = await createMCPClient({ transport });
  log("MCP", C.green, "تم الاتصال بنجاح");

  return client;
}

// ─── تعليمات الوكيل ─────────────────────────────────────────

const AGENT_INSTRUCTIONS = `أنت وكيل متخصص في استخراج النص العربي من ملفات PDF الممسوحة ضوئياً (OCR).

## مجموعات الأدوات المتاحة:

### 1. أدوات المهارة (skill scripts) — المسار الأساسي:
- **skill_classify_pdf**: تصنيف PDF (نصي / ممسوح / مختلط / محمي) — الخطوة الأولى دائماً
- **skill_ocr_mistral**: استخراج OCR عبر Mistral API → يُنتج ملف JSON خام
- **skill_write_output**: تحويل JSON الخام إلى TXT أو Markdown نهائي
- **skill_enhance_images**: تحسين جودة الصور قبل OCR (عند ضعف النتائج)

### 2. أدوات MCP (خادم OCR المتكامل) — مسار بديل:
- **convert_document_to_markdown**: تحويل شامل (OCR + تطبيع + LLM اختياري) في خطوة واحدة

### 3. أدوات نظام الملفات:
- **read_file**: قراءة محتوى ملف
- **write_file**: كتابة ملف جديد (يتجنب الكتابة فوق الموجود)
- **list_files**: سرد ملفات في مجلد مع تصفية حسب الامتداد
- **classify_pdf**: تصنيف سريع مدمج (بديل خفيف لـ skill_classify_pdf)

## سير العمل المعتاد (المسار الأساسي عبر أدوات المهارة):
1. إذا أعطاك المستخدم مسار مجلد → استخدم list_files لاكتشاف PDFs
2. صنّف كل ملف عبر **skill_classify_pdf**
3. إذا كان ممسوحاً أو مختلطاً:
   أ. نفّذ OCR عبر **skill_ocr_mistral** → ينتج ملف JSON
   ب. حوّل JSON إلى الصيغة المطلوبة عبر **skill_write_output**
4. إذا كانت النتائج ضعيفة → استخدم **skill_enhance_images** ثم أعد OCR
5. أبلغ المستخدم بالنتائج (المحرك، عدد الصفحات، الحجم، الوقت)

## المسار البديل (عبر MCP — خطوة واحدة):
- استخدم **convert_document_to_markdown** مباشرةً عندما:
  - المستخدم يريد تحويل سريع بدون تحكم تفصيلي
  - يريد تفعيل تطبيع النص العربي المتقدم (normalizer)
  - يريد تحسين LLM اختياري

## خيارات التطبيع المتاحة في convert_document_to_markdown:
- normalizeHamza: توحيد الهمزات (الافتراضي: true)
- removeDiacritics: إزالة التشكيل (الافتراضي: true)
- normalizeDigits: توحيد الأرقام — "arabic" أو "western" أو "none"
- scriptSpecificRules: قواعد السيناريوهات (الافتراضي: true)
- fixConnectedLetters: إصلاح الحروف الملتصقة (الافتراضي: true)

## قواعد استخراج النص (غير قابلة للتفاوض):
- الدقة الحرفية: لا تصحح أخطاء إملائية، لا تُعد الصياغة
- التشكيل: حافظ على كل علامات التشكيل إن وُجدت
- البنية: أسطر وفقرات كما في الأصل تماماً
- غير واضح: ضعه بين {غير واضح: وصف}
- لا تخمن أبداً — ضع العلامة وامضِ

## قواعد عامة:
- تحدث بالعربية المصرية المهنية دائماً
- أبلغ المستخدم بأي أخطاء أو تحذيرات فوراً
- لا تكتب فوق ملفات موجودة بدون إذن
- إذا كان الملف محمياً (protected) → أبلغ المستخدم وأوقف المعالجة
- إذا كان الملف أكبر من 50 صفحة → أبلغ المستخدم بالعدد قبل البدء`;

// ─── بناء الوكيل ────────────────────────────────────────────

async function buildAgent() {
  const config = buildAgentConfig();

  // التحقق من البيئة
  const envCheck = validateEnvironment();
  if (!envCheck.valid) {
    log("خطأ", C.red, `مفاتيح API مفقودة: ${envCheck.missing.join(", ")}`);
    log("خطأ", C.red, "أنشئ ملف .env بناءً على .env.example");
    process.exit(1);
  }

  // إنشاء عميل MCP للاتصال بخادم OCR
  let mcpClient: Awaited<ReturnType<typeof createOcrMcpClient>> | null = null;
  let mcpTools: Record<string, unknown> = {};

  try {
    mcpClient = await createOcrMcpClient(config.mcpServerPath);
    mcpTools = await mcpClient.tools();
    log(
      "أدوات",
      C.cyan,
      `تم تحميل ${Object.keys(mcpTools).length} أداة من خادم MCP`
    );
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log("تحذير", C.yellow, `فشل الاتصال بخادم MCP: ${msg}`);
    log("تحذير", C.yellow, "الوكيل سيعمل بالأدوات المحلية فقط");
  }

  // دمج كل الأدوات: محلية + مهارة (skill) + MCP
  const allTools = {
    // أدوات نظام الملفات
    classify_pdf: classifyPdfTool,
    read_file: readFileTool,
    write_file: writeFileTool,
    list_files: listFilesTool,
    // أدوات المهارة (skill scripts)
    skill_classify_pdf: skillClassifyPdf,
    skill_ocr_mistral: skillOcrMistral,
    skill_write_output: skillWriteOutput,
    skill_enhance_images: skillEnhanceImages,
    // أدوات MCP (خادم OCR المتكامل)
    ...mcpTools,
  };

  const skillCount = 4;
  const localCount = 4;
  const mcpCount = Object.keys(mcpTools).length;
  log(
    "وكيل",
    C.green,
    `إجمالي الأدوات: ${Object.keys(allTools).length} (${skillCount} مهارة + ${localCount} محلية + ${mcpCount} MCP)`
  );

  // بناء الوكيل
  const agent = new ToolLoopAgent({
    model: openai(config.agentModel),
    instructions: AGENT_INSTRUCTIONS,
    tools: allTools as Record<string, unknown>,
    stopWhen: stepCountIs(config.maxSteps),

    // ─── دوال رد النداء ─────────────────────────────
    onStepFinish: ({ text, toolCalls }) => {
      if (toolCalls && toolCalls.length > 0) {
        for (const call of toolCalls) {
          const callArgs =
            "input" in call
              ? (call as Record<string, unknown>).input
              : (call as Record<string, unknown>).args;
          log(
            "أداة",
            C.cyan,
            `← ${call.toolName}(${JSON.stringify(callArgs ?? {}).substring(0, 100)}...)`
          );
        }
      }
      if (text) {
        log("وكيل", C.dim, text.substring(0, 200));
      }
    },
  });

  return { agent, mcpClient, config };
}

// ─── واجهة سطر الأوامر ──────────────────────────────────────

async function main(): Promise<void> {
  log("بدء", C.green, "وكيل OCR العربي — Vercel AI SDK v6");
  log("بدء", C.dim, "─".repeat(50));

  const { agent, mcpClient, config } = await buildAgent();

  // تحليل معاملات سطر الأوامر
  const args = process.argv.slice(2);
  let userPrompt: string;

  if (args.length === 0) {
    // وضع تفاعلي — طلب افتراضي
    userPrompt = `اسرد ملفات PDF في المجلد: ${config.defaultInputDir}`;
    log("وضع", C.yellow, "لم يُحدد ملف — سيتم سرد ملفات PDF المتاحة");
  } else if (args[0] === "--prompt" || args[0] === "-p") {
    // طلب نصي حر
    userPrompt = args.slice(1).join(" ");
  } else {
    // مسار ملف PDF مباشر
    const pdfPath = resolve(args[0]);
    const outputFormat = args.includes("--txt") ? "txt" : "md";
    const outputPath = args
      .find((a) => a.startsWith("--output="))
      ?.split("=")[1];

    userPrompt = `حوّل ملف PDF التالي إلى ${outputFormat}:
المسار: ${pdfPath}${outputPath ? `\nمسار الإخراج: ${outputPath}` : ""}

الخطوات:
1. صنّف الملف أولاً
2. إذا كان ممسوحاً أو مختلطاً — نفّذ OCR عبر convert_document_to_markdown
3. اكتب النتيجة في ملف ${outputFormat}
4. أبلغني بالنتائج`;
  }

  log("طلب", C.blue, userPrompt.substring(0, 150));
  log("بدء", C.dim, "─".repeat(50));

  try {
    // تشغيل الوكيل
    const result = await agent.generate({
      prompt: userPrompt,
    });

    // عرض النتيجة النهائية
    console.error();
    log("نتيجة", C.green, "─".repeat(50));
    console.error(result.text);
    log("نتيجة", C.green, "─".repeat(50));

    // إحصائيات الاستخدام
    const usage = result.usage as unknown as Record<string, number> | undefined;
    if (usage) {
      const input = usage["promptTokens"] ?? usage["inputTokens"] ?? 0;
      const output = usage["completionTokens"] ?? usage["outputTokens"] ?? 0;
      const total = usage["totalTokens"] ?? input + output;
      log(
        "إحصائيات",
        C.dim,
        `الرموز: ${input} إدخال + ${output} إخراج = ${total} إجمالي`
      );
    }
    log("إحصائيات", C.dim, `الخطوات: ${result.steps?.length ?? 0}`);
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log("خطأ", C.red, `فشل تشغيل الوكيل: ${msg}`);
    if (error instanceof Error && error.stack) {
      console.error(error.stack);
    }
    process.exitCode = 1;
  } finally {
    // تنظيف اتصال MCP
    if (mcpClient) {
      try {
        await mcpClient.close();
        log("MCP", C.dim, "تم إغلاق الاتصال");
      } catch {
        // تجاهل أخطاء الإغلاق
      }
    }
  }
}

// ─── نقطة الدخول ────────────────────────────────────────────

main().catch((error) => {
  console.error("خطأ غير متوقع:", error);
  process.exit(1);
});

#!/usr/bin/env npx tsx
/**
 * batch.ts — معالجة دفعية لعدة ملفات PDF
 *
 * يقرأ مجلداً كاملاً ويُعالج جميع ملفات PDF الموجودة فيه.
 * يستخدم نفس بنية الوكيل مع تكرار على كل ملف.
 *
 * الاستخدام:
 *   npx tsx src/batch.ts /path/to/pdf/folder
 *   npx tsx src/batch.ts /path/to/pdf/folder --output /path/to/output --format txt
 */

import { generateText, stepCountIs } from "ai";
import { createMCPClient } from "@ai-sdk/mcp";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { openai } from "@ai-sdk/openai";
import { readdir, mkdir } from "node:fs/promises";
import { join, extname, basename, resolve } from "node:path";

import { buildAgentConfig, validateEnvironment } from "./config";

// ─── ألوان الطرفية ──────────────────────────────────────────

const C = {
  reset: "\x1b[0m",
  bold: "\x1b[1m",
  dim: "\x1b[2m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  red: "\x1b[31m",
  cyan: "\x1b[36m",
} as const;

function log(prefix: string, color: string, msg: string): void {
  console.error(`${color}${C.bold}[${prefix}]${C.reset} ${msg}`);
}

// ─── تحليل المعاملات ────────────────────────────────────────

interface BatchArgs {
  inputDir: string;
  outputDir: string;
  format: "txt" | "md";
}

function parseBatchArgs(): BatchArgs {
  const args = process.argv.slice(2);
  if (args.length === 0) {
    console.error(
      "الاستخدام: npx tsx src/batch.ts <مجلد_PDF> [--output <مجلد>] [--format txt|md]"
    );
    process.exit(1);
  }

  const inputDir = resolve(args[0]);
  let outputDir = "";
  let format: "txt" | "md" = "md";

  for (let i = 1; i < args.length; i++) {
    if (args[i] === "--output" && args[i + 1]) {
      outputDir = resolve(args[++i]);
    } else if (args[i] === "--format" && args[i + 1]) {
      format = args[++i] === "txt" ? "txt" : "md";
    }
  }

  if (!outputDir) {
    outputDir = join(inputDir, "ocr_output");
  }

  return { inputDir, outputDir, format };
}

// ─── المنطق الرئيسي ────────────────────────────────────────

async function main(): Promise<void> {
  const { inputDir, outputDir, format } = parseBatchArgs();
  const config = buildAgentConfig();

  log("دفعي", C.green, `مجلد الإدخال: ${inputDir}`);
  log("دفعي", C.green, `مجلد الإخراج: ${outputDir}`);
  log("دفعي", C.green, `الصيغة: ${format.toUpperCase()}`);

  // التحقق من البيئة
  const envCheck = validateEnvironment();
  if (!envCheck.valid) {
    log("خطأ", C.red, `مفاتيح مفقودة: ${envCheck.missing.join(", ")}`);
    process.exit(1);
  }

  // اكتشاف ملفات PDF
  const entries = await readdir(inputDir);
  const pdfFiles = entries.filter((f) => extname(f).toLowerCase() === ".pdf");

  if (pdfFiles.length === 0) {
    log("خطأ", C.yellow, "لا توجد ملفات PDF في المجلد المحدد");
    process.exit(0);
  }

  log("دفعي", C.cyan, `تم اكتشاف ${pdfFiles.length} ملف PDF`);

  // إنشاء مجلد الإخراج
  await mkdir(outputDir, { recursive: true });

  // إنشاء عميل MCP
  let mcpClient: Awaited<ReturnType<typeof createMCPClient>> | null = null;
  let mcpTools: Record<string, unknown> = {};

  try {
    const transport = new StdioClientTransport({
      command: "npx",
      args: ["tsx", config.mcpServerPath],
      env: {
        ...process.env,
        MISTRAL_API_KEY: process.env["MISTRAL_API_KEY"] ?? "",
        OPENAI_API_KEY: process.env["OPENAI_API_KEY"] ?? "",
      },
    });
    mcpClient = await createMCPClient({ transport });
    mcpTools = await mcpClient.tools();
    log("MCP", C.green, "تم الاتصال بخادم OCR");
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log("خطأ", C.red, `فشل الاتصال بخادم MCP: ${msg}`);
    process.exit(1);
  }

  // معالجة كل ملف
  const results: Array<{
    file: string;
    success: boolean;
    output?: string;
    error?: string;
    timeMs: number;
  }> = [];

  for (let i = 0; i < pdfFiles.length; i++) {
    const pdfFile = pdfFiles[i]!;
    const pdfPath = join(inputDir, pdfFile);
    const outputName = basename(pdfFile, ".pdf") + "." + format;
    const outputPath = join(outputDir, outputName);

    log("تقدم", C.cyan, `[${i + 1}/${pdfFiles.length}] ${pdfFile}`);

    const startTime = Date.now();

    try {
      await generateText({
        model: openai(config.agentModel),
        tools: mcpTools as Record<string, unknown>,
        stopWhen: stepCountIs(5),
        messages: [
          {
            role: "user",
            content: [
              {
                type: "text",
                text: `حوّل هذا الملف إلى markdown:
inputPath: ${pdfPath}
outputPath: ${outputPath}
استخدم الإعدادات الافتراضية للتطبيع.`,
              },
            ],
          },
        ],
      });

      const elapsed = Date.now() - startTime;
      results.push({
        file: pdfFile,
        success: true,
        output: outputPath,
        timeMs: elapsed,
      });
      log(
        "نجاح",
        C.green,
        `${pdfFile} → ${outputName} (${(elapsed / 1000).toFixed(1)}ث)`
      );
    } catch (error: unknown) {
      const elapsed = Date.now() - startTime;
      const msg = error instanceof Error ? error.message : String(error);
      results.push({
        file: pdfFile,
        success: false,
        error: msg,
        timeMs: elapsed,
      });
      log("فشل", C.red, `${pdfFile}: ${msg}`);
    }
  }

  // ملخص النتائج
  const succeeded = results.filter((r) => r.success).length;
  const failed = results.filter((r) => !r.success).length;
  const totalTimeMs = results.reduce((sum, r) => sum + r.timeMs, 0);

  console.error();
  log("ملخص", C.green, "═".repeat(50));
  log("ملخص", C.green, `الإجمالي: ${pdfFiles.length} ملف`);
  log("ملخص", C.green, `نجاح: ${succeeded} | فشل: ${failed}`);
  log("ملخص", C.green, `الوقت الكلي: ${(totalTimeMs / 1000).toFixed(1)} ثانية`);
  log("ملخص", C.green, `مجلد الإخراج: ${outputDir}`);

  if (failed > 0) {
    log("ملخص", C.red, "الملفات الفاشلة:");
    for (const r of results.filter((r) => !r.success)) {
      log("ملخص", C.red, `  - ${r.file}: ${r.error}`);
    }
  }

  // تنظيف
  if (mcpClient) {
    try {
      await mcpClient.close();
    } catch {
      // تجاهل
    }
  }

  // رمز الخروج
  process.exitCode = failed > 0 ? 1 : 0;
}

main().catch((error) => {
  console.error("خطأ غير متوقع:", error);
  process.exit(1);
});

/**
 * config.ts — تحميل وإدارة إعدادات الوكيل
 *
 * يقرأ متغيرات البيئة من .env ويُعدّ الإعدادات الافتراضية.
 */

import { config as dotenvConfig } from "dotenv";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import type { AgentConfig } from "./types";

// ─── تحميل متغيرات البيئة ───────────────────────────────────

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// بحث عن .env في جذر المشروع ثم المجلد الأب
dotenvConfig({ path: resolve(__dirname, "../../.env"), quiet: true });
dotenvConfig({ path: resolve(__dirname, "../../../.env"), quiet: true });

// ─── التحقق من المتطلبات ────────────────────────────────────

/** التحقق من وجود مفاتيح API المطلوبة */
export function validateEnvironment(): { valid: boolean; missing: string[] } {
  const required = ["OPENAI_API_KEY"];
  const recommended = ["MISTRAL_API_KEY"];
  const missing: string[] = [];
  const warnings: string[] = [];

  for (const key of required) {
    if (!process.env[key]) {
      missing.push(key);
    }
  }

  for (const key of recommended) {
    if (!process.env[key]) {
      warnings.push(key);
    }
  }

  if (warnings.length > 0) {
    console.error(`⚠ مفاتيح موصى بها غير موجودة: ${warnings.join(", ")}`);
  }

  return { valid: missing.length === 0, missing };
}

// ─── بناء الإعدادات ─────────────────────────────────────────

/** بناء إعدادات الوكيل من متغيرات البيئة مع القيم الافتراضية */
export function buildAgentConfig(): AgentConfig {
  const projectRoot = resolve(__dirname, "../..");

  return {
    agentModel: process.env["AGENT_MODEL"] ?? "gpt-4o",
    maxSteps: parseInt(process.env["AGENT_MAX_STEPS"] ?? "10", 10),
    // خادم MCP — داخل البايبلاين في mcp-server/index.ts
    mcpServerPath:
      process.env["MCP_SERVER_PATH"] ??
      resolve(__dirname, "mcp-server", "index.ts"),
    defaultInputDir: process.env["DEFAULT_INPUT_DIR"] ?? resolve(projectRoot),
    defaultOutputDir: process.env["DEFAULT_OUTPUT_DIR"] ?? resolve(projectRoot),
  };
}

/**
 * @description بناء إعدادات محول OCR من سطر الأوامر ومتغيرات البيئة
 */

import process from "node:process";
import type {
  ConfigManager,
  LLMConfig,
  MistralOCRConfig,
  NormalizationOptions,
  ParsedArgs,
  PreOCRConfig,
} from "./types.js";
import { clamp, isTruthy, toNumberFloat, toNumberInt } from "./text-helpers.js";

const DEFAULT_LLM_MODEL = "kimi-k2.5";
const DEFAULT_MISTRAL_OCR_MODEL = "mistral-ocr-latest";
const DEFAULT_PRE_OCR_LANG = "ar";

const DEFAULT_MATCH_THRESHOLD = 0.88;
const DEFAULT_FULLPAGE_FALLBACK_RATIO = 0.7;
const DEFAULT_REGION_PADDING_PX = 12;
const DEFAULT_LLM_MAX_ITERATIONS = 3;
const DEFAULT_LLM_TARGET_MATCH = 100.0;
const DEFAULT_DIFF_PREVIEW_LINES = 12;

const DEFAULT_INPUT = String.raw`E:\New folder (31)\12.pdf`;

function parseArgs(argv: string[]): ParsedArgs {
  const parsed: ParsedArgs = {};

  for (let i = 0; i < argv.length; i += 1) {
    const token = argv[i];
    if (!token.startsWith("--")) {
      continue;
    }

    const arg = token.slice(2);
    const eq = arg.indexOf("=");

    if (eq >= 0) {
      const name = arg.slice(0, eq).trim();
      const value = arg.slice(eq + 1);
      if (name) {
        parsed[name] = value;
      }
      continue;
    }

    const name = arg.trim();
    if (!name) {
      continue;
    }

    const next = argv[i + 1];
    if (next && !next.startsWith("--")) {
      parsed[name] = next;
      i += 1;
    } else {
      parsed[name] = true;
    }
  }

  return parsed;
}

function argString(parsed: ParsedArgs, name: string, fallback: string): string {
  const v = parsed[name];
  if (typeof v === "string" && v.trim()) {
    return v;
  }
  return fallback;
}

function argOptionalString(
  parsed: ParsedArgs,
  name: string
): string | undefined {
  const v = parsed[name];
  if (typeof v === "string" && v.trim()) {
    return v;
  }
  return undefined;
}

function argBool(parsed: ParsedArgs, name: string, fallback = false): boolean {
  const v = parsed[name];
  if (typeof v === "boolean") {
    return v;
  }
  if (typeof v === "string") {
    return isTruthy(v);
  }
  return fallback;
}

export function buildConfig(argv: string[]): ConfigManager {
  const args = parseArgs(argv);

  const llm: LLMConfig = {
    enabled: argBool(args, "use-llm"),
    model: argString(args, "llm-model", DEFAULT_LLM_MODEL),
    referencePath: argOptionalString(args, "llm-reference"),
    strict: argBool(args, "llm-strict"),
    iterative: !argBool(args, "llm-no-iterative"),
    maxIterations: Math.max(
      1,
      toNumberInt(
        argOptionalString(args, "llm-max-iterations"),
        DEFAULT_LLM_MAX_ITERATIONS
      )
    ),
    targetMatch: clamp(
      toNumberFloat(
        argOptionalString(args, "llm-target-match"),
        DEFAULT_LLM_TARGET_MATCH
      ),
      0,
      100
    ),
    diffPreviewLines: Math.max(
      1,
      toNumberInt(
        argOptionalString(args, "llm-diff-preview-lines"),
        DEFAULT_DIFF_PREVIEW_LINES
      )
    ),
  };

  const tableRaw = (
    argOptionalString(args, "mistral-table-format") ??
    process.env['MISTRAL_OCR_TABLE_FORMAT'] ??
    ""
  )
    .trim()
    .toLowerCase();
  const tableFormat =
    tableRaw === "markdown" || tableRaw === "html"
      ? (tableRaw as "markdown" | "html")
      : undefined;

  const mistral: MistralOCRConfig = {
    model: argString(
      args,
      "mistral-ocr-model",
      (process.env['MISTRAL_OCR_MODEL'] ?? DEFAULT_MISTRAL_OCR_MODEL).trim() ||
        DEFAULT_MISTRAL_OCR_MODEL
    ),
    useDocumentInput: !argBool(args, "mistral-disable-document-input"),
    useBatchOCR: argBool(args, "mistral-use-batch"),
    batchTimeoutSec: Math.max(
      5,
      toNumberInt(
        argOptionalString(args, "mistral-batch-timeout-sec") ??
          process.env['MISTRAL_BATCH_TIMEOUT_SEC'],
        300
      )
    ),
    batchPollIntervalSec: Math.max(
      0.5,
      toNumberFloat(
        argOptionalString(args, "mistral-batch-poll-interval-sec") ??
          process.env['MISTRAL_BATCH_POLL_INTERVAL_SEC'],
        3
      )
    ),
    annotationSchemaPath:
      argOptionalString(args, "mistral-annotation-schema") ??
      (process.env['MISTRAL_ANNOTATION_SCHEMA_PATH']?.trim() || undefined),
    annotationPrompt:
      argOptionalString(args, "mistral-annotation-prompt") ??
      (process.env['MISTRAL_ANNOTATION_PROMPT']?.trim() || undefined),
    annotationOutputPath:
      argOptionalString(args, "mistral-annotation-output") ??
      (process.env['MISTRAL_ANNOTATION_OUTPUT_PATH']?.trim() || undefined),
    annotationStrict: !argBool(args, "mistral-annotation-non-strict"),
    tableFormat,
    extractHeader: argBool(args, "mistral-extract-header"),
    extractFooter: argBool(args, "mistral-extract-footer"),
    includeImageBase64: argBool(args, "mistral-include-image-base64"),
  };
  if (mistral.model !== DEFAULT_MISTRAL_OCR_MODEL) {
    throw new Error(
      `Mistral OCR model must be ${DEFAULT_MISTRAL_OCR_MODEL}. Received: ${mistral.model}`
    );
  }

  const preOcr: PreOCRConfig = {
    enabled: !argBool(args, "disable-pre-ocr-filter"),
    lang: argString(
      args,
      "pre-ocr-lang",
      (process.env['PRE_OCR_LANG'] ?? DEFAULT_PRE_OCR_LANG).trim() ||
        DEFAULT_PRE_OCR_LANG
    ),
    matchThreshold: clamp(
      toNumberFloat(
        argOptionalString(args, "pre-ocr-match-threshold"),
        DEFAULT_MATCH_THRESHOLD
      ),
      0,
      1
    ),
    fullpageFallbackRatio: clamp(
      toNumberFloat(
        argOptionalString(args, "pre-ocr-fullpage-fallback-ratio"),
        DEFAULT_FULLPAGE_FALLBACK_RATIO
      ),
      0,
      1
    ),
    regionPaddingPx: Math.max(
      0,
      toNumberInt(
        argOptionalString(args, "pre-ocr-region-padding-px"),
        DEFAULT_REGION_PADDING_PX
      )
    ),
  };

  const normalizerOptions: NormalizationOptions = {
    normalizeYa: argBool(args, "normalize-ya", false),
    normalizeTaMarbuta: argBool(args, "normalize-ta-marbuta", false),
    normalizeHamza: !argBool(args, "no-normalize-hamza"),
    normalizeDigits: (argOptionalString(args, "normalize-digits") ??
      "arabic") as "none" | "arabic" | "western",
    removeDiacritics: !argBool(args, "no-remove-diacritics"),
    fixConnectedLetters: !argBool(args, "no-fix-connected-letters"),
    fixArabicPunctuation: !argBool(args, "no-fix-arabic-punctuation"),
    scriptSpecificRules: !argBool(args, "no-script-specific-rules"),
  };

  return {
    inputPath: argString(args, "input", DEFAULT_INPUT),
    outputPath: argOptionalString(args, "output"),
    normalizeOutput: !argBool(args, "no-normalize"),
    normalizerOptions,
    saveRawMarkdown: !argBool(args, "no-raw"),
    llm,
    mistral,
    preOcr,
  };
}

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
  ErrorCode,
  McpError,
} from "@modelcontextprotocol/sdk/types.js";
import { existsSync, readFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { parse as parseEnv } from "dotenv";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const collectEnvCandidates = (startPath, limit = 5) => {
  const candidates = [];
  let current = resolve(startPath);

  for (let index = 0; index < limit; index += 1) {
    candidates.push(resolve(current, ".env"));
    const parent = dirname(current);
    if (parent === current) {
      break;
    }
    current = parent;
  }

  return candidates;
};

const stripWrappingQuotes = (value) => value.replace(/^['"]|['"]$/g, "");

const isPlaceholderEnvValue = (key, value) => {
  const trimmed = stripWrappingQuotes((value ?? "").trim());
  if (!trimmed) {
    return true;
  }

  if (trimmed.includes("CHANGE_THIS")) {
    return true;
  }

  if (key === "DATABASE_URL" && /:\/\/USER:PASSWORD@HOST(?::\d+)?\/DB_NAME/i.test(trimmed)) {
    return true;
  }

  return false;
};

const applyEnvFile = (filePath) => {
  const parsed = parseEnv(readFileSync(filePath));

  for (const [key, rawValue] of Object.entries(parsed)) {
    const value = rawValue.trim();
    const existingValue = process.env[key];

    if (isPlaceholderEnvValue(key, value)) {
      continue;
    }

    if (existingValue === undefined || isPlaceholderEnvValue(key, existingValue)) {
      process.env[key] = value;
    }
  }
};

const seen = new Set();
for (const candidate of [
  ...collectEnvCandidates(process.cwd()),
  ...collectEnvCandidates(__dirname),
]) {
  const normalized = resolve(candidate);
  if (seen.has(normalized) || !existsSync(normalized)) {
    continue;
  }

  seen.add(normalized);
  applyEnvFile(normalized);
}

