          description: "Fix Arabic punctuation spacing (default: true)",
          default: true,
        },
        scriptSpecificRules: {
          type: "boolean",
          description: "Enable screenplay-specific rules (default: true)",
          default: true,
        },
      },
    },
  },
  required: ["inputPath"],
};

server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "convert_document_to_markdown",
        description:
          "Converts a PDF document to Markdown using Mistral OCR with optional LLM refinement and normalization.",
        inputSchema: convertDocumentInputSchema,
      },
    ],
  };
});

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "convert_document_to_markdown") {
    throw new McpError(
      ErrorCode.MethodNotFound,
      `Unknown tool: ${request.params.name}`
    );
  }

  const args = request.params.arguments as {
    inputPath: string;
    outputPath?: string;
    normalizeOutput?: boolean;
    saveRawMarkdown?: boolean;
    useLlm?: boolean;
    llmModel?: string;
    llmReferencePath?: string;
    llmStrict?: boolean;
    mistralOcrModel?: string;
    useBatchOcr?: boolean;
    normalizerOptions?: NormalizationOptions;
  };

  if (!args.inputPath) {
    throw new McpError(ErrorCode.InvalidParams, "inputPath is required");
  }

  const {
    inputPath,
    outputPath,
    normalizeOutput = true,
    saveRawMarkdown = true,
    useLlm = false,
    llmModel = "kimi-k2.5",
    llmReferencePath,
    llmStrict = false,
    mistralOcrModel = "mistral-ocr-latest",
    useBatchOcr = false,
    normalizerOptions,
  } = args;

  if (mistralOcrModel !== CANONICAL_MISTRAL_OCR_MODEL) {
    throw new McpError(
      ErrorCode.InvalidParams,
      `mistralOcrModel must be ${CANONICAL_MISTRAL_OCR_MODEL}.`
    );
  }

  const config: ConfigManager = {
    inputPath,
    outputPath,
    normalizeOutput,
    normalizerOptions,
    saveRawMarkdown,
    llm: {
      enabled: useLlm,
      model: llmModel,
      referencePath: llmReferencePath,
      strict: llmStrict,
      iterative: true,
      maxIterations: 2,
      targetMatch: 98.5,
      diffPreviewLines: 12,
    },
    mistral: {
      model: mistralOcrModel,
      useDocumentInput: true,
      useBatchOCR: useBatchOcr,
      batchTimeoutSec: 300,
      batchPollIntervalSec: 3,
      annotationStrict: false,
      extractHeader: false,
      extractFooter: false,
      includeImageBase64: false,
    },
    preOcr: {
      enabled: true,
      lang: "ar",
      matchThreshold: 0.88,
      fullpageFallbackRatio: 0.7,
      regionPaddingPx: 12,
    },
  };

  try {
    const converter = new PDFToTextConverter(config);
    const { finalMarkdown } = await converter.convert();

    // Attempt to save to outputPath if specified, or generate a default one
    let savedPath = "Not saved (in-memory only)";
    let successMsg = "Document converted successfully.";

    try {
      const outPath = converter.resolveOutputPath();
      const nonOverwritingPath = await converter.getNonOverwritingPath(outPath);
      const { writeFile } = await import("node:fs/promises");
      await writeFile(nonOverwritingPath, finalMarkdown, "utf-8");
      savedPath = nonOverwritingPath;
      successMsg += ` Saved to ${savedPath}`;
    } catch (fsError) {
      console.error("Failed to write to file:", fsError);
      successMsg += ` Note: Failed to write to file: ${fsError}`;
    }

    return {
      content: [
        {
          type: "text",
          text: `${successMsg}\n\nFinal Markdown Preview (first 1000 chars):\n${finalMarkdown.substring(0, 1000)}...`,
        },
      ],
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    return {
      content: [
        {
          type: "text",
          text: `Conversion failed: ${errorMessage}`,
        },
      ],
      isError: true,
    };
  }
});

async function run() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Mistral OCR MCP Server running on stdio");
}

run().catch((error) => {
  console.error("Fatal error:", error);
  process.exit(1);
});

/**
 * @description طبقة LLM لتحسين النصوص المستخرجة من OCR عبر Kimi Chat
 */

import { readFile } from "node:fs/promises";
import process from "node:process";
import { setTimeout as sleep } from "node:timers/promises";
import type { JsonRecord, LLMConfig } from "./types.js";
import { log } from "./ocr-logger.js";
import {
  CRITICAL_OCR_REPLACEMENTS,
  createTimeoutState,
  ensureKimiApiKey,
  ensureTrailingNewline,
  field,
  fileExists,
  getEnvOrRaise,
  isRetryableHttpStatus,
  isRetryableRequestError,
  normalizeHindiDigitsToWestern,
  normalizeSceneHeadersRobust,
  retryDelayMs,
  str,
} from "./text-helpers.js";
import { APP_NAME } from "./ocr-logger.js";
import { OCRPreprocessor } from "./ocr-preprocessor.js";

const DEFAULT_LLM_MODEL = "kimi-k2.5";

export class LLMPostProcessor {
  private static readonly SYSTEM_PROMPT = `أنت خبير في تصحيح نصوص السيناريو العربية. مهمتك:
1. مقارنة النص المدخل بالمرجع حرفياً
2. إصلاح الأخطاء الهيكلية: ترويسات المشاهد، أسماء المتكلمين، علامات الانتقال
3. إضافة كلمة "قطع" قبل كل مشهد جديد (باستثناء المشهد الأول)
4. الحفاظ على التشكيل والهمزات من المرجع
5. استخدام • لعلامات الكلام وليس -
6. الحفاظ على التنسيق الدقيق: "نهار \\-داخلي" وليس "نهار -داخلي"
7. إرجاع Markdown فقط بدون أي شرح`;

  private static readonly USER_TEMPLATE = `قم بتصحيح النص التالي ليتطابق 100% مع المرجع:

[النص المرجعي - استخدمه كحقيقة مطلقة]
{reference_text}

[النص المدخل - قم بتصحيحه]
{markdown_text}

[ملاحظات ما قبل المعالجة]
{preprocess_notes}

[تعليقات إضافية]
{feedback}

قواعد صارمة:
1. أضف "قطع" في سطر منفصل قبل كل مشهد جديد (بعد المشهد الأول)
2. استخدم • للكلام وليس -
3. الحفاظ على التشكيل والهمزات كما في المرجع
4. "إم إم" وليس "ام ام"
5. تنسيق المشهد: "مشهد1 نهار \\-داخلي"
6. لا تدمج السطور المستقلة
7. صحّح الكلمات الحرجة الشائعة مثل: رينا→ربنا، الضياع→الضباع، ينكي→بنكي
8. أخرج Markdown فقط`;

  private static readonly KIMI_BASE_URL = (
    process.env['KIMI_BASE_URL'] ?? "https://api.moonshot.ai/v1"
  ).replace(/\/+$/u, "");
  private static readonly KIMI_HTTP_TIMEOUT_MS = Math.max(
    30_000,
    Number.parseInt(process.env['KIMI_HTTP_TIMEOUT_MS'] ?? "180000", 10) || 180_000
  );
  private static readonly KIMI_HTTP_MAX_RETRIES = Math.max(
    0,
    Math.min(
      Number.parseInt(process.env['KIMI_HTTP_MAX_RETRIES'] ?? "3", 10) || 3,
      5
    )
  );
  private static readonly DEFAULT_KIMI_MODEL = "kimi-k2.5";

  private readonly config: LLMConfig;
  private referenceCache?: string;
  private readonly preprocessor: OCRPreprocessor;

  constructor(config: LLMConfig) {
    this.config = config;
    this.preprocessor = new OCRPreprocessor();
  }

  async getReferenceText(): Promise<string> {
    if (this.referenceCache !== undefined) {
      return this.referenceCache;
    }

    if (!this.config.referencePath) {
      this.referenceCache = "";
      return this.referenceCache;
    }

    if (!(await fileExists(this.config.referencePath))) {
      throw new Error(`الملف المرجعي غير موجود: ${this.config.referencePath}`);
    }

    this.referenceCache = await readFile(this.config.referencePath, "utf-8");
    return this.referenceCache;
  }

  async postprocess(
    markdownText: string,
    referenceText?: string,
    feedback = ""
  ): Promise<string> {
    const effectiveReference = referenceText ?? (await this.getReferenceText());
    const preprocessed = this.preprocessor.preprocess(markdownText);

    const userPrompt = LLMPostProcessor.USER_TEMPLATE.replace(
      "{reference_text}",
      effectiveReference || "N/A"
    )
      .replace("{markdown_text}", preprocessed.text)
      .replace(
        "{preprocess_notes}",
        preprocessed.detectedIssues.join("\n") || "لا توجد ملاحظات"
      )
      .replace("{feedback}", feedback || "N/A");

    const data = await this.callKimiChat(userPrompt);

    let out = this.extractOutputText(data).trim();
    if (!out) {
      throw new Error("الاستجابة من نموذج LLM كانت فارغة.");
    }

    out = this.stripMarkdownFences(out);
    out = this.finalValidation(out);
    return ensureTrailingNewline(out);
  }

  private finalValidation(output: string): string {
    let validated = output;

    validated = this.ensureCutsBetweenScenes(validated);
    validated = this.applyCriticalReplacements(validated);
    validated = this.normalizeSceneHeadersForValidation(validated);

    if (validated.match(/^-\s+/m) && !validated.match(/^•\s+/m)) {
      validated = validated.replace(/^-\s+/gm, "• ");
    }

    validated = normalizeHindiDigitsToWestern(validated);

    return validated;
  }

  private applyCriticalReplacements(text: string): string {
    let out = text;

    for (const replacement of CRITICAL_OCR_REPLACEMENTS) {
      if (!out.includes(replacement.wrong)) {
        continue;
      }
      out = out.replace(
        replacement.pattern,
        replacement.correct
      );
    }

    out = out.replace(/\bام إم\b/g, "إم إم");
    out = out.replace(/\bامام\b/g, "إم إم");
    return out;
  }

  private ensureCutsBetweenScenes(text: string): string {
    const lines = text.split(/\r?\n/);
    const out: string[] = [];
    let seenScene = 0;

    for (const rawLine of lines) {
      const line = rawLine.trimEnd();
      if (/^\s*مشهد[0-9٠-٩]+/u.test(line)) {
        seenScene += 1;
        if (seenScene > 1) {
          const lastNonEmpty = [...out].reverse().find((entry) => entry.trim());
          if (lastNonEmpty?.trim() !== "قطع") {
            out.push("قطع");
          }
        }
      }
      out.push(line);
    }

    return out.join("\n");
  }

  private normalizeSceneHeadersForValidation(text: string): string {
    return normalizeSceneHeadersRobust(text);
  }

  private async callKimiChat(userPrompt: string): Promise<JsonRecord> {
    const apiKey = ensureKimiApiKey(getEnvOrRaise("MOONSHOT_API_KEY"));
    const url = `${LLMPostProcessor.KIMI_BASE_URL}/chat/completions`;
    let attempt = 0;
    let lastError: unknown;

    while (attempt <= LLMPostProcessor.KIMI_HTTP_MAX_RETRIES) {
      try {
        const timeoutState = createTimeoutState(
          LLMPostProcessor.KIMI_HTTP_TIMEOUT_MS
        );
        let response: Response;
        try {
          response = await fetch(url, {
            method: "POST",
            headers: {
              Authorization: `Bearer ${apiKey}`,
              "Content-Type": "application/json",
              Accept: "application/json",
              "User-Agent": `${APP_NAME}/1.0`,
            },
            body: JSON.stringify({
              model:
                this.config.model ||
                LLMPostProcessor.DEFAULT_KIMI_MODEL ||
                DEFAULT_LLM_MODEL,
              temperature: 0,
              extra_body: {
                thinking: { type: "disabled" },
              },
              messages: [
                { role: "system", content: LLMPostProcessor.SYSTEM_PROMPT },
                { role: "user", content: userPrompt },
              ],
            }),
            signal: timeoutState.signal,
          });
        } finally {
          timeoutState.cleanup();
        }

        const raw = await response.text();
        let data: unknown = {};
        if (raw.trim()) {
          try {
            data = JSON.parse(raw);
          } catch {
            throw new Error("تعذر تحليل استجابة Kimi Chat كـ JSON.");
          }
        }

        if (!response["ok"]) {
          const dataObject =
            data && typeof data === "object" ? (data as JsonRecord) : {};
          const requestId = str(
            field(dataObject, "request_id", "") ||
              field(dataObject, "requestId", "") ||
              field(dataObject, "id", "")
          ).trim();

          if (
            isRetryableHttpStatus(response["status"]) &&
            attempt < LLMPostProcessor.KIMI_HTTP_MAX_RETRIES
          ) {
            attempt += 1;
            const delay = retryDelayMs(attempt);
            log(
              "WARN",
              "Kimi Chat returned %s. retry=%s delayMs=%s",
              response["status"],
              attempt,
              delay
            );
            await sleep(delay);
            continue;
          }

          const requestSuffix = requestId ? ` request_id=${requestId}` : "";
          throw new Error(
            `فشل استدعاء Kimi Chat: ${response["status"]} ${response.statusText}${requestSuffix} - ${raw}`
          );
        }

        if (!data || typeof data !== "object" || Array.isArray(data)) {
          throw new Error("استجابة Kimi Chat ليست JSON object صالح.");
        }

        return data as JsonRecord;
      } catch (error) {
        lastError = error;
        if (
          isRetryableRequestError(error) &&
          attempt < LLMPostProcessor.KIMI_HTTP_MAX_RETRIES
        ) {
          attempt += 1;
          const delay = retryDelayMs(attempt);
          log(
            "WARN",
            "Kimi Chat request failed. retry=%s delayMs=%s error=%s",
            attempt,
            delay,
            String(error)
          );
          await sleep(delay);
          continue;
        }
        throw error;
      }
    }

    throw new Error(`فشل Kimi Chat بعد retries: ${String(lastError)}`);
  }

  private extractOutputText(data: JsonRecord): string {
    const choices = field<unknown[]>(data, "choices", []);
    if (Array.isArray(choices) && choices.length > 0) {
      const first = choices[0];
      const message = field<unknown>(first, "message", null);
      if (message && typeof message === "object") {
        const content = field<unknown>(message, "content", "");
        const extracted = this.extractContentText(content);
        if (extracted.trim()) {
          return extracted.trim();
        }
      }
    }

    const direct = field<string>(data, "output_text", "");
    if (typeof direct === "string" && direct.trim()) {
      return direct;
    }

    return "";
  }

  private extractContentText(content: unknown): string {
    if (typeof content === "string") {
      return content;
    }
    if (!Array.isArray(content)) {
      return "";
    }

    const chunks: string[] = [];
    for (const part of content) {
      if (!part || typeof part !== "object") {
        continue;
      }
      const text = field<string>(part, "text", "");
      if (typeof text === "string" && text.trim()) {
        chunks.push(text);
      }
    }
    return chunks.join("\n").trim();
  }

  private stripMarkdownFences(text: string): string {
    return text
      .trim()
      .replace(/^```(?:markdown)?\s*/iu, "")
      .replace(/\s*```$/u, "")
      .trim();
  }
}

export class QualityChecker {
  static calculateSimilarity(text1: string, text2: string): number {
    const normalize = (s: string) =>
      s
        .replace(/\s+/g, " ")
        .replace(/[\u064B-\u065F\u0670]/g, "")
        .trim();

    const n1 = normalize(text1);
    const n2 = normalize(text2);
    const distance = this.levenshteinDistance(n1, n2);
    const maxLen = Math.max(n1.length, n2.length);

    return maxLen === 0 ? 100 : Math.round((1 - distance / maxLen) * 100);
  }

  private static levenshteinDistance(s1: string, s2: string): number {
    const m = s1.length;
    const n = s2.length;
    const dp: number[][] = Array.from({ length: m + 1 }, () =>
      Array(n + 1).fill(0)
    );

    for (let i = 0; i <= m; i += 1) dp[i][0] = i;
    for (let j = 0; j <= n; j += 1) dp[0][j] = j;

    for (let i = 1; i <= m; i += 1) {
      for (let j = 1; j <= n; j += 1) {
        if (s1[i - 1] === s2[j - 1]) {
          dp[i][j] = dp[i - 1][j - 1];
        } else {
          dp[i][j] = Math.min(
            dp[i - 1][j] + 1,
            dp[i][j - 1] + 1,
            dp[i - 1][j - 1] + 1
          );
        }
      }
    }

    return dp[m][n];
  }
}

/**
 * @description محرك تطبيع Markdown للنصوص العربية المستخرجة من OCR
 */

import type { NormalizationOptions } from "./types.js";
import { ensureTrailingNewline } from "./text-helpers.js";
import { toArabicDigitRegex, toWesternDigitRegex, westernToArabicDigitMap, arabicToWesternDigitMap } from "../../../../../packages/shared/src/utils/digit-normalizer.js";


export class MarkdownNormalizer {
  private readonly noiseOnlyLine = /^[\s\-•▪*·.]+$/u;
  private readonly bulletPrefixPattern =
    /^[\s\u200E\u200F\u061C\uFEFF]*[•·∙⋅●○◦■□▪▫◆◇–—−‒―‣⁃*+]/u;
  private readonly invisibleCharsPattern = /[\u200f\u200e\ufeff\u061c]/gu;
  private readonly htmlTagPattern = /<[^>]+>/gu;
  private readonly domArtifactTokenPattern = /@dom-element:[^\s]+/giu;
  private readonly headingNumberPattern = /^(#{1,6})\s*(\d+)\s*$/u;
  private readonly sceneHeadingPattern = /^(#{1,6})\s*(مشهد)\s*$/u;
  private readonly arabicDiacritics = /[\u064b-\u065f\u0670]/gu;
  private readonly nonWordPattern = /[^\w\u0600-\u06FF\s]/gu;
  private readonly whitespacePattern = /\s+/gu;
  private readonly sentenceEndPattern = /[.!؟?!…»"]\s*$/u;



  private readonly continuationPrefixRe = /^(?:\.{3}|…|،|(?:و|ثم)\s+)/u;

  private readonly sceneNumberExactRe = /^\s*(?:مشهد|scene)\s*[0-9٠-٩]+/iu;
  private readonly sceneTimeRe = /(نهار|ليل|صباح|مساء|فجر)/iu;
  private readonly sceneLocationRe = /(داخلي|خارجي)/iu;
  private readonly transitionRe =
    /^(?:قطع|اختفاء|تحول|انتقال|fade|cut|dissolve|wipe)(?:\s+(?:إلى|to))?[:\s]*$/iu;
  private readonly characterRe =
    /^\s*(?:صوت\s+)?[\u0600-\u06FF][\u0600-\u06FF\s0-9٠-٩]{0,30}:?\s*$/u;
  private readonly parentheticalRe = /^[\(（].*?[\)）]$/u;
  private readonly inlineDialogueGlueRe =
    /^([\u0600-\u06FF]+(?:اً))([\u0600-\u06FF][\u0600-\u06FF\s]{0,20}?)\s*[:：]\s*(.+)$/u;
  private readonly inlineDialogueRe = /^([^:：]{1,60}?)\s*[:：]\s*(.+)$/u;
  private readonly arabicOnlyWithNumbersRe =
    /^[\s\u0600-\u06FF\d٠-٩\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF]+$/u;
  private readonly basmalaBasmRe = /بسم/iu;
  private readonly basmalaAllahRe = /الله/iu;
  private readonly basmalaRahmanRe = /الرحمن/iu;
  private readonly basmalaRahimRe = /الرحيم/iu;

  private readonly headerKeywords = new Set([
    "بسم الله",
    "مشهد",
    "الصالة",
    "نهار",
    "- داخلي",
  ]);
  private readonly sceneMetadata = new Set([
    "قطع",
    "### قطع",
    "## قطع",
    "# قطع",
    "- قطع",
  ]);

  private readonly options: Required<NormalizationOptions>;

  constructor(options: NormalizationOptions = {}) {
    this.options = {
      normalizeYa: options.normalizeYa ?? false,
      normalizeTaMarbuta: options.normalizeTaMarbuta ?? false,
      normalizeHamza: options.normalizeHamza ?? true,
      normalizeDigits: options.normalizeDigits ?? "arabic",
      removeDiacritics: options.removeDiacritics ?? true,
      fixConnectedLetters: options.fixConnectedLetters ?? true,
      fixArabicPunctuation: options.fixArabicPunctuation ?? true,
      scriptSpecificRules: options.scriptSpecificRules ?? true,
    };
  }

  private normalizeArabicCharacters(text: string): string {
    let result = text;
    if (this.options.normalizeYa) {
      result = result.replace(/ى/g, "ي");
    }
    if (this.options.normalizeTaMarbuta) {
      result = result.replace(/ة/g, "ه");
    }
    return result;
  }

  private normalizeHamzaChars(text: string): string {
    if (!this.options.normalizeHamza) return text;
    let result = text;
    result = result.replace(/[إأآ]/g, "ا");
    result = result.replace(/ؤ/g, "و");
    return result;
  }

  private normalizeDigitsChars(text: string): string {
    const mode = this.options.normalizeDigits;
    if (mode === "none") return text;

    if (mode === "arabic") {
      return text.replace(toArabicDigitRegex, (m) => westernToArabicDigitMap[m] || m);
    } else if (mode === "western") {
      return text.replace(toWesternDigitRegex, (m) => arabicToWesternDigitMap[m] || m);
    }

    return text;
  }

  private fixConnectedLettersChars(text: string): string {
    if (!this.options.fixConnectedLetters) return text;
    let result = text;
    result = result.replace(/[\uFEED\uFEEE\uFEE9\uFEEA]/g, "و");
    result = result.replace(/[\uFED1\uFED2\uFED3\uFED4]/g, "ف");
    result = result.replace(/[\uFE91\uFE92\uFE8F\uFE90]/g, "ب");
    result = result.replace(/[\uFE97\uFE98\uFE95\uFE96]/g, "ت");
    return result;
  }

  private fixArabicPunctuationChars(text: string): string {
    if (!this.options.fixArabicPunctuation) return text;
    let result = text;
    result = result.replace(/،(?!\s)/g, "، ");
    result = result.replace(/,(?!\s)/g, ", ");
    result = result.replace(/\s+،/g, "،");
    result = result.replace(/\s+,/g, ",");
    result = result.replace(/\.(?!\s|\.)/g, ". ");
    result = result.replace(/\s*([؟?!])\s*/g, " $1 ");
    result = result.replace(/\s{2,}/g, " ");
    return result;
  }

  normalize(text: string): string {
    const unicode = this.normalizeUnicode(text);
    const fixedLetters = this.fixConnectedLettersChars(unicode);
    const normalizedChars = this.normalizeArabicCharacters(fixedLetters);
    const normalizedHamza = this.normalizeHamzaChars(normalizedChars);
    const normalizedDigits = this.normalizeDigitsChars(normalizedHamza);

    let lines = this.normalizeLines(normalizedDigits);
    lines = lines.map((line) => this.normalizeStructuralLine(line));

    if (this.options.scriptSpecificRules) {
      lines = this.filterSceneMetadata(lines);
    }

    if (this.options.scriptSpecificRules) {
      lines = lines.map((line) => this.normalizeSpeakerLine(line));
    }

    lines = this.normalizeBullets(lines);

    if (this.options.scriptSpecificRules) {
      lines = this.mergeSplitHeadings(lines);
    }

    lines = this.mergeWrappedLines(lines);
    lines = this.collapseBlankLines(lines);

    let finalText = lines.join("\n").trim();
    finalText = this.fixArabicPunctuationChars(finalText);

    return ensureTrailingNewline(finalText);
  }

  normalizeForMatch(text: string): string {
    let out = text.trim().toLowerCase();
    out = out.replace(this.arabicDiacritics, "");
    out = out.replace(this.nonWordPattern, " ");
    out = out.replace(this.whitespacePattern, " ").trim();
    return out;
  }

  private filterSceneMetadata(lines: string[]): string[] {
    const out: string[] = [];
    for (const line of lines) {
      const s = line.trim();
      if (this.sceneMetadata.has(s)) {
        continue;
      }
      if (this.transitionRe.test(s)) {
        continue;
      }
      out.push(line);
    }
    return out;
  }

  private normalizeUnicode(text: string): string {
    let out = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
    out = out.replace(/\ufeff/g, "");
    out = out.replace(/\xa0/g, " ");
    out = out.replace(/[–—−]/g, "-");
    out = out.replace(/…/g, "...");

    const chars: string[] = [];
    for (const ch of out) {
      if (ch === "\n" || ch === "\t") {
        chars.push(ch);
        continue;
      }
      const cp = ch.codePointAt(0) ?? 0;
      const control = (cp >= 0 && cp <= 31) || (cp >= 127 && cp <= 159);
      if (!control) {
        chars.push(ch);
      }
    }

    return chars.join("").replace(this.invisibleCharsPattern, "");
  }

  private normalizeLines(text: string): string[] {
    const out: string[] = [];

    for (const raw of text.split("\n")) {
      let line = raw.replace(/\t/g, " ");
      line = line.replace(this.domArtifactTokenPattern, " ");
      line = line.replace(this.htmlTagPattern, " ");
      line = line.trim();
      line = line.replace(/\\-/g, "-");
      line = line.replace(/\*\*/g, "").replace(/__/g, "");
      line = line.replace(this.invisibleCharsPattern, "");

      if (line && this.noiseOnlyLine.test(line)) {
        continue;
      }

      line = this.normalizeLinePrefix(line);
      line = line.replace(this.whitespacePattern, " ").trim();
      out.push(line);
    }

    return out;
  }

  private normalizeLinePrefix(line: string): string {
    let out = line;
    out = out.replace(/^\*\s+/u, "- ");
    out = out.replace(/^-\s*-+\s*/u, "- ");
    out = out.replace(/^-\s*:\s*/u, "- ");
    out = out.replace(/^-\s*\.\.\s*/u, "- ");
    return out;
  }

  private normalizeStructuralLine(line: string): string {
    const stripped = line.trim();
    if (!stripped) {
      return "";
    }

    const compactArabic = stripped.replace(/[^\u0600-\u06FF\s]/gu, "");
    const hasBasm = this.basmalaBasmRe.test(compactArabic);
    const hasAllah = this.basmalaAllahRe.test(compactArabic);
    const hasRahman = this.basmalaRahmanRe.test(compactArabic);
    const hasRahim = this.basmalaRahimRe.test(compactArabic);

    if (hasBasm && hasAllah && (hasRahman || hasRahim)) {
      return "بسم الله الرحمن الرحيم";
    }

    const glueMatch = stripped.match(this.inlineDialogueGlueRe);
    if (glueMatch) {
      const speaker = `${glueMatch[1]} ${glueMatch[2]}`
        .replace(this.whitespacePattern, " ")
        .trim();
      const dialogue = glueMatch[3].replace(this.whitespacePattern, " ").trim();
      if (speaker && dialogue && this.characterRe.test(`${speaker}:`)) {
        return `${speaker}: ${dialogue}`;
      }
    }

    const inline = stripped.match(this.inlineDialogueRe);
    if (inline) {
      const speaker = inline[1].replace(this.whitespacePattern, " ").trim();
      const dialogue = inline[2].replace(this.whitespacePattern, " ").trim();
      if (
        speaker &&
        dialogue &&
        this.arabicOnlyWithNumbersRe.test(speaker) &&
        this.characterRe.test(`${speaker}:`)
      ) {
        return `${speaker}: ${dialogue}`;
      }
    }

    if (this.transitionRe.test(stripped)) {
      return stripped.replace(/[:：]+\s*$/u, "").trim();
    }

    return stripped;
  }

  private isHeading(line: string): boolean {
    return line.startsWith("#");
  }

  private isBullet(line: string): boolean {
    return line.startsWith("- ") || line.startsWith("* ");
  }

  private isSceneHeaderCandidate(line: string): boolean {
    const normalized = line
      .replace(/-/g, " ")
      .replace(this.whitespacePattern, " ")
      .trim();
    if (!normalized) {
      return false;
    }
    if (this.sceneNumberExactRe.test(normalized)) {
      return true;
    }
    return (
      this.sceneTimeRe.test(normalized) && this.sceneLocationRe.test(normalized)
    );
  }

  private isStructuralBoundary(line: string): boolean {
    const s = line.trim();
    if (!s) {
      return true;
    }
    if (this.isHeading(s) || this.isBullet(s)) {
      return true;
    }
    if (this.transitionRe.test(s) || this.isSceneHeaderCandidate(s)) {
      return true;
    }
    if (this.parentheticalRe.test(s) || this.characterRe.test(s)) {
      return true;
    }
    if (s.startsWith("بسم الله")) {
      return true;
    }
    return false;
  }

  private mergeSplitHeadings(lines: string[]): string[] {
    const merged: string[] = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];
      const scene = line.match(this.sceneHeadingPattern);

      if (scene) {
        let j = i + 1;
        while (j < lines.length && !lines[j]) {
          j += 1;
        }
        if (j < lines.length) {
          const num = lines[j].match(this.headingNumberPattern);
          if (num) {
            merged.push(`${scene[1]} ${scene[2]} ${num[2]}`);
            i = j + 1;
            continue;
          }
        }
      }

      merged.push(line);
      i += 1;
    }

    return merged;
  }

  private normalizeSpeakerLine(line: string): string {
    let out = line;
    out = out.replace(/\s*:\s+/gu, ": ");
    out = out.replace(/\s*\.\s*\./gu, "..");
    return out;
  }

  private normalizeBullets(lines: string[]): string[] {
    const out: string[] = [];
    for (const line of lines) {
      if (!line.startsWith("- ") && !this.bulletPrefixPattern.test(line)) {
        out.push(line);
        continue;
      }
      const stripped = line
        .replace(/^[\-*•·∙⋅●○◦■□▪▫◆◇–—−‒―‣⁃+\s]+/u, "")
        .trim();
      out.push(`- ${stripped}`);
    }
    return out;
  }

  private mergeWrappedLines(lines: string[]): string[] {
    const merged: string[] = [];

    for (const line of lines) {
      if (!line) {
        merged.push(line);
        continue;
      }
      if (merged.length === 0) {
        merged.push(line);
        continue;
      }

      const prev = merged[merged.length - 1];
      if (this.continuationPrefixRe.test(line)) {
        merged[merged.length - 1] = `${prev.trimEnd()} ${line.trimStart()}`;
        continue;
      }

      const isHeaderLine = [...this.headerKeywords].some((kw) =>
        line.includes(kw)
      );
      const isPrevHeader = [...this.headerKeywords].some((kw) =>
        prev.includes(kw)
      );
      const isStructuralLine = this.isStructuralBoundary(line);
      const isPrevStructural = this.isStructuralBoundary(prev);
      const prevEndsSentence = this.sentenceEndPattern.test(prev);

      const shouldMerge =
        line &&
        !this.isHeading(line) &&
        !this.isBullet(line) &&
        !isHeaderLine &&
        !isStructuralLine &&
        prev &&
        !this.isHeading(prev) &&
        !isPrevHeader &&
        !isPrevStructural &&
        !prevEndsSentence;

      if (shouldMerge) {
        merged[merged.length - 1] = `${prev.trimEnd()} ${line.trimStart()}`;
      } else {
        merged.push(line);
      }
    }

    return merged;
  }

  private collapseBlankLines(lines: string[]): string[] {
    const out: string[] = [];
    let prevBlank = false;
    for (const line of lines) {
      const blank = !line;
      if (blank && prevBlank) {
        continue;
      }
      out.push(line);
      prevBlank = blank;
    }
    return out;
  }
}

/**
 * @description خدمة Mistral OCR لاستخراج النصوص من ملفات PDF
 */

import { readFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";
import { setTimeout as sleep } from "node:timers/promises";
import type { JsonRecord, MistralOCRConfig } from "./types.js";
import { log, APP_NAME } from "./ocr-logger.js";
import {
  createTimeoutState,
  ensureMistralApiKey,
  field,
  fileExists,
  getEnvOrRaise,
  isRetryableHttpStatus,
  isRetryableRequestError,
  retryDelayMs,
  str,
} from "./text-helpers.js";

const DEFAULT_MISTRAL_OCR_MODEL = "mistral-ocr-latest";
const MISTRAL_BASE_URL = "https://api.mistral.ai/v1";
const MISTRAL_HTTP_TIMEOUT_MS = Math.max(
  1_000,
  Number.parseInt(process.env['MISTRAL_HTTP_TIMEOUT_MS'] ?? "120000", 10) ||
    120_000
);
const MISTRAL_HTTP_MAX_RETRIES = Math.max(
  0,
  Math.min(
    Number.parseInt(process.env['MISTRAL_HTTP_MAX_RETRIES'] ?? "2", 10) || 2,
    5
  )
);

export class MistralOCRService {
  private readonly config: MistralOCRConfig;
  private annotationSchemaCache?: JsonRecord;
  private lastDocumentAnnotation?: unknown;

  constructor(config: MistralOCRConfig) {
    if (config.model !== DEFAULT_MISTRAL_OCR_MODEL) {
      throw new Error(
        `Mistral OCR model must be ${DEFAULT_MISTRAL_OCR_MODEL}. Received: ${config.model}`
      );
    }
    this.config = config;
  }

  getLastDocumentAnnotation(): unknown {
    return this.lastDocumentAnnotation;
  }

  async processDocumentUrl(
    documentUrl: string,
    documentName?: string
  ): Promise<string> {
    this.lastDocumentAnnotation = undefined;

    const documentPayload: JsonRecord = {
      type: "document_url",
      document_url: documentUrl,
    };
    if (documentName) {
      documentPayload.document_name = documentName;
    }

    const body: JsonRecord = {
      model: this.config.model,
      document: documentPayload,
      ...(await this.buildCommonRequestKwargs()),
    };

    const response = await this.requestJson("POST", "/ocr", body);
    return this.extractMarkdownFromResponse(response);
  }

  async processPdfFile(pdfPath: string): Promise<string> {
    if (!(await fileExists(pdfPath))) {
      throw new Error(`ملف PDF غير موجود: ${pdfPath}`);
    }

    const pdfBytes = await readFile(pdfPath);
    const form = new FormData();
    form.append("purpose", "ocr");
    form.append(
      "file",
      new Blob([pdfBytes], { type: "application/pdf" }),
      path.basename(pdfPath)
    );

    let fileId = "";

    try {
      const upload = await this.requestJson("POST", "/files", form);
      fileId = str(field(upload, "id", "")).trim();
      if (!fileId) {
        throw new Error("لم يتم الحصول على معرف الملف بعد الرفع إلى Mistral.");
      }

      const signedUrl = await this.getSignedUrl(fileId);
      if (!signedUrl) {
        throw new Error("تعذر الحصول على signed URL من Mistral.");
      }

      if (this.config.useBatchOCR) {
        try {
          return await this.processDocumentViaBatch(
            signedUrl,
            path.basename(pdfPath)
          );
        } catch (error) {
          log(
            "WARN",
            "تعذر/فشل Batch OCR (%s). fallback إلى OCR المباشر.",
            String(error)
          );
        }
      }

      return this.processDocumentUrl(signedUrl, path.basename(pdfPath));
    } finally {
      if (fileId) {
        try {
          await this.requestJson(
            "DELETE",
            `/files/${encodeURIComponent(fileId)}`
          );
        } catch (cleanupError) {
          log(
            "WARN",
            "تعذر حذف ملف OCR المؤقت من Mistral (%s): %s",
            fileId,
            String(cleanupError)
          );
        }
      }
    }
  }

  private async processDocumentViaBatch(
    documentUrl: string,
    documentName?: string
  ): Promise<string> {
    this.lastDocumentAnnotation = undefined;

    const payload: JsonRecord = {
      document: {
        type: "document_url",
        document_url: documentUrl,
        ...(documentName ? { document_name: documentName } : {}),
      },
      ...(await this.buildCommonRequestKwargs()),
    };

    const timeoutHours = Math.max(
      1,
      Math.ceil(this.config.batchTimeoutSec / 3600)
    );
    const batch = await this.requestJson("POST", "/batch/jobs", {
      endpoint: "/v1/ocr",
      model: this.config.model,
      requests: [{ custom_id: "ocr-document-0", body: payload }],
      timeout_hours: timeoutHours,
    });

    const jobId = str(field(batch, "id", "")).trim();
    if (!jobId) {
      throw new Error("تعذر إنشاء Batch Job صالح لعملية OCR.");
    }

    log("INFO", "تم إنشاء Batch OCR job: %s", jobId);

    const deadline = Date.now() + this.config.batchTimeoutSec * 1000;
    const pollInterval = Math.max(
      500,
      Math.round(this.config.batchPollIntervalSec * 1000)
    );

    while (true) {
      const job = await this.requestJson(
        "GET",
        `/batch/jobs/${encodeURIComponent(jobId)}?inline=true`
      );
      const status = str(field(job, "status", "")).toUpperCase();
      const completed = Number(field(job, "completed_requests", 0));
      const total = Number(field(job, "total_requests", 0));

      log("INFO", "Batch OCR status=%s (%s/%s)", status, completed, total);

      if (status === "SUCCESS") {
        const markdown = (await this.extractMarkdownFromBatchJob(job)).trim();
        if (markdown) {
          return markdown;
        }
        throw new Error("Batch OCR نجح لكن الناتج كان فارغاً.");
      }

      if (["FAILED", "TIMEOUT_EXCEEDED", "CANCELLED"].includes(status)) {
        const errors = field(job, "errors", []);
        throw new Error(
          `Batch OCR انتهى بالحالة ${status}. errors=${JSON.stringify(errors)}`
        );
      }

      if (Date.now() >= deadline) {
        try {
          await this.requestJson(
            "POST",
            `/batch/jobs/${encodeURIComponent(jobId)}/cancel`
          );
          log(
            "WARN",
            "تم إرسال طلب إلغاء لـ Batch OCR job بعد تجاوز المهلة: %s",
            jobId
          );
        } catch (cancelError) {
          log(
            "WARN",
            "تعذر إلغاء Batch OCR job %s بعد انتهاء المهلة: %s",
            jobId,
            String(cancelError)
          );
        }
        throw new Error(
          `انتهت مهلة Batch OCR (${this.config.batchTimeoutSec}s) قبل الاكتمال.`
        );
      }

      await sleep(pollInterval);
    }
  }

  private async extractMarkdownFromBatchJob(job: unknown): Promise<string> {
    const outputs = field<unknown[]>(job, "outputs", []);
    if (Array.isArray(outputs) && outputs.length > 0) {
      for (const item of outputs) {
        const body = this.extractBatchBody(item);
        if (!body) {
          continue;
        }
        const md = this.extractMarkdownFromResponse(body).trim();
        if (md) {
          return md;
        }
      }
    }

    const outputFileId = str(
      field(job, "output_file", "") || field(job, "output_file_id", "")
    ).trim();
    if (outputFileId) {
      const text = await this.downloadFileText(outputFileId);
      for (const rawLine of text.split(/\r?\n/)) {
        const line = rawLine.trim();
        if (!line) {
          continue;
        }

        let row: unknown;
        try {
          row = JSON.parse(line);
        } catch {
          continue;
        }

        const body = this.extractBatchBody(row);
        if (!body) {
          continue;
        }

        const md = this.extractMarkdownFromResponse(body).trim();
        if (md) {
          return md;
        }
      }
    }

    return "";
  }

  private extractBatchBody(row: unknown): JsonRecord | undefined {
    if (!row || typeof row !== "object") {
      return undefined;
    }

    const responseObj = field(row, "response", null);
    if (responseObj && typeof responseObj === "object") {
      const body = field(responseObj, "body", null);
      if (body && typeof body === "object") {
        return body as JsonRecord;
      }
    }

    const body = field(row, "body", null);
    if (body && typeof body === "object") {
      return body as JsonRecord;
    }

    if (Array.isArray(field(row, "pages", null))) {
      return row as JsonRecord;
    }

    return undefined;
  }

  private async buildCommonRequestKwargs(): Promise<JsonRecord> {
    const kwargs: JsonRecord = {};

    if (this.config.tableFormat) {
      kwargs.table_format = this.config.tableFormat;
    }
    if (this.config.extractHeader) {
      kwargs.extract_header = true;
    }
    if (this.config.extractFooter) {
      kwargs.extract_footer = true;
    }
    if (this.config.includeImageBase64) {
      kwargs.include_image_base64 = true;
    }

    const annotationFormat = await this.buildAnnotationFormat();
    if (annotationFormat) {
      kwargs.document_annotation_format = annotationFormat;
      if (this.config.annotationPrompt) {
        kwargs.document_annotation_prompt = this.config.annotationPrompt;
      }
    }

    return kwargs;
  }

  private async buildAnnotationFormat(): Promise<JsonRecord | undefined> {
    const schema = await this.loadAnnotationSchema();
    if (!schema) {
      return undefined;
    }

    const schemaType = str(field(schema, "type", "")).trim();
    if (["json_schema", "json_object", "text"].includes(schemaType)) {
      return schema;
    }

    return {
      type: "json_schema",
      json_schema: {
        name: "document_annotation",
        schema,
        strict: Boolean(this.config.annotationStrict),
      },
    };
  }

  private async loadAnnotationSchema(): Promise<JsonRecord | undefined> {
    if (!this.config.annotationSchemaPath) {
      return undefined;
    }
    if (this.annotationSchemaCache) {
      return this.annotationSchemaCache;
    }

    if (!(await fileExists(this.config.annotationSchemaPath))) {
      throw new Error(
        `ملف annotation schema غير موجود: ${this.config.annotationSchemaPath}`
      );
    }

    const content = await readFile(this.config.annotationSchemaPath, "utf-8");
    const parsed = JSON.parse(content);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      throw new Error("ملف annotation schema يجب أن يكون كائن JSON.");
    }

    this.annotationSchemaCache = parsed as JsonRecord;
    return this.annotationSchemaCache;
  }

  private extractMarkdownFromResponse(response: unknown): string {
    this.captureAnnotation(response);

    const pages = field<unknown[]>(response, "pages", []);
    if (!Array.isArray(pages) || pages.length === 0) {
      return "";
    }

    const pageMarkdowns: string[] = [];
    for (const page of pages) {
      const markdown = str(field(page, "markdown", "")).trim();
      if (markdown) {
        pageMarkdowns.push(markdown);
      }
    }

    return pageMarkdowns.join("\n\n").trim();
  }

  private captureAnnotation(response: unknown): void {
    const raw = field<string | object | null>(
      response,
      "document_annotation",
      null
    );
    if (raw === null || raw === undefined) {
      return;
    }

    if (typeof raw === "string") {
      const stripped = (raw as string).trim();
      if (!stripped) {
        return;
      }
      try {
        this.lastDocumentAnnotation = JSON.parse(stripped);
      } catch {
        this.lastDocumentAnnotation = stripped;
      }
      return;
    }

    this.lastDocumentAnnotation = raw;
  }

  private async getSignedUrl(fileId: string): Promise<string> {
    const attempts: Array<{
      method: "GET" | "POST";
      endpoint: string;
      body?: unknown;
    }> = [
      {
        method: "GET",
        endpoint: `/files/${encodeURIComponent(fileId)}/url?expiry=24`,
      },
      {
        method: "GET",
        endpoint: `/files/${encodeURIComponent(fileId)}/signed-url`,
      },
      {
        method: "POST",
        endpoint: `/files/${encodeURIComponent(fileId)}/url`,
        body: { expiry: 24 },
      },
      {
        method: "POST",
        endpoint: `/files/${encodeURIComponent(fileId)}/signed-url`,
        body: { expiry: 24 },
      },
    ];

    for (const a of attempts) {
      try {
        const resp = await this.requestJson(a.method, a.endpoint, a.body);
        const top = str(field(resp, "url", "")).trim();
        if (top) {
          return top;
        }

        const dataObj = field(resp, "data", null);
        if (dataObj && typeof dataObj === "object") {
          const nested = str(field(dataObj, "url", "")).trim();
          if (nested) {
            return nested;
          }
        }
      } catch {
        // continue
      }
    }

    throw new Error("تعذر الحصول على signed URL من Mistral بعد عدة محاولات.");
  }

  private async downloadFileText(fileId: string): Promise<string> {
    const endpoints = [
      `/files/${encodeURIComponent(fileId)}/content`,
      `/files/${encodeURIComponent(fileId)}/download`,
      `/files/${encodeURIComponent(fileId)}`,
    ];

    for (const endpoint of endpoints) {
      try {
        const response = await this.requestRaw("GET", endpoint);
        if (!response["ok"]) {
          continue;
        }
        return await response.text();
      } catch {
        // continue
      }
    }

    return "";
  }

  private async requestJson(
    method: "GET" | "POST" | "DELETE",
    endpoint: string,
    body?: unknown
  ): Promise<JsonRecord> {
    let attempt = 0;
    let lastError: unknown;

    while (attempt <= MISTRAL_HTTP_MAX_RETRIES) {
      try {
        const response = await this.requestRaw(method, endpoint, body);
        const raw = await response.text();

        let data: unknown = {};
        if (raw.trim()) {
          try {
            data = JSON.parse(raw);
          } catch {
            data = { raw };
          }
        }

        if (!response["ok"]) {
          const requestId =
            data && typeof data === "object"
              ? str(
                  field(data, "request_id", "") || field(data, "requestId", "")
                ).trim()
              : "";

          if (
            isRetryableHttpStatus(response["status"]) &&
            attempt < MISTRAL_HTTP_MAX_RETRIES
          ) {
            attempt += 1;
            const delay = retryDelayMs(attempt);
            log(
              "WARN",
              "Mistral API returned %s for %s %s. retry=%s delayMs=%s",
              response["status"],
              method,
              endpoint,
              attempt,
              delay
            );
            await sleep(delay);
            continue;
          }

          const requestSuffix = requestId ? ` request_id=${requestId}` : "";
          throw new Error(
            `Mistral API error ${response["status"]} ${response.statusText}${requestSuffix}: ${raw}`
          );
        }

        if (!data || typeof data !== "object" || Array.isArray(data)) {
          return {};
        }

        return data as JsonRecord;
      } catch (error) {
        lastError = error;
        if (
          isRetryableRequestError(error) &&
          attempt < MISTRAL_HTTP_MAX_RETRIES
        ) {
          attempt += 1;
          const delay = retryDelayMs(attempt);
          log(
            "WARN",
            "Mistral request failed for %s %s. retry=%s delayMs=%s error=%s",
            method,
            endpoint,
            attempt,
            delay,
            String(error)
          );
          await sleep(delay);
          continue;
        }
        throw error;
      }
    }

    throw new Error(
      `Mistral request failed after retries: ${String(lastError)}`
    );
  }

  private async requestRaw(
    method: "GET" | "POST" | "DELETE",
    endpoint: string,
    body?: unknown
  ): Promise<Response> {
    const apiKey = ensureMistralApiKey(getEnvOrRaise("MISTRAL_API_KEY"));
    const url = `${MISTRAL_BASE_URL}${endpoint.startsWith("/") ? endpoint : `/${endpoint}`}`;

    const headers: Record<string, string> = {
      Authorization: `Bearer ${apiKey}`,
      Accept: "application/json",
      "User-Agent": `${APP_NAME}/1.0`,
    };

    let bodyInit: string | FormData | undefined;
    if (body !== undefined) {
      if (body instanceof FormData) {
        bodyInit = body;
      } else {
        headers["Content-Type"] = "application/json";
        bodyInit = JSON.stringify(body);
      }
    }

    const timeoutState = createTimeoutState(MISTRAL_HTTP_TIMEOUT_MS);
    try {
      return await fetch(url, {
        method,
        headers,
        body: bodyInit,
        signal: timeoutState.signal,
      });
    } finally {
      timeoutState.cleanup();
    }
  }
}

#!/usr/bin/env node

/**
 * TypeScript conversion of ncio_mistral_all_in_one.py
 * PDF -> Markdown عبر Mistral OCR مع طبقة تطبيع + LLM refinement اختياري.
 *
 * تم تفكيك هذا الملف إلى وحدات منفصلة — هذا الملف يعيد تصدير الكلاسات العامة
 * ويحتفظ بـ PDFToTextConverter + main().
 */

import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";
import {
  StructuralRepair,
  waitForRepairStability,
} from "./structural-repair.js";

// Re-export decomposed modules for backward compatibility
export type {
  LLMConfig,
  MistralOCRConfig,
  PreOCRConfig,
  NormalizationOptions,
  ConfigManager,
} from "./types.js";
export { log } from "./ocr-logger.js";
export {
  ensureTrailingNewline,
  fileExists,
  isTruthy,
  loadEnvFile,
} from "./text-helpers.js";
export { buildConfig } from "./config-builder.js";
export { MarkdownNormalizer } from "./markdown-normalizer.js";
export { OCRPreprocessor } from "./ocr-preprocessor.js";
export { LLMPostProcessor, QualityChecker } from "./llm-post-processor.js";
export { MistralOCRService } from "./mistral-ocr-client.js";

import type { ConfigManager } from "./types.js";
import { log } from "./ocr-logger.js";
import {
  ensureTrailingNewline,
  fileExists,
  isTruthy,
  loadEnvFile,
} from "./text-helpers.js";
import { buildConfig } from "./config-builder.js";
import { MarkdownNormalizer } from "./markdown-normalizer.js";
import { OCRPreprocessor } from "./ocr-preprocessor.js";
import { LLMPostProcessor, QualityChecker } from "./llm-post-processor.js";
import { MistralOCRService } from "./mistral-ocr-client.js";

// ============================================================================
// Converter
// ============================================================================

export class PDFToTextConverter {
  private readonly config: ConfigManager;
  private readonly normalizer: MarkdownNormalizer;
  private readonly mistralService: MistralOCRService;
  private readonly llmPostProcessor?: LLMPostProcessor;
  private readonly structuralRepair: StructuralRepair;
  private readonly ocrPreprocessor: OCRPreprocessor;

  constructor(config: ConfigManager) {
    this.config = config;
    this.normalizer = new MarkdownNormalizer(config.normalizerOptions);
    this.mistralService = new MistralOCRService(config.mistral);
    this.structuralRepair = new StructuralRepair();
    this.ocrPreprocessor = new OCRPreprocessor();
    if (config.llm.enabled) {
      this.llmPostProcessor = new LLMPostProcessor(config.llm);
    }
  }

  async extractMarkdown(): Promise<string> {
    if (!(await fileExists(this.config.inputPath))) {
      throw new Error(
        `الملف غير موجود في المسار المحدد: ${this.config.inputPath}`
      );
    }

    const ext = path.extname(this.config.inputPath).toLowerCase();
    log("INFO", "بدء المعالجة للملف: %s", this.config.inputPath);

    if (ext === ".md" || ext === ".txt") {
      return readFile(this.config.inputPath, "utf-8");
    }

    if (ext !== ".pdf") {
      throw new Error("صيغة الملف غير مدعومة. الصيغ المقبولة: PDF, MD, TXT");
    }

    return this.processPdf();
  }

  private async processPdf(): Promise<string> {
    if (!this.config.mistral.useDocumentInput) {
      throw new Error(
        "في نسخة TypeScript يجب استخدام OCR المباشر للـ PDF (أزل --mistral-disable-document-input). "
      );
    }

    try {
      log("INFO", "محاولة OCR مباشر للـ PDF عبر Mistral (document_url)...");
      const markdown = (
        await this.mistralService.processPdfFile(this.config.inputPath)
      ).trim();
      if (!markdown) {
        throw new Error("OCR المباشر أعاد ناتجاً فارغاً.");
      }
      log("INFO", "نجح OCR المباشر للـ PDF.");
      return ensureTrailingNewline(markdown);
    } catch (error) {
      throw new Error(`فشل OCR المباشر للـ PDF: ${String(error)}`);
    }
  }

  resolveOutputPath(): string {
    if (this.config.outputPath) {
      return this.config.outputPath;
    }

    const ext = path.extname(this.config.inputPath);
    if (ext.toLowerCase() === ".pdf") {
      return this.config.inputPath.slice(0, -ext.length) + ".md";
    }

    const dir = path.dirname(this.config.inputPath);
    const stem = path.basename(this.config.inputPath, ext);
    return path.join(dir, `${stem}.normalized.md`);
  }

  resolveAnnotationOutputPath(outputPath: string): string {
    if (this.config.mistral.annotationOutputPath) {
      return this.config.mistral.annotationOutputPath;
    }

    const ext = path.extname(outputPath);
    const dir = path.dirname(outputPath);
    const stem = path.basename(outputPath, ext);
    return path.join(dir, `${stem}.annotation.json`);
  }

  getDocumentAnnotation(): unknown {
    return this.mistralService.getLastDocumentAnnotation();
  }

  async getNonOverwritingPath(filePath: string): Promise<string> {
    if (!(await fileExists(filePath))) {
      return filePath;
    }

    const ext = path.extname(filePath);
    const dir = path.dirname(filePath);
    const stem = path.basename(filePath, ext);

    let c = 1;
    while (true) {
      const candidate = path.join(dir, `${stem}_${c}${ext}`);
      if (!(await fileExists(candidate))) {
        log(
          "INFO",
          "الملف %s موجود مسبقاً، سيتم الحفظ باسم: %s",
          filePath,
          candidate
        );
        return candidate;
      }
      c += 1;
    }
  }

  private async applyStructuralRepair(
    text: string,
    referenceText = ""
  ): Promise<string> {
    return waitForRepairStability(this.structuralRepair, text, referenceText);
  }

  calculateMatchScore(referenceText: string, candidateText: string): number {
    const refLines = referenceText.split(/\r?\n/);
    const candLines = candidateText.split(/\r?\n/);

    const maxLen = Math.max(refLines.length, candLines.length);
    if (maxLen === 0) {
      return 100;
    }

    let eq = 0;
    for (let i = 0; i < maxLen; i += 1) {
      if ((refLines[i] ?? "") === (candLines[i] ?? "")) {
        eq += 1;
      }
    }

    return Math.round((eq / maxLen) * 1000000) / 10000;
  }

  generateDiffPreview(
    referenceText: string,
    candidateText: string,
    maxLines: number
  ): string {
    const refLines = referenceText.split(/\r?\n/);
    const candLines = candidateText.split(/\r?\n/);
    const max = Math.max(refLines.length, candLines.length);

    const out: string[] = [];
    for (let i = 0; i < max; i += 1) {
      const r = refLines[i] ?? "";
      const c = candLines[i] ?? "";
      if (r === c) {
        continue;
      }
      out.push(`@@ line ${i + 1} @@`);
      out.push(`- ${r}`);
      out.push(`+ ${c}`);
      if (out.length >= maxLines) {
        break;
      }
    }

    return out.length > 0 ? out.slice(0, maxLines).join("\n") : "N/A";
  }

  async runLlmRefinement(initialMarkdown: string): Promise<string> {
    if (!this.llmPostProcessor) {
      return initialMarkdown;
    }

    let referenceText = await this.llmPostProcessor.getReferenceText();
    if (referenceText && this.config.normalizeOutput) {
      referenceText = this.normalizer.normalize(referenceText);
    }

    const repairedInitial = await this.applyStructuralRepair(
      initialMarkdown,
      referenceText
    );

    if (!referenceText) {
      log("INFO", "لا يوجد مرجع نصي؛ سيتم تنفيذ تمرير LLM واحد فقط.");
      let result = await this.llmPostProcessor.postprocess(repairedInitial);
      if (this.config.normalizeOutput) {
        result = this.normalizer.normalize(result);
      }
      return this.applyStructuralRepair(result);
    }

    let best = repairedInitial;
    let bestScore = this.calculateMatchScore(referenceText, best);
    let bestSemanticScore = QualityChecker.calculateSimilarity(
      referenceText,
      best
    );
    log("INFO", "نسبة التطابق قبل LLM: %.2f%%", bestScore);
    log("INFO", "نسبة التطابق الدلالي قبل LLM: %s%%", bestSemanticScore);

    let current = repairedInitial;
    const rounds = this.config.llm.iterative
      ? this.config.llm.maxIterations
      : 1;
    let noImprovementRounds = 0;
    const minImprovementDelta = 0.1;

    for (let i = 1; i <= rounds; i += 1) {
      if (bestScore >= this.config.llm.targetMatch) {
        log(
          "INFO",
          "تم الوصول للنسبة المستهدفة %.2f%% قبل الجولة %s.",
          this.config.llm.targetMatch,
          i
        );
        break;
      }

      const preview = this.generateDiffPreview(
        referenceText,
        current,
        this.config.llm.diffPreviewLines
      );
      const feedback = [
        `Current best match: ${bestScore.toFixed(2)}%. Target: ${this.config.llm.targetMatch.toFixed(2)}%.`,
        "Focus only on lines that differ from reference and avoid changing already matching lines.",
        `Diff preview:\n${preview}`,
      ].join("\n");

      let candidate = await this.llmPostProcessor.postprocess(
        current,
        referenceText,
        feedback
      );
      if (this.config.normalizeOutput) {
        candidate = this.normalizer.normalize(candidate);
      }
      candidate = await this.applyStructuralRepair(candidate, referenceText);

      const score = this.calculateMatchScore(referenceText, candidate);
      const semanticScore = QualityChecker.calculateSimilarity(
        referenceText,
        candidate
      );
      log("INFO", "جولة LLM %s/%s -> نسبة التطابق: %.2f%%", i, rounds, score);
      log(
        "INFO",
        "جولة LLM %s/%s -> نسبة التطابق الدلالي: %s%%",
        i,
        rounds,
        semanticScore
      );

      current = candidate;
      const improved =
        score > bestScore + minImprovementDelta ||
        (Math.abs(score - bestScore) <= minImprovementDelta &&
          semanticScore > bestSemanticScore);

      if (
        score > bestScore ||
        (score === bestScore && semanticScore >= bestSemanticScore)
      ) {
        bestScore = score;
        bestSemanticScore = semanticScore;
        best = candidate;
      }

      if (improved) {
        noImprovementRounds = 0;
      } else {
        noImprovementRounds += 1;
      }

      if (noImprovementRounds >= 2) {
        log(
          "INFO",
          "لا يوجد تحسن ملموس لعدد %s جولات متتالية، سيتم إيقاف التحسين التكراري.",
          noImprovementRounds
        );
        break;
      }
    }

    log("INFO", "أفضل نسبة تطابق بعد التحسين التكراري: %.2f%%", bestScore);
    log(
      "INFO",
      "أفضل نسبة تطابق دلالي بعد التحسين التكراري: %s%%",
      bestSemanticScore
    );
    return best;
  }

  async convert(): Promise<{ rawMarkdown: string; finalMarkdown: string }> {
    const rawMarkdown = await this.extractMarkdown();
    let finalMarkdown = rawMarkdown;

    if (this.config.normalizeOutput) {
      finalMarkdown = this.normalizer.normalize(rawMarkdown);
      log(
        "INFO",
        "اكتمل التطبيع: حجم النص قبل=%s حرف، بعد=%s حرف.",
        rawMarkdown.length,
        finalMarkdown.length
      );
    } else {
      log("INFO", "تم الاستخراج بدون تطبيع بناءً على الإعدادات.");
    }

    if (path.extname(this.config.inputPath).toLowerCase() === ".pdf") {
      const preprocessed = this.ocrPreprocessor.preprocess(finalMarkdown);
      if (preprocessed.detectedIssues.length > 0) {
        log(
          "INFO",
          "تم تطبيق تصحيحات OCR المسبقة: %s",
          preprocessed.detectedIssues.join(" | ")
        );
      }
      finalMarkdown = preprocessed.text;
    }

    finalMarkdown = await this.applyStructuralRepair(finalMarkdown);
    log("INFO", "اكتمل الإصلاح البنيوي الأولي للنص المستخرج.");

    if (this.config.llm.enabled && this.llmPostProcessor) {
      log("INFO", "بدء تمرير طبقة LLM لتحسين التطابق...");
      try {
        finalMarkdown = await this.runLlmRefinement(finalMarkdown);
        log("INFO", "اكتملت طبقة LLM بنجاح.");
      } catch (error) {
        if (this.config.llm.strict) {
          throw error;
        }
        log(
          "WARN",
          "فشلت طبقة LLM وسيتم المتابعة بالنص الحالي: %s",
          String(error)
        );
      }
    }

    return { rawMarkdown, finalMarkdown };
  }
}

// ============================================================================
// Main
// ============================================================================

async function main(): Promise<void> {
  if (isTruthy(process.env['FORCE_CPU_ONLY'] ?? "")) {
    process.env['CUDA_VISIBLE_DEVICES'] = "-1";
  }

  const envPath = path.join(process.cwd(), ".env");
  await loadEnvFile(envPath);

  const config = buildConfig(process.argv.slice(2));
  const converter = new PDFToTextConverter(config);

  try {
    const { rawMarkdown, finalMarkdown } = await converter.convert();
    log(
      "INFO",
      "العملية مكتملة. تم استخراج نص يحتوي على %s حرف.",
      finalMarkdown.length
    );

    const outputPath = await converter.getNonOverwritingPath(
      converter.resolveOutputPath()
    );

    if (config.saveRawMarkdown && rawMarkdown !== finalMarkdown) {
      const ext = path.extname(outputPath);
      const stem = path.basename(outputPath, ext);
      const dir = path.dirname(outputPath);
      const rawPath = await converter.getNonOverwritingPath(
        path.join(dir, `${stem}.raw.md`)
      );
      await writeFile(rawPath, rawMarkdown, "utf-8");
      log("INFO", "تم حفظ النسخة الخام في: %s", rawPath);
    }

    await writeFile(outputPath, finalMarkdown, "utf-8");
    log("INFO", "تم حفظ النص المستخرج في: %s", outputPath);

    const annotation = converter.getDocumentAnnotation();
    if (annotation !== undefined && annotation !== null) {
      const annotationPath = await converter.getNonOverwritingPath(
        converter.resolveAnnotationOutputPath(outputPath)
      );
      await writeFile(
        annotationPath,
        `${JSON.stringify(annotation, null, 2)}\n`,
        "utf-8"
      );
      log("INFO", "تم حفظ document annotation في: %s", annotationPath);
    }

    log("INFO", "تمت المعالجة بنجاح.");
  } catch (error) {
    log(
      "CRITICAL",
      "فشل البرنامج في إكمال المهمة المطلوبة بسبب الخطأ: %s",
      String(error)
    );
    process.exitCode = 1;
  }
}

// Only run main() if this file is executed directly (not imported)
if (import.meta.url === `file://${process.argv[1]}`) {
  void main();
}

/**
 * @description نظام التسجيل لمحول OCR
 */

import util from "node:util";

const APP_NAME = "MistralOCRPDFConverter";

export function log(
  level: "INFO" | "WARN" | "ERROR" | "CRITICAL",
  message: string,
  ...args: unknown[]
): void {
  const ts = new Date().toISOString();
  const line = `${ts} - ${APP_NAME} - ${level} - ${util.format(message, ...args)}`;
  if (level === "ERROR" || level === "CRITICAL") {
    console.error(line);
  } else {
    console.log(line);
  }
}

export { APP_NAME };

/**
 * @description معالج مسبق لتصحيح أخطاء OCR الشائعة في النصوص العربية
 */

import type { PreprocessResult } from "./types.js";
import {
  CRITICAL_OCR_REPLACEMENTS,
  escapeRegExp,
  normalizeHindiDigitsToWestern,
  normalizeSceneHeadersRobust,
  SCENE_HEADER_LINE_PATTERN,
} from "./text-helpers.js";

export class OCRPreprocessor {
  private static readonly NAME_PATTERNS = [
    { reversed: "يربص", correct: "صبري" },
    { reversed: "فصنم", correct: "منصف" },
    { reversed: "دومحم", correct: "محمود" },
    { reversed: "دمحا", correct: "أحمد" },
    { reversed: "دنه", correct: "هند" },
    { reversed: "يسوب", correct: "بوسي" },
    { reversed: "رمرم", correct: "مرمر" },
    { reversed: "مإ مإ", correct: "إم إم" },
    { reversed: "ىطسلاا", correct: "الاسطى" },
    { reversed: "يزوف", correct: "فوزي" },
    { reversed: "سونرع", correct: "عرنوس" },
    { reversed: "دعسم", correct: "مسعد" },
  ].map((r) => ({ ...r, pattern: new RegExp(escapeRegExp(r.reversed), "g") }));

  preprocess(text: string): PreprocessResult {
    const issues: string[] = [];
    let processed = this.fixCatastrophicStart(text, issues);

    for (const pattern of OCRPreprocessor.NAME_PATTERNS) {
      if (processed.includes(pattern.reversed)) {
        issues.push(`انعكاس: ${pattern.reversed} ← ${pattern.correct}`);
        processed = processed.replace(
          pattern.pattern,
          pattern.correct
        );
      }
    }

    processed = this.applyCriticalCorrections(processed, issues);

    const digitsNormalized = normalizeHindiDigitsToWestern(processed);
    if (digitsNormalized !== processed) {
      issues.push("تحويل الأرقام الهندية إلى عربية");
      processed = digitsNormalized;
    }

    processed = this.normalizeSceneHeaders(processed, issues);

    if (processed.match(/^-\s+/m)) {
      issues.push("توحيد علامات الكلام: - ← •");
      processed = processed.replace(/^-\s+/gm, "• ");
    }

    if (processed.includes("ام ام")) {
      issues.push("إضافة همزة: ام ام ← إم إم");
      processed = processed.replace(/ام ام/g, "إم إم");
    }

    const scenePattern = /مشهد[١٢٣٤٥٦٧٨٩٠1-9]/g;
    const scenes = processed.match(scenePattern);
    if (scenes && scenes.length > 1) {
      issues.push(`إضافة كلمة "قطع" قبل ${scenes.length - 1} مشهد`);
    }

    return { text: processed, detectedIssues: issues };
  }

  private fixCatastrophicStart(text: string, issues: string[]): string {
    const lines = text.split(/\r?\n/);
    const firstIndex = lines.findIndex((line) => line.trim().length > 0);
    if (firstIndex < 0) {
      return text;
    }

    let sceneLineIndex = firstIndex;
    let sceneLine = lines[sceneLineIndex].trim();

    if (/^[٠١٢٣٤٥٦٧٨٩0-9]+$/u.test(sceneLine)) {
      const nextNonEmptyIndex = lines.findIndex(
        (line, index) => index > sceneLineIndex && line.trim().length > 0
      );
      if (nextNonEmptyIndex >= 0) {
        sceneLineIndex = nextNonEmptyIndex;
        sceneLine = lines[sceneLineIndex].trim();
      }
    }

    if (/^(?:\s*#+\s*)?مشهد\s*[٠١٢٣٤٥٦٧٨٩0-9]+\b/u.test(sceneLine)) {
      return text;
    }

    const sceneMatch = sceneLine.match(SCENE_HEADER_LINE_PATTERN);
    if (!sceneMatch) {
      return text;
    }

    const sceneNumber = normalizeHindiDigitsToWestern(
      sceneMatch[1] ?? ""
    ).trim();
    if (!sceneNumber) {
      return text;
    }

    if (
      sceneLineIndex !== firstIndex &&
      /^[٠١٢٣٤٥٦٧٨٩0-9]+$/u.test(lines[firstIndex].trim())
    ) {
      lines.splice(firstIndex, 1);
      sceneLineIndex -= 1;
    }

    const tail = (sceneMatch[2] ?? "").trim();
    if (tail) {
      lines.splice(sceneLineIndex, 1, `مشهد${sceneNumber}`, tail);
    } else {
      lines[sceneLineIndex] = `مشهد${sceneNumber}`;
    }

    if (!text.includes("بسم الله")) {
      lines.unshift("بسم الله الرحمن الرحيم");
      issues.push("إصلاح بداية كارثية: إضافة البسملة وتطبيع أول مشهد");
    } else {
      issues.push("إصلاح بداية كارثية: تطبيع أول مشهد");
    }

    return lines.join("\n");
  }

  private applyCriticalCorrections(text: string, issues: string[]): string {
    let out = text;
    for (const replacement of CRITICAL_OCR_REPLACEMENTS) {
      if (!out.includes(replacement.wrong)) {
        continue;
      }
      out = out.replace(
        replacement.pattern,
        replacement.correct
      );
      issues.push(`تصحيح حرج: ${replacement.label}`);
    }
    return out;
  }

  private normalizeSceneHeaders(text: string, issues: string[]): string {
    return normalizeSceneHeadersRobust(text, (sceneHeader) => {
      issues.push(`توحيد ترويسة مشهد: ${sceneHeader}`);
    });
  }
}

#!/usr/bin/env npx tsx
/**
 * open-pdf-agent.ts
 *
 * وكيل تنفيذ حتمي لمسار فتح PDF داخل التطبيق:
 * 1) يمر على ملفات البايبلاين المطلوبة (footprint verification)
 * 2) يصنّف PDF عبر الأدوات المحلية + أدوات المهارة
 * 3) ينفذ OCR عبر skill scripts
 * 4) يكتب النص الخام TXT
 * 5) يمرر النص عبر MCP tool (convert_document_to_markdown) للتفعيل الحقيقي لمسار MCP
 *
 * المخرجات دائماً JSON على stdout.
 */

import { readFile, stat } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";
import { createMCPClient } from "@ai-sdk/mcp";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

import { buildAgentConfig } from "./config";
import { classifyPdfTool } from "./tools";
import { skillOcrMistral, skillWriteOutput } from "./skill-tools";
import type { ClassificationResult } from "./types";

type JsonRecord = Record<string, unknown>;

interface OpenPdfAgentArgs {
  input: string;
  outputJson: string;
  outputTxt: string;
  outputMcpMd: string;
  pages: string;
}

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const toStringArray = (value: unknown): string[] =>
  Array.isArray(value)
    ? value.filter((entry): entry is string => typeof entry === "string")
    : [];

const toJsonRecord = (value: unknown): JsonRecord =>
  value && typeof value === "object" ? (value as JsonRecord) : {};

const writeStderr = (message: string): void => {
  process.stderr.write(`${message}\n`);
};

const isFalseLike = (value: string): boolean =>
  /^(0|false|no|off)$/iu.test(value.trim());

const isEnabledByDefault = (raw: string | undefined): boolean => {
  if (typeof raw !== "string") return true;
  return !isFalseLike(raw);
};

const parseArgs = (argv: string[]): OpenPdfAgentArgs => {
  const args = new Map<string, string>();

  for (let index = 0; index < argv.length; index += 1) {
    const key = argv[index];
    if (!key || !key.startsWith("--")) continue;

    const value = argv[index + 1];
    if (!value || value.startsWith("--")) continue;

    args.set(key, value);
    index += 1;
  }

  const readRequired = (name: string): string => {
    const value = args.get(name);
    if (!value || !value.trim()) {
      throw new Error(`معامل مفقود: ${name}`);
    }
    return value.trim();
  };

  return {
    input: readRequired("--input"),
    outputJson: readRequired("--output-json"),
    outputTxt: readRequired("--output-txt"),
    outputMcpMd: readRequired("--output-mcp-md"),
    pages: (args.get("--pages") ?? "all").trim(),
  };
};

const parseToolJson = (raw: unknown, toolName: string): JsonRecord => {
  if (typeof raw === "string") {
    try {
      return toJsonRecord(JSON.parse(raw));
    } catch (error) {
      throw new Error(
        `تعذر تحليل JSON من ${toolName}: ${error instanceof Error ? error.message : String(error)}`,
        { cause: error }
      );
    }
  }
  return toJsonRecord(raw);
};

const runTool = async (
  toolDef: unknown,
  payload: Record<string, unknown>,
  toolName: string
): Promise<JsonRecord> => {
  const maybeExecute = (toolDef as { execute?: unknown }).execute;
  if (typeof maybeExecute !== "function") {
    throw new Error(`الأداة ${toolName} لا تحتوي execute()`);
  }
  const response = await (
    maybeExecute as (input: Record<string, unknown>) => Promise<unknown>
  )(payload);
  const parsed = parseToolJson(response, toolName);

  if (parsed["success"] === false) {
    const reason =
      typeof parsed["error"] === "string"
        ? parsed["error"]
        : `فشلت الأداة ${toolName}`;
    throw new Error(reason);
  }
  if (typeof parsed["error"] === "string" && parsed["error"].trim()) {
    throw new Error(parsed["error"].trim());
  }

  return parsed;
};

const toClassification = (value: JsonRecord): ClassificationResult | null => {
  const requiredKeys: Array<keyof ClassificationResult> = [
    "type",
    "pages",
    "size_mb",
    "filename",
    "has_arabic",
    "recommended_engine",
    "notes",
  ];

  const hasAllKeys = requiredKeys.every((key) => key in value);
  if (!hasAllKeys) return null;

  return {
    type: value["type"] as ClassificationResult["type"],
    pages: Number(value["pages"] ?? 0),
    size_mb: Number(value["size_mb"] ?? 0),
    filename: String(value["filename"] ?? ""),
    has_arabic: Boolean(value["has_arabic"]),
    recommended_engine: value[
      "recommended_engine"
    ] as ClassificationResult["recommended_engine"],
    notes: toStringArray(value["notes"]),
  };
};

const verifyPathType = async (
  absolutePath: string,
  expected: "file" | "dir"
): Promise<void> => {
  const entry = await stat(absolutePath);
  if (expected === "file" && !entry.isFile()) {
    throw new Error(`المسار ليس ملفاً: ${absolutePath}`);
  }
  if (expected === "dir" && !entry.isDirectory()) {
    throw new Error(`المسار ليس مجلداً: ${absolutePath}`);
  }
};

const verifyPipelineFootprint = async (
  agentRoot: string,
  mcpServerPath: string
): Promise<{
  checkedDirectories: string[];
  checkedFiles: string[];
}> => {
  const mcpRoot = dirname(mcpServerPath);
  const requiredDirectories = [
    agentRoot,
    resolve(agentRoot, "skill-scripts"),
    mcpRoot,
    resolve(mcpRoot, "node_modules"),
  ];

  const requiredFiles = [
    resolve(agentRoot, "agent.ts"),
    resolve(agentRoot, "batch.ts"),
    resolve(agentRoot, "config.ts"),
    resolve(agentRoot, "skill-tools.ts"),
    resolve(agentRoot, "tools.ts"),
    resolve(agentRoot, "types.ts"),
    resolve(agentRoot, "skill-scripts", "classify-pdf.ts"),
    resolve(agentRoot, "skill-scripts", "enhance-image.ts"),
    resolve(agentRoot, "skill-scripts", "ocr-mistral.ts"),
    resolve(agentRoot, "skill-scripts", "write-output.ts"),
    resolve(agentRoot, "skill-scripts", "extraction-rules.md"),
    resolve(agentRoot, "skill-scripts", "troubleshooting.md"),
    resolve(mcpRoot, "annotation_schema.json"),
    resolve(mcpRoot, "index.ts"),
    resolve(mcpRoot, "ncio_mistral_all_in_one.ts"),
    resolve(mcpRoot, "package.json"),
    resolve(mcpRoot, "pnpm-lock.yaml"),
    resolve(mcpRoot, "tsconfig.json"),
  ];

  for (const dirPath of requiredDirectories) {
    await verifyPathType(dirPath, "dir");
  }

  // قراءة سريعة لضمان "المرور" الفعلي على الملفات
  for (const filePath of requiredFiles) {
    await verifyPathType(filePath, "file");
    await readFile(filePath, "utf-8");
  }

  return {
    checkedDirectories: requiredDirectories,
    checkedFiles: requiredFiles,
  };
};

const runMcpStage = async (
  mcpServerPath: string,
  rawTxtPath: string,
  normalizedMdOutputPath: string
): Promise<{
  summary: string | null;
  llmEnabled: boolean;
  llmModel: string | null;
  llmReferencePath: string | null;
}> => {
  const llmReferencePathRaw =
    process.env["OPEN_PDF_AGENT_LLM_REFERENCE_PATH"] ?? "";
  const llmReferencePath = llmReferencePathRaw.trim() || null;
  const llmModelRaw = process.env["OPEN_PDF_AGENT_LLM_MODEL"] ?? "";
  const llmModel = llmModelRaw.trim() || "kimi-k2.5";
  const forceLlmReviewRaw =
    process.env["OPEN_PDF_AGENT_ENABLE_MCP_LLM_REVIEW"] ?? "";
  const forceLlmReview = /^(1|true|yes|on)$/iu.test(forceLlmReviewRaw.trim());
  const llmEnabled = Boolean(llmReferencePath) || forceLlmReview;

  const transport = new StdioClientTransport({
    command: process.execPath,
    args: ["--import", "tsx", mcpServerPath],
    env: {
      ...process.env,
      MISTRAL_API_KEY: process.env["MISTRAL_API_KEY"] ?? "",
      MOONSHOT_API_KEY: process.env["MOONSHOT_API_KEY"] ?? "",
      OPENAI_API_KEY: process.env["OPENAI_API_KEY"] ?? "",
    },
  });

  const client = await createMCPClient({ transport });
  try {
    const tools = (await client.tools()) as Record<string, unknown>;
    const convertTool = tools["convert_document_to_markdown"];
    const execute = (
      convertTool as
        | {
            execute?: unknown;
          }
        | undefined
    )?.execute;

    if (!convertTool || typeof execute !== "function") {
      throw new Error(
        "أداة convert_document_to_markdown غير متاحة من خادم MCP."
      );
    }

    const response = await (
      execute as (input: Record<string, unknown>) => Promise<unknown>
    )({
      inputPath: rawTxtPath,
      outputPath: normalizedMdOutputPath,
      normalizeOutput: true,
      saveRawMarkdown: false,
      useLlm: llmEnabled,
      llmModel,
      ...(llmReferencePath ? { llmReferencePath } : {}),
      llmStrict: false,
      useBatchOcr: false,
    });

    const payload = toJsonRecord(response);
    const content = Array.isArray(payload["content"])
      ? (payload["content"] as Array<Record<string, unknown>>)
      : [];
    const firstText = content.find(
      (item) => typeof item?.["text"] === "string"
    );

    return {
      summary:
        firstText && typeof firstText["text"] === "string"
          ? firstText["text"]
          : null,
      llmEnabled,
      llmModel: llmEnabled ? llmModel : null,
      llmReferencePath: llmEnabled ? llmReferencePath : null,
    };
  } finally {
    await client.close();
  }
};

const main = async (): Promise<void> => {
  const args = parseArgs(process.argv.slice(2));
  const inputPath = resolve(args.input);
  const outputJsonPath = resolve(args.outputJson);
  const outputTxtPath = resolve(args.outputTxt);
  const outputMcpMdPath = resolve(args.outputMcpMd);

  const agentConfig = buildAgentConfig();
  const mcpServerPath = resolve(agentConfig.mcpServerPath);
  const agentRoot = resolve(__dirname);

  const attempts = ["pipeline-open-agent"];
  const warnings: string[] = [];

  const verifyFootprintEnabled = isEnabledByDefault(
    process.env["OPEN_PDF_AGENT_VERIFY_FOOTPRINT"] ?? "false"
  );
  const mcpStageEnabled = isEnabledByDefault(
    process.env["OPEN_PDF_AGENT_ENABLE_MCP_STAGE"] ?? "true"
  );

  let footprint: {
    checkedDirectories: string[];
    checkedFiles: string[];
  } | null = null;
  if (verifyFootprintEnabled) {
    footprint = await verifyPipelineFootprint(agentRoot, mcpServerPath);
    attempts.push("pipeline-footprint-verified");
  } else {
    attempts.push("pipeline-footprint-skipped");
  }

  const localClassificationRaw = await runTool(
    classifyPdfTool,
    { pdfPath: inputPath },
    "classify_pdf"
  );
  attempts.push("classify-local");

  // Duplicate skill classification removed — single classify is sufficient
  const classification = toClassification(localClassificationRaw);

  if (!classification) {
    throw new Error("تعذر بناء نتيجة تصنيف PDF من أدوات الوكيل.");
  }
  if (classification.type === "protected") {
    throw new Error("الملف محمي بكلمة مرور — يتطلب فك التشفير أولاً.");
  }
  warnings.push(...toStringArray(classification.notes));

  const ocrResult = await runTool(
    skillOcrMistral,
    {
      input: inputPath,
      output: outputJsonPath,
      pages: args.pages,
    },
    "skill_ocr_mistral"
  );
  attempts.push("ocr-skill");
  warnings.push(...toStringArray(ocrResult["warnings"]));
  warnings.push(...toStringArray(ocrResult["notes"]));

  const writeResult = await runTool(
    skillWriteOutput,
    {
      input: outputJsonPath,
      format: "txt-raw",
      output: outputTxtPath,
    },
    "skill_write_output"
  );
  attempts.push("write-output-skill");
  warnings.push(...toStringArray(writeResult["warnings"]));
  warnings.push(...toStringArray(writeResult["notes"]));

  const rawText = await readFile(outputTxtPath, "utf-8");
  if (!rawText.trim()) {
    throw new Error("النص الخام الناتج من OCR فارغ.");
  }

  let mcpStage: {
    summary: string | null;
    llmEnabled: boolean;
    llmModel: string | null;
    llmReferencePath: string | null;
  } = {
    summary: null,
    llmEnabled: false,
    llmModel: null,
    llmReferencePath: null,
  };
  let markdownText = rawText;

  if (mcpStageEnabled) {
    mcpStage = await runMcpStage(mcpServerPath, outputTxtPath, outputMcpMdPath);
    attempts.push("mcp-convert_document_to_markdown");
    try {
      const markdownFromMcp = await readFile(outputMcpMdPath, "utf-8");
      if (markdownFromMcp.trim()) {
        markdownText = markdownFromMcp;
      }
    } catch {
      warnings.push(
        "MCP stage completed but markdown output file was not found."
      );
    }
  } else {
    attempts.push("mcp-stage-skipped");
  }

  const payload = {
    success: true,
    text: rawText,
    textRaw: rawText,
    textMarkdown: markdownText,
    classification,
    warnings,
    attempts,
    meta: {
      textStage: "pre-format",
      textFormat: "txt-raw",
      footprint,
      mcpStageEnabled,
      mcp: {
        serverPath: mcpServerPath,
        outputPath: outputMcpMdPath,
        summary: mcpStage.summary,
        llmEnabled: mcpStage.llmEnabled,
        llmModel: mcpStage.llmModel,
        llmReferencePath: mcpStage.llmReferencePath,
      },
    },
  };

  process.stdout.write(JSON.stringify(payload));
};

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.message : String(error);
  writeStderr(`open-pdf-agent failed: ${message}`);
  process.stdout.write(
    JSON.stringify({
      success: false,
      error: message,
    })
  );
  process.exitCode = 1;
});

#!/usr/bin/env npx tsx
/**
 * classify-pdf.ts — تصنيف ملف PDF وتحديد المسار الأنسب لمعالجته
 *
 * الاستخدام:
 *   npx tsx classify-pdf.ts "/path/to/input.pdf"
 *
 * المخرج: JSON على stdout يتضمن نوع الملف والتوصية
 */

import { execFileSync } from "node:child_process";
import { statSync } from "node:fs";
import { basename } from "node:path";

// ─── أنواع البيانات ───────────────────────────────────────────

interface ClassificationResult {
  /** نوع الملف: نصي / ممسوح / مختلط / محمي / غير صالح */
  type: "text-based" | "scanned" | "mixed" | "protected" | "invalid";
  /** عدد الصفحات */
  pages: number;
  /** حجم الملف بالميجابايت */
  size_mb: number;
  /** اسم الملف */
  filename: string;
  /** هل يحتوي نصاً عربياً */
  has_arabic: boolean;
  /** المحرك الموصى به */
  recommended_engine: "pdfminer" | "mistral" | "vision";
  /** ملاحظات إضافية */
  notes: string[];
}

// ─── دوال مساعدة ──────────────────────────────────────────────

/** استخراج معلومات PDF عبر pdfinfo */
function getPdfInfo(pdfPath: string): Record<string, string> {
  try {
    const output = execFileSync("pdfinfo", [pdfPath], {
      encoding: "utf-8",
      timeout: 10_000,
      windowsHide: true,
      stdio: ["ignore", "pipe", "pipe"],
    });
    const info: Record<string, string> = {};
    for (const line of output.split("\n")) {
      const colonIdx = line.indexOf(":");
      if (colonIdx > 0) {
        const key = line.slice(0, colonIdx).trim();
        const value = line.slice(colonIdx + 1).trim();
        info[key] = value;
      }
    }
    return info;
  } catch {
    return {};
  }
}

/** محاولة استخراج نص خام من PDF عبر pdftotext */
function extractRawText(pdfPath: string, maxPages = 3): string {
  try {
    return execFileSync("pdftotext", ["-l", String(maxPages), pdfPath, "-"], {
      encoding: "utf-8",
      timeout: 15_000,
      windowsHide: true,
      stdio: ["ignore", "pipe", "pipe"],
    });
  } catch {
    return "";
  }
}

/** حساب نسبة الأحرف العربية في النص */
function arabicRatio(text: string): number {
  if (text.length === 0) return 0;
  const arabicChars = [...text].filter(
    (c) => c.charCodeAt(0) >= 0x0600 && c.charCodeAt(0) <= 0x06ff
  ).length;
  return arabicChars / text.length;
}

/** حساب نسبة الأحرف القابلة للطباعة (غير المسافات) */
function printableRatio(text: string): number {
  const stripped = text.replace(/\s/g, "");
  return stripped.length;
}

// ─── المنطق الرئيسي ──────────────────────────────────────────

function classifyPdf(pdfPath: string): ClassificationResult {
  const notes: string[] = [];

  // التحقق من وجود الملف
  let fileSize: number;
  try {
    fileSize = statSync(pdfPath).size;
  } catch {
    return {
      type: "invalid",
      pages: 0,
      size_mb: 0,
      filename: basename(pdfPath),
      has_arabic: false,
      recommended_engine: "vision",
      notes: ["الملف غير موجود أو لا يمكن الوصول إليه"],
    };
  }

  const sizeMb = Math.round((fileSize / (1024 * 1024)) * 100) / 100;
  const filename = basename(pdfPath);

  // استخراج معلومات PDF
  const info = getPdfInfo(pdfPath);
  const pages = parseInt(info["Pages"] ?? "0", 10);

  // فحص الحماية
  if (info["Encrypted"] === "yes") {
    return {
      type: "protected",
      pages,
      size_mb: sizeMb,
      filename,
      has_arabic: false,
      recommended_engine: "vision",
      notes: ["الملف محمي بكلمة مرور — يتطلب فك التشفير أولاً"],
    };
  }

  // تحذير الحجم
  if (sizeMb > 50) {
    notes.push(
      `حجم الملف كبير (${sizeMb}MB) — قد يتجاوز حد Mistral API (50MB)`
    );
  }

  // تحذير الصفحات
  if (pages > 1000) {
    notes.push(`عدد الصفحات كبير (${pages}) — يتطلب معالجة على دفعات`);
  } else if (pages > 50) {
    notes.push(`${pages} صفحة — يُنصح بسؤال المستخدم قبل البدء`);
  }

  // محاولة استخراج نص
  const rawText = extractRawText(pdfPath);
  const printable = printableRatio(rawText);
  const arRatio = arabicRatio(rawText);
  const hasArabic = arRatio > 0.05;

  // تحديد النوع
  let type: ClassificationResult["type"];
  let engine: ClassificationResult["recommended_engine"];

  if (printable > 200) {
    // يوجد نص كافٍ — PDF نصي أو مختلط
    if (printable > 500) {
      type = "text-based";
      engine = "pdfminer";
      notes.push("PDF نصي — يمكن الاستخراج المباشر بدون OCR");
    } else {
      type = "mixed";
      engine = "mistral";
      notes.push("PDF مختلط — بعض الصفحات نصية وبعضها ممسوح");
    }
  } else {
    // لا يوجد نص كافٍ — PDF ممسوح ضوئياً
    type = "scanned";
    engine = "mistral";
    notes.push("PDF ممسوح ضوئياً — يتطلب OCR كامل");
  }

  // إذا لم يتوفر مفتاح Mistral
  if (engine === "mistral" && !process.env["MISTRAL_API_KEY"]) {
    notes.push("⚠ مفتاح MISTRAL_API_KEY غير متوفر — سيُستخدم المحرك الاحتياطي");
  }

  return {
    type,
    pages,
    size_mb: sizeMb,
    filename,
    has_arabic: hasArabic,
    recommended_engine: engine,
    notes,
  };
}

// ─── نقطة الدخول ──────────────────────────────────────────────

const pdfPath = process.argv[2];

if (!pdfPath) {
  console.error("الاستخدام: npx tsx classify-pdf.ts <مسار_ملف_PDF>");
  process.exit(1);
}

const result = classifyPdf(pdfPath);
console.log(JSON.stringify(result, null, 2));

#!/usr/bin/env npx tsx
/**
 * enhance-image.ts — تحسين جودة صور PDF الممسوحة قبل OCR
 *
 * الاستخدام:
 *   npx tsx enhance-image.ts --input "/tmp/ocr_pages" --output "/tmp/ocr_enhanced"
 *   npx tsx enhance-image.ts --input "/path/to/single.png" --output "/path/to/enhanced.png"
 *
 * العمليات:
 *   1. تحسين التباين (contrast)
 *   2. تحسين الحدة (sharpness)
 *   3. تحويل لتدرج الرمادي (grayscale) — يحسّن دقة OCR للنص
 *   4. تطبيق عتبة تكيفية (adaptive threshold) — لفصل النص عن الخلفية
 *   5. إزالة الضوضاء (denoise)
 */

import { readdirSync, mkdirSync, statSync, existsSync } from "node:fs";
import { join, basename, extname } from "node:path";

// ─── تحليل المعاملات ──────────────────────────────────────────

function parseArgs(): { input: string; output: string } {
  const args = process.argv.slice(2);
  let input = "";
  let output = "";

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--input" && args[i + 1]) input = args[++i];
    else if (args[i] === "--output" && args[i + 1]) output = args[++i];
  }

  if (!input || !output) {
    console.error(
      "الاستخدام: npx tsx enhance-image.ts --input <مجلد_أو_صورة> --output <مجلد_أو_صورة>"
    );
    process.exit(1);
  }

  return { input, output };
}

// ─── تحسين صورة واحدة ────────────────────────────────────────

async function enhanceImage(
  inputPath: string,
  outputPath: string
): Promise<void> {
  // استيراد ديناميكي لـ sharp
  const sharp = (await import("sharp")).default;

  await sharp(inputPath)
    // 1. تحويل لتدرج الرمادي — يُحسّن التمييز بين النص والخلفية
    .grayscale()
    // 2. تطبيع الألوان — يوازن التباين تلقائياً
    .normalize()
    // 3. تحسين الحدة — يُبرز حواف الحروف العربية
    .sharpen({
      sigma: 1.5,
      m1: 1.0, // flat areas sharpening
      m2: 2.0, // jagged areas sharpening
    })
    // 4. تعديل التباين والسطوع
    .modulate({
      brightness: 1.05, // زيادة طفيفة في السطوع
    })
    // 5. إزالة الضوضاء عبر median filter
    .median(3)
    // 6. ضمان DPI مناسب (300)
    .withMetadata({ density: 300 })
    .png({ quality: 95, compressionLevel: 6 })
    .toFile(outputPath);
}

// ─── المنطق الرئيسي ──────────────────────────────────────────

async function main(): Promise<void> {
  const { input, output } = parseArgs();

  const inputStat = statSync(input);

  if (inputStat.isFile()) {
    // معالجة صورة واحدة
    console.error(`تحسين: ${basename(input)}`);
    await enhanceImage(input, output);
    console.error(`تم: ${output}`);
    console.log(JSON.stringify({ success: true, files_processed: 1 }));
    return;
  }

  if (inputStat.isDirectory()) {
    // معالجة مجلد صور
    if (!existsSync(output)) {
      mkdirSync(output, { recursive: true });
    }

    const imageFiles = readdirSync(input).filter((f) => {
      const ext = extname(f).toLowerCase();
      return [".png", ".jpg", ".jpeg", ".tiff", ".tif", ".bmp"].includes(ext);
    });

    if (imageFiles.length === 0) {
      console.error("لا توجد صور في المجلد المحدد");
      process.exit(1);
    }

    console.error(`معالجة ${imageFiles.length} صورة...`);
    let processed = 0;

    for (const file of imageFiles) {
      const inPath = join(input, file);
      const outPath = join(output, file);

      try {
        await enhanceImage(inPath, outPath);
        processed++;

        if (processed % 10 === 0) {
          console.error(`  تقدم: ${processed}/${imageFiles.length}`);
        }
      } catch (err: any) {
        console.error(`  فشل تحسين ${file}: ${err.message}`);
      }
    }

    console.error(
      `تم تحسين ${processed}/${imageFiles.length} صورة → ${output}`
    );
    console.log(
      JSON.stringify({
        success: true,
        files_processed: processed,
        files_total: imageFiles.length,
        output_dir: output,
      })
    );
    return;
  }

  console.error("المدخل ليس ملفاً ولا مجلداً صالحاً");
  process.exit(1);
}

main();

#!/usr/bin/env npx tsx
/**
 * ocr-mistral.ts — استخراج النص من PDF عبر Mistral OCR 3
 *
 * الاستخدام:
 *   npx tsx ocr-mistral.ts --input "/path/to/file.pdf" --output "/path/to/result.json"
 *   npx tsx ocr-mistral.ts --input "/path/to/file.pdf" --output "/path/to/result.json" --pages "0-9"
 *
 * المتطلبات:
 *   - متغير البيئة MISTRAL_API_KEY
 *   - حزمة @mistralai/mistralai
 *
 * المخرج: ملف JSON يحتوي نتائج OCR لكل صفحة
 */

import { readFileSync, writeFileSync } from "node:fs";
import { basename } from "node:path";

const CANONICAL_MISTRAL_OCR_MODEL = "mistral-ocr-latest";

// ─── أنواع البيانات ───────────────────────────────────────────

interface OcrPageResult {
  /** رقم الصفحة (يبدأ من 0) */
  index: number;
  /** النص المستخرج بصيغة Markdown */
  markdown: string;
  /** الصور المكتشفة في الصفحة */
  images: Array<{
    id: string;
    bbox: {
      top_left_x: number;
      top_left_y: number;
      bottom_right_x: number;
      bottom_right_y: number;
    };
  }>;
}

interface OcrResult {
  /** اسم الملف المصدر */
  source: string;
  /** النموذج المستخدم */
  model: string;
  /** عدد الصفحات المعالجة */
  total_pages: number;
  /** مجموع بايتات المستند */
  doc_size_bytes: number | null;
  /** نتائج كل صفحة */
  pages: OcrPageResult[];
  /** وقت المعالجة بالثواني */
  processing_time_seconds: number;
}

interface MistralOcrImageRaw {
  id?: unknown;
  top_left_x?: unknown;
  top_left_y?: unknown;
  bottom_right_x?: unknown;
  bottom_right_y?: unknown;
}

interface MistralOcrPageRaw {
  index?: unknown;
  markdown?: unknown;
  images?: unknown;
}

interface MistralOcrResponseRaw {
  model?: unknown;
  pages?: unknown;
  usage_info?: unknown;
}

interface MistralOcrRequest {
  model: string;
  document: {
    type: "document_url";
    documentUrl: string;
  };
  includeImageBase64: boolean;
  tableFormat: "markdown" | "html";
  pages?: number[];
}

// ─── تحليل المعاملات ──────────────────────────────────────────

function parseArgs(): {
  input: string;
  output: string;
  pages: number[] | null;
} {
  const args = process.argv.slice(2);
  let input = "";
  let output = "";
  let pagesStr = "";

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--input" && args[i + 1]) input = args[++i];
    else if (args[i] === "--output" && args[i + 1]) output = args[++i];
    else if (args[i] === "--pages" && args[i + 1]) pagesStr = args[++i];
  }

  if (!input || !output) {
    console.error(
      "الاستخدام: npx tsx ocr-mistral.ts --input <pdf> --output <json> [--pages 0-9|all]"
    );
    process.exit(1);
  }

  // تحليل نطاق الصفحات
  let pages: number[] | null = null;
  if (pagesStr && pagesStr !== "all") {
    const match = pagesStr.match(/^(\d+)-(\d+)$/);
    if (match) {
      const start = parseInt(match[1], 10);
      const end = parseInt(match[2], 10);
      pages = Array.from({ length: end - start + 1 }, (_, i) => start + i);
    } else {
      // أرقام مفصولة بفاصلة
      pages = pagesStr.split(",").map((s) => parseInt(s.trim(), 10));
    }
  }

  return { input, output, pages };
}

// ─── المنطق الرئيسي ──────────────────────────────────────────

function requireApiKey(raw: string | undefined): string {
  const value = (raw ?? "").trim();
  if (!value) {
    throw new Error("خطأ: متغير البيئة MISTRAL_API_KEY غير موجود");
  }
  if (/\s/u.test(value)) {
    throw new Error("خطأ: قيمة MISTRAL_API_KEY غير صالحة (تحتوي مسافات)");
  }
  return value;
}

function toInt(value: unknown, fallback: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.trunc(parsed);
}

function toNumberOrNull(value: unknown, fallback: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return parsed;
}

function normalizeImages(images: unknown): OcrPageResult["images"] {
  if (!Array.isArray(images)) return [];
  const mapped: OcrPageResult["images"] = [];

  for (const image of images) {
    if (!image || typeof image !== "object") {
      continue;
    }
    const raw = image as MistralOcrImageRaw;
    mapped.push({
      id: typeof raw.id === "string" ? raw.id : "",
      bbox: {
        top_left_x: toInt(raw.top_left_x, 0),
        top_left_y: toInt(raw.top_left_y, 0),
        bottom_right_x: toInt(raw.bottom_right_x, 0),
        bottom_right_y: toInt(raw.bottom_right_y, 0),
      },
    });
  }

  return mapped;
}

function buildNormalizedResult(
  inputPath: string,
  response: MistralOcrResponseRaw,
  docSizeBytes: number,
  elapsedSeconds: number
): OcrResult {
  const pagesRaw = Array.isArray(response.pages) ? response.pages : [];
  const usageInfo =
    response.usage_info && typeof response.usage_info === "object"
      ? (response.usage_info as Record<string, unknown>)
      : undefined;

  const result: OcrResult = {
    source: basename(inputPath),
    model:
      typeof response.model === "string"
        ? response.model
        : "mistral-ocr-latest",
    total_pages: pagesRaw.length,
    doc_size_bytes: toNumberOrNull(usageInfo?.doc_size_bytes, docSizeBytes),
    processing_time_seconds: Math.round(elapsedSeconds * 100) / 100,
    pages: [],
  };

  for (const page of pagesRaw) {
    if (!page || typeof page !== "object") {
      continue;
    }
    const rawPage = page as MistralOcrPageRaw;
    result.pages.push({
      index: toInt(rawPage.index, 0),
      markdown: typeof rawPage.markdown === "string" ? rawPage.markdown : "",
      images: normalizeImages(rawPage.images),
    });
  }

  return result;
}

async function withTimeout<T>(
  promise: Promise<T>,
  timeoutMs: number,
  timeoutMessage: string
): Promise<T> {
  let timer: NodeJS.Timeout | undefined;
  const timeoutPromise = new Promise<never>((_, reject) => {
    timer = setTimeout(() => reject(new Error(timeoutMessage)), timeoutMs);
  });

  try {
    return await Promise.race([promise, timeoutPromise]);
  } finally {
    if (timer) {
      clearTimeout(timer);
    }
  }
}

function getStatusCode(error: unknown): number | null {
  if (!error || typeof error !== "object") return null;
  const e = error as Record<string, unknown>;
  const candidates = [e.statusCode, e["status"], e.code];
  for (const value of candidates) {
    const asNumber = Number(value);
    if (Number.isInteger(asNumber)) {
      return asNumber;
    }
  }
  return null;
}

function resolveHardLockedModel(raw: string | undefined): string {
  if (typeof raw !== "string" || !raw.trim()) {
    return CANONICAL_MISTRAL_OCR_MODEL;
  }
  const normalized = raw.trim();
  if (normalized !== CANONICAL_MISTRAL_OCR_MODEL) {
    throw new Error(
      `MISTRAL_OCR_MODEL must be ${CANONICAL_MISTRAL_OCR_MODEL}. القيمة الحالية: ${normalized}`
    );
  }
  return CANONICAL_MISTRAL_OCR_MODEL;
}

async function runOcr(): Promise<void> {
  const { input, output, pages } = parseArgs();

  const model = resolveHardLockedModel(process.env["MISTRAL_OCR_MODEL"]);
  const timeoutMs = Math.max(
    1_000,
    Number.parseInt(process.env["MISTRAL_OCR_TIMEOUT_MS"] ?? "600000", 10) ||
      600_000
  );

  let apiKey = "";
  try {
    apiKey = requireApiKey(process.env["MISTRAL_API_KEY"]);
  } catch (error) {
    console.error(error instanceof Error ? error.message : String(error));
    process.exit(1);
  }

  // استيراد ديناميكي لـ Mistral SDK
  const { Mistral } = await import("@mistralai/mistralai");
  const client = new Mistral({ apiKey });

  // قراءة PDF وتحويله لـ base64
  console.error(`قراءة الملف: ${input}`);
  const pdfBuffer = readFileSync(input);
  const base64Pdf = pdfBuffer.toString("base64");
  const docSizeBytes = pdfBuffer.byteLength;

  console.error(`حجم الملف: ${(docSizeBytes / 1024 / 1024).toFixed(2)} MB`);

  // فحص حد الحجم
  if (docSizeBytes > 50 * 1024 * 1024) {
    console.error("تحذير: الملف أكبر من 50MB — قد يرفضه Mistral API");
  }

  // بناء طلب OCR
  const ocrParams: MistralOcrRequest = {
    model,
    document: {
      type: "document_url",
      documentUrl: `data:application/pdf;base64,${base64Pdf}`,
    },
    includeImageBase64: false,
    tableFormat: "markdown",
  };

  if (pages !== null) {
    ocrParams.pages = pages;
    console.error(`معالجة صفحات محددة: ${pages.join(", ")}`);
  } else {
    console.error("معالجة كل الصفحات...");
  }

  // تنفيذ OCR
  const startTime = Date.now();

  try {
    const response = await withTimeout(
      client.ocr.process(ocrParams),
      timeoutMs,
      `انتهت مهلة استدعاء OCR بعد ${timeoutMs}ms`
    );
    const elapsed = (Date.now() - startTime) / 1000;

    const result = buildNormalizedResult(
      input,
      response as unknown as MistralOcrResponseRaw,
      docSizeBytes,
      elapsed
    );

    // كتابة النتيجة
    writeFileSync(output, JSON.stringify(result, null, 2), "utf-8");
    console.error(
      `تمت المعالجة: ${result.total_pages} صفحة في ${elapsed.toFixed(1)} ثانية`
    );
    console.error(`المخرج: ${output}`);

    // إخراج ملخص على stdout
    console.log(
      JSON.stringify({
        success: true,
        pages_processed: result.total_pages,
        model: result.model,
        time_seconds: result.processing_time_seconds,
        output_path: output,
      })
    );
  } catch (error: unknown) {
    const elapsed = (Date.now() - startTime) / 1000;
    console.error(`فشل OCR بعد ${elapsed.toFixed(1)} ثانية`);
    const errorMessage = error instanceof Error ? error.message : String(error);
    console.error(`الخطأ: ${errorMessage}`);

    // محاولة تحديد نوع الخطأ
    const statusCode = getStatusCode(error);
    if (statusCode === 401) {
      console.error("→ مفتاح API غير صالح");
    } else if (statusCode === 413) {
      console.error("→ الملف أكبر من الحد المسموح");
    } else if (statusCode === 429) {
      console.error("→ تجاوز حد الطلبات — انتظر ثم أعد المحاولة");
    }

    console.log(
      JSON.stringify({
        success: false,
        error: errorMessage,
        status_code: statusCode ?? null,
      })
    );
    process.exit(1);
  }
}

runOcr();

#!/usr/bin/env npx tsx
/**
 * write-output.ts — تحويل نتائج OCR إلى ملف TXT أو Markdown
 *
 * الاستخدام:
 *   npx tsx write-output.ts --input "/path/to/ocr_result.json" --format "md" --output "/path/to/output.md"
 *   npx tsx write-output.ts --input "/path/to/ocr_result.json" --format "txt" --output "/path/to/output.txt"
 *
 * المدخل: ملف JSON ناتج من ocr-mistral.ts أو أي مصدر يتبع نفس الهيكل
 */

import { readFileSync, writeFileSync } from "node:fs";
import { basename } from "node:path";

// ─── أنواع البيانات ───────────────────────────────────────────

interface OcrPageResult {
  index: number;
  markdown: string;
  images: Array<{ id: string; bbox: Record<string, number> }>;
}

interface OcrResult {
  source: string;
  model: string;
  total_pages: number;
  doc_size_bytes: number | null;
  pages: OcrPageResult[];
  processing_time_seconds: number;
}

type OutputFormat = "txt" | "txt-raw" | "md";

// ─── تحليل المعاملات ──────────────────────────────────────────

function parseArgs(): { input: string; format: OutputFormat; output: string } {
  const args = process.argv.slice(2);
  let input = "";
  let format: OutputFormat = "txt";
  let output = "";

  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--input" && args[i + 1]) input = args[++i];
    else if (args[i] === "--format" && args[i + 1]) {
      const f = args[++i].toLowerCase();
      if (f === "md" || f === "markdown") format = "md";
      else if (f === "txt-raw") format = "txt-raw";
      else format = "txt";
    } else if (args[i] === "--output" && args[i + 1]) output = args[++i];
  }

  if (!input || !output) {
    console.error(
      "الاستخدام: npx tsx write-output.ts --input <json> --format <txt|txt-raw|md> --output <ملف>"
    );
    process.exit(1);
  }

  return { input, format, output };
}

// ─── مولّدات المخرجات ─────────────────────────────────────────

/** كتابة مخرج نصي خام */
function generateTxt(data: OcrResult): string {
  const separator = "=".repeat(60);
  const lines: string[] = [];

  for (const page of data.pages) {
    const pageNum = page.index + 1;
    lines.push(separator);
    lines.push(`الصفحة ${pageNum}`);
    lines.push(separator);
    lines.push("");
    lines.push(page.markdown.trim());
    lines.push("");
    lines.push("");
  }

  return lines.join("\n");
}

/** كتابة مخرج نصي خام قبل أي تنسيق صفحات */
function generateTxtRaw(data: OcrResult): string {
  return data.pages
    .map((page) => page.markdown.trim())
    .filter((pageText) => pageText.length > 0)
    .join("\n\n");
}

/** كتابة مخرج Markdown مع بنية وبيانات وصفية */
function generateMarkdown(data: OcrResult): string {
  const lines: string[] = [];

  // ترويسة المستند
  lines.push(`# ${data.source}`);
  lines.push("");
  lines.push(`> **المحرك:** \`${data.model}\``);
  lines.push(`> **عدد الصفحات:** ${data.total_pages}`);
  if (data.processing_time_seconds > 0) {
    lines.push(`> **وقت المعالجة:** ${data.processing_time_seconds} ثانية`);
  }
  lines.push("");
  lines.push("---");
  lines.push("");

  // فهرس الصفحات (للملفات الكبيرة)
  if (data.total_pages > 10) {
    lines.push("## فهرس الصفحات");
    lines.push("");
    for (const page of data.pages) {
      const pageNum = page.index + 1;
      lines.push(`- [الصفحة ${pageNum}](#الصفحة-${pageNum})`);
    }
    lines.push("");
    lines.push("---");
    lines.push("");
  }

  // محتوى الصفحات
  for (const page of data.pages) {
    const pageNum = page.index + 1;
    lines.push(`## الصفحة ${pageNum}`);
    lines.push("");
    lines.push(page.markdown.trim());
    lines.push("");

    // إشارة للصور المكتشفة
    if (page.images.length > 0) {
      lines.push(`> *تم اكتشاف ${page.images.length} صورة في هذه الصفحة*`);
      lines.push("");
    }

    lines.push("---");
    lines.push("");
  }

  return lines.join("\n");
}

// ─── المنطق الرئيسي ──────────────────────────────────────────

function main(): void {
  const { input, format, output } = parseArgs();

  // قراءة نتائج OCR
  let data: OcrResult;
  try {
    const raw = readFileSync(input, "utf-8");
    data = JSON.parse(raw) as OcrResult;
  } catch (err: any) {
    console.error(`فشل قراءة ملف الإدخال: ${err.message}`);
    process.exit(1);
  }

  if (!data.pages || data.pages.length === 0) {
    console.error("الملف لا يحتوي صفحات — تحقق من نتائج OCR");
    process.exit(1);
  }

  // توليد المخرج
  const content =
    format === "md"
      ? generateMarkdown(data)
      : format === "txt-raw"
        ? generateTxtRaw(data)
        : generateTxt(data);

  // كتابة الملف
  writeFileSync(output, content, "utf-8");

  const sizeKb = Math.round(Buffer.byteLength(content, "utf-8") / 1024);

  console.error(`تم الكتابة: ${output}`);
  console.error(`الصيغة: ${format.toUpperCase()}`);
  console.error(`الصفحات: ${data.pages.length}`);
  console.error(`الحجم: ${sizeKb} KB`);

  // ملخص على stdout
  console.log(
    JSON.stringify({
      success: true,
      format,
      pages: data.pages.length,
      output_path: output,
      size_kb: sizeKb,
    })
  );
}

main();

/**
 * skill-tools.ts — تغليف سكريبتات المهارة (skill) كأدوات AI SDK
 *
 * يحوّل السكريبتات الموجودة في skill.zip إلى أدوات قابلة للاستدعاء
 * من الوكيل مباشرةً عبر `tool()` من Vercel AI SDK v6.
 *
 * السكريبتات المُغلَّفة:
 *   - classify-pdf.ts   → أداة skill_classify_pdf
 *   - ocr-mistral.ts    → أداة skill_ocr_mistral
 *   - write-output.ts   → أداة skill_write_output
 *   - enhance-image.ts  → أداة skill_enhance_images
 *
 * كل أداة تُنفِّذ السكريبت الأصلي كعملية فرعية (child process)
 * وتُعيد النتيجة بصيغة JSON.
 */

import { tool } from "ai";
import { z } from "zod";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { stat } from "node:fs/promises";

const execFileAsync = promisify(execFile);

// ─── مسارات السكريبتات ──────────────────────────────────────

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const SCRIPTS_DIR = resolve(__dirname, "skill-scripts");

/**
 * تنفيذ سكريبت TypeScript عبر npx tsx
 * يلتقط stdout (JSON) و stderr (سجل العمليات)
 */
async function runScript(
  scriptName: string,
  args: string[],
  timeoutMs = 300_000
): Promise<{ stdout: string; stderr: string }> {
  const scriptPath = resolve(SCRIPTS_DIR, scriptName);

  // التحقق من وجود السكريبت
  try {
    await stat(scriptPath);
  } catch {
    throw new Error(`السكريبت غير موجود: ${scriptPath}`);
  }

  const { stdout, stderr } = await execFileAsync(
    process.execPath,
    ["--import", "tsx", scriptPath, ...args],
    {
      timeout: timeoutMs,
      maxBuffer: 50 * 1024 * 1024, // 50MB — لملفات OCR الكبيرة
      env: {
        ...process.env,
        // ضمان تمرير مفاتيح API
        MISTRAL_API_KEY: process.env["MISTRAL_API_KEY"] ?? "",
        OPENAI_API_KEY: process.env["OPENAI_API_KEY"] ?? "",
      },
    }
  );

  return { stdout: stdout.trim(), stderr: stderr.trim() };
}

// ═══════════════════════════════════════════════════════════════
// أداة 1: تصنيف PDF (classify-pdf.ts)
// ═══════════════════════════════════════════════════════════════

export const skillClassifyPdf = tool({
  description: `تصنيف ملف PDF وتحديد نوعه (نصي / ممسوح ضوئياً / مختلط / محمي) والمحرك الأنسب لمعالجته.
هذه هي الخطوة الأولى الإلزامية قبل أي عملية OCR.
تعتمد على أدوات النظام (pdfinfo, pdftotext) لتحليل الملف.

المخرج JSON يحتوي:
- type: نوع PDF (text-based | scanned | mixed | protected | invalid)
- pages: عدد الصفحات
- size_mb: الحجم بالميجابايت
- has_arabic: هل يحتوي نصاً عربياً
- recommended_engine: المحرك الموصى به (pdfminer | mistral | vision)
- notes: ملاحظات وتحذيرات`,

  inputSchema: z.object({
    pdfPath: z.string().describe("المسار المطلق لملف PDF المراد تصنيفه"),
  }),

  execute: async ({ pdfPath }) => {
    try {
      const { stdout, stderr } = await runScript("classify-pdf.ts", [pdfPath]);
      if (stderr) {
        console.error(`[skill/classify] ${stderr}`);
      }
      return (
        stdout ||
        JSON.stringify({ success: false, error: "لا مخرجات من سكريبت التصنيف" })
      );
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      return JSON.stringify({ success: false, error: `فشل التصنيف: ${msg}` });
    }
  },
});

// ═══════════════════════════════════════════════════════════════
// أداة 2: OCR عبر Mistral (ocr-mistral.ts)
// ═══════════════════════════════════════════════════════════════

export const skillOcrMistral = tool({
  description: `استخراج النص من ملف PDF عبر Mistral OCR 3 — المحرك الأساسي بدقة 99%+ للعربية.
يتطلب متغير البيئة MISTRAL_API_KEY.
يُنتج ملف JSON يحتوي نتائج OCR لكل صفحة (markdown + صور مكتشفة).

المدخلات:
- input: مسار ملف PDF
- output: مسار ملف JSON الناتج
- pages: نطاق الصفحات ("all" أو "0-9" أو "0,3,5")

استخدم هذه الأداة بدلاً من أداة MCP convert_document_to_markdown
عندما تريد التحكم الكامل في عملية OCR وحفظ النتائج الخام.`,

  inputSchema: z.object({
    input: z.string().describe("المسار المطلق لملف PDF"),
    output: z.string().describe("المسار المطلق لملف JSON الناتج"),
    pages: z
      .string()
      .default("all")
      .describe('نطاق الصفحات: "all" أو "0-9" أو "0,3,5"'),
  }),

  execute: async ({ input, output, pages }) => {
    try {
      // التحقق من وجود المفتاح
      if (!process.env["MISTRAL_API_KEY"]) {
        return JSON.stringify({
          success: false,
