/**
 * tools.ts — أدوات الوكيل المحلية (بدون MCP)
 *
 * أدوات مساعدة للقراءة والكتابة وتصنيف الملفات،
 * تعمل مباشرةً داخل الوكيل بدون الحاجة لخادم MCP خارجي.
 */

import { tool } from "ai";
import { z } from "zod";
import { readFile, writeFile, stat, readdir, mkdir } from "node:fs/promises";
import { basename, extname, dirname, join } from "node:path";
import { execFileSync } from "node:child_process";
import type { ClassificationResult } from "./types";

// ─── أداة قراءة الملفات ─────────────────────────────────────

export const readFileTool = tool({
  description:
    "قراءة محتوى ملف من نظام الملفات. يدعم الملفات النصية (txt, md, json, csv). للملفات الثنائية يُعيد معلومات وصفية فقط.",
  inputSchema: z.object({
    filePath: z.string().describe("المسار المطلق للملف المراد قراءته"),
    encoding: z
      .enum(["utf-8", "base64"])
      .default("utf-8")
      .describe("ترميز القراءة — utf-8 للنصوص، base64 للثنائيات"),
  }),
  execute: async ({ filePath, encoding }) => {
    try {
      const fileStat = await stat(filePath);
      const sizeKb = Math.round(fileStat.size / 1024);
      const ext = extname(filePath).toLowerCase();

      // ملفات PDF و الصور — إعادة معلومات وصفية فقط
      if ([".pdf", ".png", ".jpg", ".jpeg", ".tiff", ".bmp"].includes(ext)) {
        return JSON.stringify({
          success: true,
          type: "binary",
          filename: basename(filePath),
          extension: ext,
          size_kb: sizeKb,
          message: `ملف ثنائي (${ext}) — الحجم: ${sizeKb} KB. استخدم أداة OCR للمعالجة.`,
        });
      }

      // ملفات نصية
      const content = await readFile(filePath, encoding as BufferEncoding);
      const lineCount = encoding === "utf-8" ? content.split("\n").length : 0;

      return JSON.stringify({
        success: true,
        type: "text",
        filename: basename(filePath),
        extension: ext,
        size_kb: sizeKb,
        line_count: lineCount,
        content:
          content.length > 50_000
            ? content.substring(0, 50_000) +
              "\n\n... [تم اقتطاع المحتوى — الملف طويل جداً]"
            : content,
      });
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      return JSON.stringify({ success: false, error: msg });
    }
  },
});

// ─── أداة كتابة الملفات ─────────────────────────────────────

export const writeFileTool = tool({
  description:
    "كتابة محتوى نصي إلى ملف. يُنشئ المجلدات تلقائياً إن لم تكن موجودة. يتجنب الكتابة فوق الملفات الموجودة.",
  inputSchema: z.object({
    filePath: z.string().describe("المسار المطلق لملف الإخراج"),
    content: z.string().describe("المحتوى المراد كتابته"),
    overwrite: z
      .boolean()
      .default(false)
      .describe("السماح بالكتابة فوق ملف موجود"),
  }),
  execute: async ({ filePath, content, overwrite }) => {
    try {
      // إنشاء المجلد إن لم يكن موجوداً
      const dir = dirname(filePath);
      await mkdir(dir, { recursive: true });

      // التحقق من وجود الملف
      let finalPath = filePath;
      if (!overwrite) {
        try {
          await stat(filePath);
          // الملف موجود — إضافة لاحقة رقمية
          const ext = extname(filePath);
          const base = filePath.slice(0, -ext.length);
          let counter = 1;
          while (true) {
            finalPath = `${base}_${counter}${ext}`;
            try {
              await stat(finalPath);
              counter++;
            } catch {
              break; // الملف غير موجود — يمكن الاستخدام
            }
          }
        } catch {
          // الملف غير موجود — المسار الأصلي صالح
        }
      }

      await writeFile(finalPath, content, "utf-8");
      const sizeKb = Math.round(Buffer.byteLength(content, "utf-8") / 1024);

      return JSON.stringify({
        success: true,
        path: finalPath,
        size_kb: sizeKb,
        lines: content.split("\n").length,
      });
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      return JSON.stringify({ success: false, error: msg });
    }
  },
});

// ─── أداة سرد الملفات ───────────────────────────────────────

export const listFilesTool = tool({
  description:
    "سرد الملفات في مجلد محدد مع تصفية اختيارية حسب الامتداد. مفيد لاكتشاف ملفات PDF في مجلد.",
  inputSchema: z.object({
    dirPath: z.string().describe("المسار المطلق للمجلد"),
    extensions: z
      .array(z.string())
      .optional()
      .describe('تصفية حسب الامتداد (مثال: [".pdf", ".txt"])'),
  }),
  execute: async ({ dirPath, extensions }) => {
    try {
      const entries = await readdir(dirPath, { withFileTypes: true });
      const files: Array<{
        name: string;
        type: string;
        size_kb?: number;
      }> = [];

      for (const entry of entries) {
        if (entry.isFile()) {
          const ext = extname(entry.name).toLowerCase();
          if (extensions && !extensions.includes(ext)) continue;

          try {
            const fileStat = await stat(join(dirPath, entry.name));
            files.push({
              name: entry.name,
              type: ext,
              size_kb: Math.round(fileStat.size / 1024),
            });
          } catch {
            files.push({ name: entry.name, type: ext });
          }
        }
      }

      return JSON.stringify({
        success: true,
        directory: dirPath,
        total_files: files.length,
        files,
      });
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      return JSON.stringify({ success: false, error: msg });
    }
  },
});

// ─── أداة تصنيف PDF ─────────────────────────────────────────

export const classifyPdfTool = tool({
  description:
    "تصنيف ملف PDF وتحديد نوعه (نصي / ممسوح / مختلط / محمي) والمحرك الأنسب لمعالجته. الخطوة الأولى قبل أي عملية OCR.",
  inputSchema: z.object({
    pdfPath: z.string().describe("المسار المطلق لملف PDF"),
  }),
  execute: async ({ pdfPath }) => {
    try {
      const fileStat = await stat(pdfPath);
      const sizeMb = Math.round((fileStat.size / (1024 * 1024)) * 100) / 100;
      const filename = basename(pdfPath);
      const notes: string[] = [];

      // محاولة استخراج معلومات PDF عبر pdfinfo
      let pages = 0;
      let isEncrypted = false;
      try {
        const output = execFileSync("pdfinfo", [pdfPath], {
          encoding: "utf-8",
          timeout: 10_000,
          windowsHide: true,
          stdio: ["ignore", "pipe", "pipe"],
        });
        for (const line of output.split("\n")) {
          if (line.startsWith("Pages:")) {
            pages = parseInt(line.split(":")[1]?.trim() ?? "0", 10);
          }
          if (line.startsWith("Encrypted:") && line.includes("yes")) {
            isEncrypted = true;
          }
        }
      } catch {
        notes.push("لم يُعثر على pdfinfo — التصنيف مبني على حجم الملف فقط");
      }

      if (isEncrypted) {
        return JSON.stringify({
          type: "protected",
          pages,
          size_mb: sizeMb,
          filename,
          has_arabic: false,
          recommended_engine: "vision",
          notes: ["الملف محمي بكلمة مرور — يتطلب فك التشفير أولاً"],
        } satisfies ClassificationResult);
      }

      // محاولة استخراج نص خام
      let rawText = "";
      try {
        rawText = execFileSync("pdftotext", ["-l", "3", pdfPath, "-"], {
          encoding: "utf-8",
          timeout: 15_000,
          windowsHide: true,
          stdio: ["ignore", "pipe", "pipe"],
        });
      } catch {
        notes.push("لم يُعثر على pdftotext — يُفترض أن الملف ممسوح ضوئياً");
      }

      // تحليل النص المستخرج
      const printableCount = rawText.replace(/\s/g, "").length;
      const arabicChars = [...rawText].filter(
        (c) => c.charCodeAt(0) >= 0x0600 && c.charCodeAt(0) <= 0x06ff
      ).length;
      const hasArabic =
        rawText.length > 0 && arabicChars / rawText.length > 0.05;

      // تحديد النوع
      let type: ClassificationResult["type"];
      let engine: ClassificationResult["recommended_engine"];

      if (printableCount > 500) {
        type = "text-based";
        engine = "pdfminer";
        notes.push("PDF نصي — يمكن الاستخراج المباشر بدون OCR");
      } else if (printableCount > 200) {
        type = "mixed";
        engine = "mistral";
        notes.push("PDF مختلط — بعض الصفحات نصية وبعضها ممسوح");
      } else {
        type = "scanned";
        engine = "mistral";
        notes.push("PDF ممسوح ضوئياً — يتطلب OCR كامل");
      }

      if (sizeMb > 50) {
        notes.push(`حجم الملف كبير (${sizeMb}MB) — قد يتجاوز حد Mistral API`);
      }
      if (pages > 50) {
        notes.push(`${pages} صفحة — قد يستغرق وقتاً طويلاً`);
      }

      if (!process.env["MISTRAL_API_KEY"] && engine === "mistral") {
        notes.push(
          "⚠ مفتاح MISTRAL_API_KEY غير متوفر — ستُستخدم طبقة احتياطية"
        );
      }

      return JSON.stringify({
        type,
        pages,
        size_mb: sizeMb,
        filename,
        has_arabic: hasArabic,
        recommended_engine: engine,
        notes,
      } satisfies ClassificationResult);
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error);
      return JSON.stringify({
        type: "invalid",
        pages: 0,
        size_mb: 0,
        filename: basename(pdfPath),
        has_arabic: false,
        recommended_engine: "vision",
        notes: [`خطأ في التصنيف: ${msg}`],
      } satisfies ClassificationResult);
    }
  },
});

/**
 * Queue Integration Tests
 *
 * End-to-end integration tests for queue system with failure and retry scenarios
 */

import { describe, it, expect, beforeAll, afterAll, afterEach, vi } from 'vitest';
import { queueManager, QueueName } from '@/queues/queue.config';
import { queueAIAnalysis, registerAIAnalysisWorker } from '@/queues/jobs/ai-analysis.job';
import {
  queueDocumentProcessing,
  registerDocumentProcessingWorker,
} from '@/queues/jobs/document-processing.job';
import { Queue } from 'bullmq';

describe('Queue Integration Tests', () => {
  beforeAll(() => {
    // Initialize workers
    registerAIAnalysisWorker();
    registerDocumentProcessingWorker();
  });

  afterEach(async () => {
    // Clean up queues after each test
    const queues = [QueueName.AI_ANALYSIS, QueueName.DOCUMENT_PROCESSING];

    for (const queueName of queues) {
      const queue = queueManager.getQueue(queueName);
      await queue.obliterate({ force: true });
    }
  });

  afterAll(async () => {
    await queueManager.close();
  });

  describe('Job Lifecycle', () => {
    it('should complete full job lifecycle: queue -> process -> complete', async () => {
      const jobId = await queueAIAnalysis({
        type: 'scene',
        entityId: 'lifecycle-scene',
        userId: 'user-lifecycle',
        analysisType: 'quick',
      });

      const queue = queueManager.getQueue(QueueName.AI_ANALYSIS);
      const job = await queue.getJob(jobId);

      expect(job).toBeDefined();

      // Wait for job to be processed
      await new Promise((resolve) => setTimeout(resolve, 4000));

      // Check job state
      if (job) {
        const state = await job.getState();
        expect(['completed', 'active', 'waiting', 'delayed']).toContain(state);
      }
    }, 10000);

    it('should process multiple jobs in sequence', async () => {
      const jobIds = [];

      for (let i = 0; i < 3; i++) {
        const jobId = await queueAIAnalysis({
          type: 'character',
          entityId: `seq-char-${i}`,
          userId: 'user-seq',
          analysisType: 'quick',
        });
        jobIds.push(jobId);
      }

      expect(jobIds.length).toBe(3);

      const queue = queueManager.getQueue(QueueName.AI_ANALYSIS);

      // Verify all jobs are in queue
      for (const jobId of jobIds) {
        const job = await queue.getJob(jobId);
        expect(job).toBeDefined();
      }
    });

    it('should process jobs from different queues concurrently', async () => {
      const aiJobId = await queueAIAnalysis({
        type: 'scene',
        entityId: 'concurrent-scene',
        userId: 'user-concurrent',
        analysisType: 'quick',
      });

      const docJobId = await queueDocumentProcessing({
        documentId: 'concurrent-doc',
        filePath: '/uploads/concurrent.pdf',
        fileType: 'pdf',
        userId: 'user-concurrent',
      });

      expect(aiJobId).toBeDefined();
      expect(docJobId).toBeDefined();

      const aiQueue = queueManager.getQueue(QueueName.AI_ANALYSIS);
      const docQueue = queueManager.getQueue(QueueName.DOCUMENT_PROCESSING);

      const aiJob = await aiQueue.getJob(aiJobId);
      const docJob = await docQueue.getJob(docJobId);

      expect(aiJob).toBeDefined();
      expect(docJob).toBeDefined();
    });
  });

  describe('Failure and Retry Scenarios', () => {
    it('should retry failed job with exponential backoff', async () => {
      // Create a mock processor that fails initially
      let attemptCount = 0;
      const failingProcessor = vi.fn(async (job: any) => {
        attemptCount++;
        if (attemptCount < 3) {
          throw new Error(`Attempt ${attemptCount} failed`);
        }
        return { success: true, attempt: attemptCount };
      });

      // Register custom worker with failing processor
      const testQueue = queueManager.getQueue(QueueName.NOTIFICATIONS);
      const worker = queueManager.registerWorker(
        QueueName.NOTIFICATIONS,
        failingProcessor
      );

      // Add job with retry config
      const job = await testQueue.add(
        'retry-test',
        { data: 'test' },
        {
          attempts: 3,
          backoff: {
            type: 'exponential',
            delay: 100,
          },
        }
      );

      // Wait for retries to complete
      await new Promise((resolve) => setTimeout(resolve, 2000));

      // Verify job was retried
      const updatedJob = await testQueue.getJob(job.id!);

      if (updatedJob) {
        const state = await updatedJob.getState();
        // Job should eventually complete or still be retrying
        expect(['completed', 'active', 'waiting', 'failed']).toContain(state);
      }

      await worker.close();
    }, 10000);

    it('should fail job after max retry attempts', async () => {
      let attemptCount = 0;
      const alwaysFailingProcessor = vi.fn(async (job: any) => {
        attemptCount++;
        throw new Error(`Permanent failure at attempt ${attemptCount}`);
      });

      const testQueue = queueManager.getQueue(QueueName.EXPORT);
      const worker = queueManager.registerWorker(
        QueueName.EXPORT,
        alwaysFailingProcessor
      );

      const job = await testQueue.add(
        'fail-test',
        { data: 'test' },
        {
          attempts: 2,
          backoff: {
            type: 'fixed',
            delay: 100,
          },
        }
      );

      // Wait for all retry attempts
      await new Promise((resolve) => setTimeout(resolve, 2000));

      const updatedJob = await testQueue.getJob(job.id!);

      if (updatedJob) {
        const state = await updatedJob.getState();
        // After max retries, should be failed or active
        expect(['failed', 'active', 'waiting']).toContain(state);
      }

      // Should have attempted multiple times
      expect(attemptCount).toBeGreaterThan(0);

      await worker.close();
    }, 10000);

    it('should handle job timeout', async () => {
      const slowProcessor = vi.fn(async (job: any) => {
        // Simulate long processing
        await new Promise((resolve) => setTimeout(resolve, 5000));
        return { success: true };
      });

      const testQueue = queueManager.getQueue(QueueName.CACHE_WARMING);
      const worker = queueManager.registerWorker(
        QueueName.CACHE_WARMING,
        slowProcessor,
        {
          lockDuration: 1000, // Short lock duration for testing
        }
      );

      const job = await testQueue.add('timeout-test', { data: 'test' });

      // Wait a bit
      await new Promise((resolve) => setTimeout(resolve, 2000));

      const updatedJob = await testQueue.getJob(job.id!);

      if (updatedJob) {
        const state = await updatedJob.getState();
        expect(['active', 'waiting', 'completed', 'failed']).toContain(state);
      }

      await worker.close();
    }, 15000);

    it('should handle job stalling and recovery', async () => {
      // Create processor that simulates stalling
      const stallingProcessor = vi.fn(async (job: any) => {
        // Process quickly to avoid actual stall
        return { success: true };
      });

      const testQueue = queueManager.getQueue(QueueName.AI_ANALYSIS);

      const job = await testQueue.add('stall-test', { data: 'test' });

      // Monitor for stalled jobs
      const stalledPromise = new Promise((resolve) => {
        testQueue.on('stalled', (jobId) => {
          resolve(jobId);
        });
      });

      // Wait a bit
      await new Promise((resolve) => setTimeout(resolve, 1000));

      const updatedJob = await testQueue.getJob(job.id!);
      expect(updatedJob).toBeDefined();
    }, 10000);
  });

  describe('Queue Statistics and Monitoring', () => {
    it('should track queue statistics accurately', async () => {
      // Add multiple jobs
      await queueAIAnalysis({
        type: 'scene',
        entityId: 'stats-1',
        userId: 'user-stats',
        analysisType: 'quick',
      });

      await queueAIAnalysis({
        type: 'character',
        entityId: 'stats-2',
        userId: 'user-stats',
        analysisType: 'quick',
      });

      const stats = await queueManager.getQueueStats(QueueName.AI_ANALYSIS);

      expect(stats.name).toBe(QueueName.AI_ANALYSIS);
      expect(stats.total).toBeGreaterThanOrEqual(2);
      expect(typeof stats.waiting).toBe('number');
      expect(typeof stats.active).toBe('number');
      expect(typeof stats.completed).toBe('number');
      expect(typeof stats.failed).toBe('number');
    });

    it('should get stats for all queues', async () => {
      await queueAIAnalysis({
        type: 'scene',
        entityId: 'all-stats-1',
        userId: 'user-all',
        analysisType: 'quick',
      });

      await queueDocumentProcessing({
        documentId: 'all-stats-doc',
        filePath: '/uploads/stats.pdf',
        fileType: 'pdf',
        userId: 'user-all',
      });

      const allStats = await queueManager.getAllStats();

      expect(Array.isArray(allStats)).toBe(true);
      expect(allStats.length).toBeGreaterThan(0);

