        type: 'scene',
        entityId: 'pause-test',
        userId: 'user-pause',
        analysisType: 'quick',
      });

      // Pause queue
      await queueManager.pauseQueue(QueueName.AI_ANALYSIS);
      const pausedState = await queue.isPaused();
      expect(pausedState).toBe(true);

      // Resume queue
      await queueManager.resumeQueue(QueueName.AI_ANALYSIS);
