    );

    expect(result.chunks).toHaveLength(2);
    expect(result.metrics.totalChunks).toBe(3);
    expect(result.metrics.retrievedChunks).toBe(2);
    expect(mockRetrieve).toHaveBeenCalledWith(
      expect.objectContaining({
